use crate::{Constructor, Inductive, Sig, Term};
use std::rc::Rc;

const POS: usize = 0;
const N: usize = 1;
const BOOL: usize = 2;
const CMP: usize = 3;
const MASK: usize = 4;
const OPTION: usize = 5;
const MEM: usize = 6;
pub const INSTR: usize = 7;
const POSVIEW: usize = 8;
const MEMVIEW: usize = 9;
const NAT: usize = 10;
const ID: usize = 11;
const LIST: usize = 12;
const OP: usize = 13;
const EXPR: usize = 14;
const ETERM: usize = 15;
const SVAL: usize = 16;
const SVALLIST: usize = 17;
const JOB: usize = 18;
const EV: usize = 19;
const RV: usize = 20;
const RENV: usize = 21;

fn ind(i: usize) -> Term {
    Term::Ind(i)
}

fn constr(i: usize, j: usize) -> Term {
    Term::Constr(i, j)
}

fn rec(i: usize, t: u32) -> Term {
    Term::Rec(i, t)
}

fn var(i: usize) -> Term {
    Term::Var(i)
}

fn app(f: Term, x: Term) -> Term {
    Term::App(Box::new(f), Box::new(x))
}

fn app2(f: Term, x: Term, y: Term) -> Term {
    app(app(f, x), y)
}

fn apps(head: Term, args: Vec<Term>) -> Term {
    args.into_iter().fold(head, app)
}

fn lam(a: Term, b: Term) -> Term {
    Term::Lam(Box::new(a), Box::new(b))
}

fn pi(a: Term, b: Term) -> Term {
    Term::Pi(Box::new(a), Box::new(b))
}

fn p() -> Term {
    ind(POS)
}

fn nn() -> Term {
    ind(N)
}

fn xh() -> Term {
    constr(POS, 0)
}

fn xo(t: Term) -> Term {
    app(constr(POS, 1), t)
}

fn xi(t: Term) -> Term {
    app(constr(POS, 2), t)
}

fn n0() -> Term {
    constr(N, 0)
}

fn npos(t: Term) -> Term {
    app(constr(N, 1), t)
}

fn pp() -> Term {
    Term::Sigma(Box::new(p()), Box::new(p()))
}

fn mk_pair(a: Term, b: Term) -> Term {
    Term::Pair(Box::new(pp()), Box::new(a), Box::new(b))
}

fn fst(t: Term) -> Term {
    Term::Fst(Box::new(t))
}

fn snd(t: Term) -> Term {
    Term::Snd(Box::new(t))
}

fn bb() -> Term {
    ind(BOOL)
}

fn cc() -> Term {
    ind(CMP)
}

fn mm() -> Term {
    ind(MASK)
}

fn bfalse() -> Term {
    constr(BOOL, 0)
}

fn btrue() -> Term {
    constr(BOOL, 1)
}

fn ceq() -> Term {
    constr(CMP, 0)
}

fn clt() -> Term {
    constr(CMP, 1)
}

fn cgt() -> Term {
    constr(CMP, 2)
}

fn isnul() -> Term {
    constr(MASK, 0)
}

fn ispos(t: Term) -> Term {
    app(constr(MASK, 1), t)
}

fn isneg() -> Term {
    constr(MASK, 2)
}

fn mmpp() -> Term {
    Term::Sigma(Box::new(mm()), Box::new(mm()))
}

fn mk_mpair(a: Term, b: Term) -> Term {
    Term::Pair(Box::new(mmpp()), Box::new(a), Box::new(b))
}

fn let_bind(ty: Term, arg: Term, inner: Term) -> Term {
    app(lam(ty, inner), arg)
}

fn case_pos(ret: Term, on_xh: Term, on_xo: Term, on_xi: Term, scrut: Term) -> Term {
    apps(
        rec(POS, 1),
        vec![
            lam(p(), ret.clone()),
            on_xh,
            lam(p(), lam(ret.clone(), on_xo)),
            lam(p(), lam(ret, on_xi)),
            scrut,
        ],
    )
}

fn case_n(ret: Term, on_n0: Term, on_npos: Term, scrut: Term) -> Term {
    apps(
        rec(N, 1),
        vec![lam(nn(), ret), on_n0, lam(p(), on_npos), scrut],
    )
}

fn case_cmp(ret: Term, on_eq: Term, on_lt: Term, on_gt: Term, scrut: Term) -> Term {
    apps(
        rec(CMP, 1),
        vec![lam(cc(), ret), on_eq, on_lt, on_gt, scrut],
    )
}

fn case_mask(ret: Term, on_isnul: Term, on_ispos: Term, on_isneg: Term, scrut: Term) -> Term {
    apps(
        rec(MASK, 1),
        vec![
            lam(mm(), ret),
            on_isnul,
            lam(p(), on_ispos),
            on_isneg,
            scrut,
        ],
    )
}

fn optn() -> Term {
    app(ind(OPTION), nn())
}

fn none_n() -> Term {
    app(constr(OPTION, 0), nn())
}

fn some_n(v: Term) -> Term {
    app2(constr(OPTION, 1), nn(), v)
}

fn case_optn(ret: Term, on_none: Term, on_some: Term, scrut: Term) -> Term {
    apps(
        rec(OPTION, 1),
        vec![nn(), lam(optn(), ret), on_none, lam(nn(), on_some), scrut],
    )
}

fn mem() -> Term {
    ind(MEM)
}

fn leaf() -> Term {
    constr(MEM, 0)
}

fn node(l: Term, o: Term, r: Term) -> Term {
    apps(constr(MEM, 1), vec![l, o, r])
}

pub fn state_ty() -> Term {
    Term::Sigma(
        Box::new(mem()),
        Box::new(Term::Sigma(Box::new(nn()), Box::new(mem()))),
    )
}

pub fn mk_state(regs: Term, pc: Term, m: Term) -> Term {
    Term::Pair(
        Box::new(state_ty()),
        Box::new(regs),
        Box::new(Term::Pair(
            Box::new(Term::Sigma(Box::new(nn()), Box::new(mem()))),
            Box::new(pc),
            Box::new(m),
        )),
    )
}

pub fn st_regs(s: Term) -> Term {
    fst(s)
}

pub fn st_pc(s: Term) -> Term {
    fst(snd(s))
}

pub fn st_mem(s: Term) -> Term {
    snd(snd(s))
}

fn pv() -> Term {
    ind(POSVIEW)
}

fn vh() -> Term {
    constr(POSVIEW, 0)
}

fn vo(t: Term) -> Term {
    app(constr(POSVIEW, 1), t)
}

fn vi(t: Term) -> Term {
    app(constr(POSVIEW, 2), t)
}

fn peel() -> Term {
    apps(
        rec(POS, 1),
        vec![
            lam(p(), pv()),
            vh(),
            lam(p(), lam(pv(), vo(var(1)))),
            lam(p(), lam(pv(), vi(var(1)))),
        ],
    )
}

fn case_posview(ret: Term, on_vh: Term, on_vo: Term, on_vi: Term, scrut: Term) -> Term {
    apps(
        rec(POSVIEW, 1),
        vec![
            lam(pv(), ret),
            on_vh,
            lam(p(), on_vo),
            lam(p(), on_vi),
            scrut,
        ],
    )
}

fn mvw() -> Term {
    ind(MEMVIEW)
}

fn mvleaf() -> Term {
    constr(MEMVIEW, 0)
}

fn mvnode(l: Term, o: Term, r: Term) -> Term {
    apps(constr(MEMVIEW, 1), vec![l, o, r])
}

fn peel_mem() -> Term {
    apps(
        rec(MEM, 1),
        vec![
            lam(mem(), mvw()),
            mvleaf(),
            lam(
                mem(),
                lam(
                    optn(),
                    lam(
                        mem(),
                        lam(mvw(), lam(mvw(), mvnode(var(4), var(3), var(2)))),
                    ),
                ),
            ),
        ],
    )
}

fn case_memview(ret: Term, on_leaf: Term, on_node: Term, scrut: Term) -> Term {
    apps(
        rec(MEMVIEW, 1),
        vec![
            lam(mvw(), ret),
            on_leaf,
            lam(mem(), lam(optn(), lam(mem(), on_node))),
            scrut,
        ],
    )
}

