fn renv_invert_motive() -> Term {
    let inner_motive = lam(svlist_ty(), Term::Universe(0));
    let m_nil_inner = realizes_val(sv_constr(nat_z(), nat_lit(0), svnil()), n0());
    let m_cons_inner = lam(
        sval_ty(),
        lam(
            svlist_ty(),
            lam(
                Term::Universe(0),
                realizes_val(
                    var(2),
                    app2(n_get(), var(4), app2(nat_get(), var(5), nat_z())),
                ),
            ),
        ),
    );
    let body = apps(
        rec(SVALLIST, 2),
        vec![inner_motive, m_nil_inner, m_cons_inner, var(3)],
    );
    lam(
        svlist_ty(),
        lam(
            slotenv_ty(),
            lam(
                list_ty(nn()),
                lam(realizes_env(var(2), var(1), var(0)), body),
            ),
        ),
    )
}

fn renv_lookup0(env: Term, senv: Term, locals: Term, h: Term) -> Term {
    let m = renv_invert_motive();
    let method_nil = lam(list_ty(nn()), rv_z(nat_z()));
    let method_cons_tys = vec![
        sval_ty(),
        nat_ty(),
        svlist_ty(),
        slotenv_ty(),
        list_ty(nn()),
        realizes_val(var(4), app2(n_get(), var(0), var(3))),
        realizes_env(var(3), var(2), var(1)),
        lnth_at(var(2), var(5)),
        apps(m.clone(), vec![var(5), var(4), var(3), var(1)]),
    ];
    let method_cons = lams(&method_cons_tys, var(3));
    apps(
        rec(RENV, 1),
        vec![m, method_nil, method_cons, env, senv, locals, h],
    )
}

fn renv_invert_motive_1() -> Term {
    let im = || lam(svlist_ty(), Term::Universe(0));
    let canonical = || realizes_val(sv_constr(nat_z(), nat_lit(0), svnil()), n0());
    let leaf = realizes_val(
        var(2),
        app2(n_get(), var(7), app2(nat_get(), var(8), nat_lit(1))),
    );
    let inner_cons = lam(sval_ty(), lam(svlist_ty(), lam(Term::Universe(0), leaf)));
    let inner_rec = apps(
        rec(SVALLIST, 2),
        vec![im(), canonical(), inner_cons, var(1)],
    );
    let m_cons = lam(
        sval_ty(),
        lam(svlist_ty(), lam(Term::Universe(0), inner_rec)),
    );
    let body = apps(rec(SVALLIST, 2), vec![im(), canonical(), m_cons, var(3)]);
    lam(
        svlist_ty(),
        lam(
            slotenv_ty(),
            lam(
                list_ty(nn()),
                lam(realizes_env(var(2), var(1), var(0)), body),
            ),
        ),
    )
}

fn renv_lookup1(env: Term, senv: Term, locals: Term, h: Term) -> Term {
    let m = renv_invert_motive_1();
    let method_nil = lam(list_ty(nn()), rv_z(nat_z()));
    let method_cons_tys = vec![
        sval_ty(),
        nat_ty(),
        svlist_ty(),
        slotenv_ty(),
        list_ty(nn()),
        realizes_val(var(4), app2(n_get(), var(0), var(3))),
        realizes_env(var(3), var(2), var(1)),
        lnth_at(var(2), var(5)),
        apps(m.clone(), vec![var(5), var(4), var(3), var(1)]),
    ];
    let method_cons = lams(
        &method_cons_tys,
        renv_lookup0(var(6), var(5), var(4), var(2)),
    );
    apps(
        rec(RENV, 1),
        vec![m, method_nil, method_cons, env, senv, locals, h],
    )
}

fn renv_realizes(env: Term, senv: Term, locals: Term, slot: Term) -> Term {
    let canonical = realizes_val(sv_constr(nat_z(), nat_lit(0), svnil()), n0());
    let inner_m = lam(
        svlist_ty(),
        pi(slotenv_ty(), pi(nat_ty(), Term::Universe(0))),
    );
    let m_nil = lam(slotenv_ty(), lam(nat_ty(), canonical));
    let base = realizes_val(
        var(4),
        app2(
            n_get(),
            lift(5, 0, &locals),
            app2(nat_get(), var(1), nat_z()),
        ),
    );
    let step = lam(
        nat_ty(),
        lam(
            Term::Universe(0),
            app2(var(4), ltail(nat_ty(), var(3)), var(1)),
        ),
    );
    let nat_rec = apps(
        rec(NAT, 2),
        vec![lam(nat_ty(), Term::Universe(0)), base, step, var(0)],
    );
    let m_cons = lam(
        sval_ty(),
        lam(
            svlist_ty(),
            lam(
                pi(slotenv_ty(), pi(nat_ty(), Term::Universe(0))),
                lam(slotenv_ty(), lam(nat_ty(), nat_rec)),
            ),
        ),
    );
    let body = apps(rec(SVALLIST, 2), vec![inner_m, m_nil, m_cons, env]);
    app2(body, senv, slot)
}

fn renv_lookup(slot: Term, env: Term, senv: Term, locals: Term, h: Term) -> Term {
    let m = lam(
        svlist_ty(),
        lam(
            slotenv_ty(),
            lam(
                list_ty(nn()),
                lam(
                    realizes_env(var(2), var(1), var(0)),
                    pi(nat_ty(), renv_realizes(var(4), var(3), var(2), var(0))),
                ),
            ),
        ),
    );
    let method_nil = lam(list_ty(nn()), lam(nat_ty(), rv_z(nat_z())));
    let cons_tys = vec![
        sval_ty(),
        nat_ty(),
        svlist_ty(),
        slotenv_ty(),
        list_ty(nn()),
        realizes_val(var(4), app2(n_get(), var(0), var(3))),
        realizes_env(var(3), var(2), var(1)),
        lnth_at(var(2), var(5)),
        pi(nat_ty(), renv_realizes(var(6), var(5), var(4), var(0))),
    ];
    let motive_cm = lam(
        nat_ty(),
        renv_realizes(
            svcons(var(10), var(8)),
            lcons(nat_ty(), var(9), var(7)),
            var(6),
            var(0),
        ),
    );
    let step_binder_ty = renv_realizes(
        svcons(var(10), var(8)),
        lcons(nat_ty(), var(9), var(7)),
        var(6),
        var(0),
    );
    let step_cm = lam(nat_ty(), lam(step_binder_ty, app(var(3), var(1))));
    let cons_body = lam(
        nat_ty(),
        apps(rec(NAT, 1), vec![motive_cm, var(4), step_cm, var(0)]),
    );
    let method_cons = lams(&cons_tys, cons_body);
    app(
        apps(
            rec(RENV, 1),
            vec![m, method_nil, method_cons, env, senv, locals, h],
        ),
        slot,
    )
}

