pub fn p_jeval_var0() -> (Term, Term) {
    let z = || sv_constr(nat_lit(10), nat_lit(0), svnil());
    let env = || svcons(z(), svnil());
    let e = || et_var(nat_lit(0));
    let prop = p_jeval(env(), e(), z());
    let tys = vec![
        list_ty(func_ty()),
        slotenv_ty(),
        list_ty(nn()),
        expr_ty(),
        list_ty(sframe_ty()),
        nat_ty(),
        realizes_env(env(), var(4), var(3)),
    ];
    let (_ops, _slot, rloc) = pjeval_run_terms(e());
    let rhs = apps(
        s_run(),
        vec![var(6), var(1), mk_sstate(mk_sframe(rloc, var(3)), var(2))],
    );
    let idproof = refl(optn(), rhs);
    let rvproof = renv_lookup0(env(), var(5), var(4), var(0));
    let witness = pair_of(pjeval_concl(e(), z()), idproof, rvproof);
    let proof = lams(&tys, witness);
    (prop, proof)
}

