pub fn read_args_snoc() -> (Term, Term) {
    let ra = |l: Term, slots: Term| apps(read_args(), vec![l, slots]);
    let nget = |l: Term, i: Term| app2(n_get(), l, i);
    let prop = pi(
        list_ty(nn()),
        pi(
            nat_ty(),
            pi(
                slotenv_ty(),
                id_ty(
                    list_ty(nn()),
                    ra(var(2), lsnoc(nat_ty(), var(0), var(1))),
                    lsnoc(nn(), ra(var(2), var(0)), nget(var(2), var(1))),
                ),
            ),
        ),
    );
    let motive = lam(
        slotenv_ty(),
        id_ty(
            list_ty(nn()),
            ra(var(3), lsnoc(nat_ty(), var(0), var(2))),
            lsnoc(nn(), ra(var(3), var(0)), nget(var(3), var(2))),
        ),
    );
    let m_nil = refl(list_ty(nn()), lcons(nn(), nget(var(2), var(1)), lnil(nn())));
    let ih_ty = id_ty(
        list_ty(nn()),
        ra(var(4), lsnoc(nat_ty(), var(0), var(3))),
        lsnoc(nn(), ra(var(4), var(0)), nget(var(4), var(3))),
    );
    let f = lam(list_ty(nn()), lcons(nn(), nget(var(6), var(3)), var(0)));
    let x = ra(var(5), lsnoc(nat_ty(), var(1), var(4)));
    let y = lsnoc(nn(), ra(var(5), var(1)), nget(var(5), var(4)));
    let m_cons = lam(
        nat_ty(),
        lam(
            slotenv_ty(),
            lam(ih_ty, ap(list_ty(nn()), list_ty(nn()), f, x, y, var(0))),
        ),
    );
    let proof = lam(
        list_ty(nn()),
        lam(
            nat_ty(),
            lam(
                slotenv_ty(),
                apps(rec(LIST, 0), vec![nat_ty(), motive, m_nil, m_cons, var(0)]),
            ),
        ),
    );
    (prop, proof)
}

