fn iota_seg(base: Term, len: Term) -> Term {
    let folded = apps(
        rec(NAT, 1),
        vec![
            lam(nat_ty(), pi(nat_ty(), slotenv_ty())),
            lam(nat_ty(), lnil(nat_ty())),
            lam(
                nat_ty(),
                lam(
                    pi(nat_ty(), slotenv_ty()),
                    lam(
                        nat_ty(),
                        lcons(nat_ty(), var(0), app(var(1), nat_s(var(0)))),
                    ),
                ),
            ),
            len,
        ],
    );
    app(folded, base)
}

pub fn read_args_seg3() -> (Term, Term) {
    let ra = |l: Term, s: Term| apps(read_args(), vec![l, s]);
    let body_goal = |pre: Term, mid: Term, post: Term| {
        id_ty(
            list_ty(nn()),
            ra(
                lappend(nn(), pre.clone(), lappend(nn(), mid.clone(), post)),
                iota_seg(llen(nn(), pre), llen(nn(), mid.clone())),
            ),
            mid,
        )
    };
    let prop = pi(
        list_ty(nn()),
        pi(
            list_ty(nn()),
            pi(list_ty(nn()), body_goal(var(1), var(2), var(0))),
        ),
    );
    let motive = lam(
        list_ty(nn()),
        pi(
            list_ty(nn()),
            pi(list_ty(nn()), body_goal(var(1), var(2), var(0))),
        ),
    );
    let m_nil = lam(
        list_ty(nn()),
        lam(list_ty(nn()), refl(list_ty(nn()), lnil(nn()))),
    );
    let ih_ty = pi(
        list_ty(nn()),
        pi(list_ty(nn()), body_goal(var(1), var(2), var(0))),
    );
    let z = lappend(nn(), var(3), var(0));
    let w_b = lappend(nn(), var(1), lcons(nn(), var(4), z.clone()));
    let w_ih = lappend(
        nn(),
        lappend(nn(), var(1), lcons(nn(), var(4), lnil(nn()))),
        z.clone(),
    );
    let s_b = iota_seg(nat_s(llen(nn(), var(1))), llen(nn(), var(3)));
    let s_ih = iota_seg(llen(nn(), lsnoc(nn(), var(1), var(4))), llen(nn(), var(3)));
    let a_val = app2(
        n_get(),
        lappend(nn(), var(1), lcons(nn(), var(4), z.clone())),
        llen(nn(), var(1)),
    );
    let b_val = ra(w_b.clone(), s_b.clone());
    let (_, ngal) = n_get_append_len();
    let h_a = apps(ngal, vec![var(4), z.clone(), var(1)]);
    let (_, la) = lappend_assoc();
    let la_inst = apps(la, vec![z.clone(), lcons(nn(), var(4), lnil(nn())), var(1)]);
    let h_w = id_sym(list_ty(nn()), w_ih.clone(), w_b.clone(), la_inst);
    let f_list = lam(
        list_ty(nn()),
        apps(read_args(), vec![var(0), lift(1, 0, &s_b)]),
    );
    let ap_list = ap(
        list_ty(nn()),
        list_ty(nn()),
        f_list,
        w_b.clone(),
        w_ih.clone(),
        h_w,
    );
    let (_, lls) = llen_snoc();
    let lls_inst = apps(lls, vec![var(4), var(1)]);
    let h_s_sym = id_sym(
        nat_ty(),
        llen(nn(), lsnoc(nn(), var(1), var(4))),
        nat_s(llen(nn(), var(1))),
        lls_inst,
    );
    let f_seg = lam(nat_ty(), iota_seg(var(0), lift(1, 0, &llen(nn(), var(3)))));
    let h_s = ap(
        nat_ty(),
        slotenv_ty(),
        f_seg,
        nat_s(llen(nn(), var(1))),
        llen(nn(), lsnoc(nn(), var(1), var(4))),
        h_s_sym,
    );
    let f_slot = lam(
        slotenv_ty(),
        apps(read_args(), vec![lift(1, 0, &w_ih), var(0)]),
    );
    let ap_slot = ap(
        slotenv_ty(),
        list_ty(nn()),
        f_slot,
        s_b.clone(),
        s_ih.clone(),
        h_s,
    );
    let h_bridge = id_trans(
        list_ty(nn()),
        b_val.clone(),
        ra(w_ih.clone(), s_b.clone()),
        ra(w_ih.clone(), s_ih.clone()),
        ap_list,
        ap_slot,
    );
    let ih_inst = apps(var(2), vec![lsnoc(nn(), var(1), var(4)), var(0)]);
    let h_b = id_trans(
        list_ty(nn()),
        b_val.clone(),
        ra(w_ih, s_ih),
        var(3),
        h_bridge,
        ih_inst,
    );
    let m_cons = lam(
        nn(),
        lam(
            list_ty(nn()),
            lam(
                ih_ty,
                lam(
                    list_ty(nn()),
                    lam(
                        list_ty(nn()),
                        lcons_cong(nn(), a_val, var(4), b_val, var(3), h_a, h_b),
                    ),
                ),
            ),
        ),
    );
    let proof = lam(
        list_ty(nn()),
        apps(rec(LIST, 0), vec![nn(), motive, m_nil, m_cons, var(0)]),
    );
    (prop, proof)
}

pub fn iota_seg_snoc() -> (Term, Term) {
    let goal = |b: Term, n: Term| {
        id_ty(
            slotenv_ty(),
            iota_seg(b.clone(), nat_s(n.clone())),
            lsnoc(
                nat_ty(),
                iota_seg(b.clone(), n.clone()),
                app2(nat_add(), b, n),
            ),
        )
    };
    let prop = pi(nat_ty(), pi(nat_ty(), goal(var(0), var(1))));
    let motive = lam(nat_ty(), pi(nat_ty(), goal(var(0), var(1))));
    let m_zero = lam(
        nat_ty(),
        refl(slotenv_ty(), lcons(nat_ty(), var(0), lnil(nat_ty()))),
    );
    let ih_ty = pi(nat_ty(), goal(var(0), var(1)));
    let sb = nat_s(var(0));
    let kk = var(2);
    let iss_sb_sk = iota_seg(sb.clone(), nat_s(kk.clone()));
    let iss_sb_k = iota_seg(sb.clone(), kk.clone());
    let add_sb_k = app2(nat_add(), sb.clone(), kk.clone());
    let add_b_sk = app2(nat_add(), var(0), nat_s(kk.clone()));
    let ih_inst = apps(var(1), vec![sb]);
    let (_, nasl) = nat_add_succ_l();
    let nasl_inst = apps(nasl, vec![var(0), kk]);
    let f_snoc = lam(nat_ty(), lsnoc(nat_ty(), lift(1, 0, &iss_sb_k), var(0)));
    let snoc_rewrite = ap(
        nat_ty(),
        slotenv_ty(),
        f_snoc,
        add_sb_k.clone(),
        add_b_sk.clone(),
        nasl_inst,
    );
    let inner = id_trans(
        slotenv_ty(),
        iss_sb_sk.clone(),
        lsnoc(nat_ty(), iss_sb_k.clone(), add_sb_k),
        lsnoc(nat_ty(), iss_sb_k.clone(), add_b_sk.clone()),
        ih_inst,
        snoc_rewrite,
    );
    let f_cons = lam(slotenv_ty(), lcons(nat_ty(), var(1), var(0)));
    let m_succ_body = ap(
        slotenv_ty(),
        slotenv_ty(),
        f_cons,
        iss_sb_sk,
        lsnoc(nat_ty(), iss_sb_k, add_b_sk),
        inner,
    );
    let m_succ = lam(nat_ty(), lam(ih_ty, lam(nat_ty(), m_succ_body)));
    let proof = lam(
        nat_ty(),
        apps(rec(NAT, 0), vec![motive, m_zero, m_succ, var(0)]),
    );
    (prop, proof)
}

pub fn iota_fwd_eq_seg() -> (Term, Term) {
    let goal = |n: Term| id_ty(slotenv_ty(), iota_fwd(n.clone()), iota_seg(nat_z(), n));
    let prop = pi(nat_ty(), goal(var(0)));
    let motive = lam(nat_ty(), goal(var(0)));
    let m_zero = refl(slotenv_ty(), lnil(nat_ty()));
    let ih_ty = goal(var(0));
    let kk = var(1);
    let seg0_k = iota_seg(nat_z(), kk.clone());
    let snoc_seg0_k = lsnoc(nat_ty(), seg0_k.clone(), kk.clone());
    let f_snoc = lam(slotenv_ty(), lsnoc(nat_ty(), var(0), lift(1, 0, &kk)));
    let step1 = ap(
        slotenv_ty(),
        slotenv_ty(),
        f_snoc,
        iota_fwd(kk.clone()),
        seg0_k.clone(),
        var(0),
    );
    let (_, iss) = iota_seg_snoc();
    let iss_inst = apps(iss, vec![kk.clone(), nat_z()]);
    let (_, nazl) = nat_add_zero_l();
    let nazl_inst = apps(nazl, vec![kk.clone()]);
    let f_rw = lam(nat_ty(), lsnoc(nat_ty(), lift(1, 0, &seg0_k), var(0)));
    let rewrite_k = ap(
        nat_ty(),
        slotenv_ty(),
        f_rw,
        app2(nat_add(), nat_z(), kk.clone()),
        kk.clone(),
        nazl_inst,
    );
    let iss_to_k = id_trans(
        slotenv_ty(),
        iota_seg(nat_z(), nat_s(kk.clone())),
        lsnoc(
            nat_ty(),
            seg0_k.clone(),
            app2(nat_add(), nat_z(), kk.clone()),
        ),
        snoc_seg0_k.clone(),
        iss_inst,
        rewrite_k,
    );
    let step2 = id_sym(
        slotenv_ty(),
        iota_seg(nat_z(), nat_s(kk.clone())),
        snoc_seg0_k.clone(),
        iss_to_k,
    );
    let m_succ_body = id_trans(
        slotenv_ty(),
        iota_fwd(nat_s(kk.clone())),
        snoc_seg0_k,
        iota_seg(nat_z(), nat_s(kk)),
        step1,
        step2,
    );
    let m_succ = lam(nat_ty(), lam(ih_ty, m_succ_body));
    let proof = lam(
        nat_ty(),
        apps(rec(NAT, 0), vec![motive, m_zero, m_succ, var(0)]),
    );
    (prop, proof)
}

pub fn read_args_iota_prefix() -> (Term, Term) {
    let ra = |l: Term, s: Term| apps(read_args(), vec![l, s]);
    let prop = pi(
        list_ty(nn()),
        pi(
            list_ty(nn()),
            id_ty(
                list_ty(nn()),
                ra(lappend(nn(), var(1), var(0)), iota_fwd(llen(nn(), var(1)))),
                var(1),
            ),
        ),
    );
    let list_pre_suf = lappend(nn(), var(1), var(0));
    let (_, seg3) = read_args_seg3();
    let seg3_inst = apps(seg3, vec![var(1), lnil(nn()), var(0)]);
    let (_, ife) = iota_fwd_eq_seg();
    let ife_inst = apps(ife, vec![llen(nn(), var(1))]);
    let f_slot = lam(
        slotenv_ty(),
        apps(read_args(), vec![lift(1, 0, &list_pre_suf), var(0)]),
    );
    let slot_bridge = ap(
        slotenv_ty(),
        list_ty(nn()),
        f_slot,
        iota_fwd(llen(nn(), var(1))),
        iota_seg(nat_z(), llen(nn(), var(1))),
        ife_inst,
    );
    let result = id_trans(
        list_ty(nn()),
        ra(list_pre_suf.clone(), iota_fwd(llen(nn(), var(1)))),
        ra(list_pre_suf, iota_seg(nat_z(), llen(nn(), var(1)))),
        var(1),
        slot_bridge,
        seg3_inst,
    );
    let proof = lam(list_ty(nn()), lam(list_ty(nn()), result));
    (prop, proof)
}

pub fn read_args_loop_frame() -> (Term, Term) {
    let ra = |l: Term, s: Term| apps(read_args(), vec![l, s]);
    let nget = |l: Term, i: Term| app2(n_get(), l, i);
    let iota = |c: Term| iota_fwd(llen(nn(), c));

    let prop = pi(
        list_ty(nn()),
        pi(
            nat_ty(),
            id_ty(
                list_ty(nn()),
                ra(var(1), lsnoc(nat_ty(), iota(var(1)), var(0))),
                lsnoc(nn(), var(1), nget(var(1), var(0))),
            ),
        ),
    );

    let cc = var(1);
    let ss = var(0);
    let iotac = iota(cc.clone());

    let (_, ras) = read_args_snoc();
    let ras_inst = apps(ras, vec![cc.clone(), ss.clone(), iotac.clone()]);

    let (_, rip) = read_args_iota_prefix();
    let rip_inst = apps(rip, vec![cc.clone(), lnil(nn())]);

    let (_, lnr) = lappend_nil_r();
    let lnr_inst = apps(lnr, vec![cc.clone()]);

    let f_ra = lam(
        list_ty(nn()),
        apps(read_args(), vec![var(0), lift(1, 0, &iotac)]),
    );
    let ap_ra = ap(
        list_ty(nn()),
        list_ty(nn()),
        f_ra,
        lappend(nn(), cc.clone(), lnil(nn())),
        cc.clone(),
        lnr_inst,
    );

    let prefix_eq = id_trans(
        list_ty(nn()),
        ra(cc.clone(), iotac.clone()),
        ra(lappend(nn(), cc.clone(), lnil(nn())), iotac.clone()),
        cc.clone(),
        id_sym(
            list_ty(nn()),
            ra(lappend(nn(), cc.clone(), lnil(nn())), iotac.clone()),
            ra(cc.clone(), iotac.clone()),
            ap_ra,
        ),
        rip_inst,
    );

    let f_snoc = lam(
        list_ty(nn()),
        lsnoc(nn(), var(0), nget(lift(1, 0, &cc), lift(1, 0, &ss))),
    );
    let ap_snoc = ap(
        list_ty(nn()),
        list_ty(nn()),
        f_snoc,
        ra(cc.clone(), iotac.clone()),
        cc.clone(),
        prefix_eq,
    );

    let result = id_trans(
        list_ty(nn()),
        ra(cc.clone(), lsnoc(nat_ty(), iotac.clone(), ss.clone())),
        lsnoc(
            nn(),
            ra(cc.clone(), iotac.clone()),
            nget(cc.clone(), ss.clone()),
        ),
        lsnoc(nn(), cc.clone(), nget(cc.clone(), ss.clone())),
        ras_inst,
        ap_snoc,
    );

    let proof = lam(list_ty(nn()), lam(nat_ty(), result));
    (prop, proof)
}

pub fn loop_call_carried_bridge() -> (Term, Term) {
    let llen_l = llen(nn(), var(2));
    let m_list = lsnoc(nn(), var(2), var(1));
    let frame = lsnoc(nn(), m_list.clone(), var(0));
    let iota_l = iota_fwd(llen_l.clone());
    let argslots = lsnoc(nat_ty(), iota_l.clone(), nat_s(llen_l.clone()));
    let a_val = apps(read_args(), vec![frame.clone(), iota_l.clone()]);
    let b_val = app2(n_get(), frame.clone(), nat_s(llen_l.clone()));
    let target = lsnoc(nn(), var(2), var(0));
    let suf_ab = lappend(
        nn(),
        lcons(nn(), var(1), lnil(nn())),
        lcons(nn(), var(0), lnil(nn())),
    );
    let prop = pi(
        list_ty(nn()),
        pi(
            nn(),
            pi(
                nn(),
                id_ty(
                    list_ty(nn()),
                    apps(read_args(), vec![frame.clone(), argslots.clone()]),
                    target.clone(),
                ),
            ),
        ),
    );
    let (_, ras) = read_args_snoc();
    let step_snoc = apps(
        ras,
        vec![frame.clone(), nat_s(llen_l.clone()), iota_l.clone()],
    );
    let (_, la) = lappend_assoc();
    let la_inst = apps(
        la,
        vec![
            lcons(nn(), var(0), lnil(nn())),
            lcons(nn(), var(1), lnil(nn())),
            var(2),
        ],
    );
    let (_, rip) = read_args_iota_prefix();
    let rip_inst = apps(rip, vec![var(2), suf_ab.clone()]);
    let f_frame = lam(
        list_ty(nn()),
        apps(read_args(), vec![var(0), iota_fwd(llen(nn(), var(3)))]),
    );
    let mid_i = apps(
        read_args(),
        vec![lappend(nn(), var(2), suf_ab.clone()), iota_l.clone()],
    );
    let ap_frame = ap(
        list_ty(nn()),
        list_ty(nn()),
        f_frame,
        frame.clone(),
        lappend(nn(), var(2), suf_ab),
        la_inst,
    );
    let h_i = id_trans(
        list_ty(nn()),
        a_val.clone(),
        mid_i,
        var(2),
        ap_frame,
        rip_inst,
    );
    let (_, ngs) = n_get_snoc();
    let ngs_inst = apps(ngs, vec![var(0), m_list.clone()]);
    let (_, lls) = llen_snoc();
    let lls_inst = apps(lls, vec![var(1), var(2)]);
    let h_idx = id_sym(
        nat_ty(),
        llen(nn(), m_list.clone()),
        nat_s(llen_l.clone()),
        lls_inst,
    );
    let f_idx = lam(nat_ty(), app2(n_get(), lift(1, 0, &frame), var(0)));
    let ap_idx = ap(
        nat_ty(),
        nn(),
        f_idx,
        nat_s(llen_l.clone()),
        llen(nn(), m_list.clone()),
        h_idx,
    );
    let mid_ii = app2(n_get(), frame.clone(), llen(nn(), m_list));
    let h_ii = id_trans(nn(), b_val.clone(), mid_ii, var(0), ap_idx, ngs_inst);
    let f_list_snoc = lam(list_ty(nn()), lsnoc(nn(), var(0), lift(1, 0, &b_val)));
    let ap_list_snoc = ap(
        list_ty(nn()),
        list_ty(nn()),
        f_list_snoc,
        a_val.clone(),
        var(2),
        h_i,
    );
    let f_elem_snoc = lam(nn(), lsnoc(nn(), var(3), var(0)));
    let ap_elem_snoc = ap(
        nn(),
        list_ty(nn()),
        f_elem_snoc,
        b_val.clone(),
        var(0),
        h_ii,
    );
    let cong = id_trans(
        list_ty(nn()),
        lsnoc(nn(), a_val.clone(), b_val.clone()),
        lsnoc(nn(), var(2), b_val.clone()),
        target.clone(),
        ap_list_snoc,
        ap_elem_snoc,
    );
    let result = id_trans(
        list_ty(nn()),
        apps(read_args(), vec![frame, argslots]),
        lsnoc(nn(), a_val, b_val),
        target,
        step_snoc,
        cong,
    );
    let proof = lam(list_ty(nn()), lam(nn(), lam(nn(), result)));
    (prop, proof)
}

pub fn lappend_nil_r() -> (Term, Term) {
    let goal = |l: Term| id_ty(list_ty(nn()), lappend(nn(), l.clone(), lnil(nn())), l);
    let prop = pi(list_ty(nn()), goal(var(0)));
    let motive = lam(list_ty(nn()), goal(var(0)));
    let m_nil = refl(list_ty(nn()), lnil(nn()));
    let ih_ty = goal(var(0));
    let f_cons = lam(list_ty(nn()), lcons(nn(), var(3), var(0)));
    let m_cons = lam(
        nn(),
        lam(
            list_ty(nn()),
            lam(
                ih_ty,
                ap(
                    list_ty(nn()),
                    list_ty(nn()),
                    f_cons,
                    lappend(nn(), var(1), lnil(nn())),
                    var(1),
                    var(0),
                ),
            ),
        ),
    );
    let proof = lam(
        list_ty(nn()),
        apps(rec(LIST, 0), vec![nn(), motive, m_nil, m_cons, var(0)]),
    );
    (prop, proof)
}

pub fn entry_renv_bridge() -> (Term, Term) {
    let ra = |l: Term, s: Term| apps(read_args(), vec![l, s]);
    let nget = |l: Term, i: Term| app2(n_get(), l, i);
    let llen_l = llen(nn(), var(1));
    let iota_l = iota_fwd(llen_l);
    let a_val = ra(var(1), lsnoc(nat_ty(), iota_l.clone(), var(0)));
    let mid = lsnoc(nn(), ra(var(1), iota_l.clone()), nget(var(1), var(0)));
    let target = lsnoc(nn(), var(1), nget(var(1), var(0)));
    let prop = pi(
        list_ty(nn()),
        pi(
            nat_ty(),
            id_ty(list_ty(nn()), a_val.clone(), target.clone()),
        ),
    );

    let (_, ras) = read_args_snoc();
    let step1 = apps(ras, vec![var(1), var(0), iota_l.clone()]);

    let (_, lnr) = lappend_nil_r();
    let lnr_inst = apps(lnr, vec![var(1)]);
    let lnr_sym = id_sym(
        list_ty(nn()),
        lappend(nn(), var(1), lnil(nn())),
        var(1),
        lnr_inst,
    );
    let f_ra = lam(list_ty(nn()), ra(var(0), lift(1, 0, &iota_l)));
    let ap_frame = ap(
        list_ty(nn()),
        list_ty(nn()),
        f_ra,
        var(1),
        lappend(nn(), var(1), lnil(nn())),
        lnr_sym,
    );
    let (_, rip) = read_args_iota_prefix();
    let rip_inst = apps(rip, vec![var(1), lnil(nn())]);
    let h_ra_id = id_trans(
        list_ty(nn()),
        ra(var(1), iota_l.clone()),
        ra(lappend(nn(), var(1), lnil(nn())), iota_l.clone()),
        var(1),
        ap_frame,
        rip_inst,
    );

    let f_snoc = lam(
        list_ty(nn()),
        lsnoc(nn(), var(0), lift(1, 0, &nget(var(1), var(0)))),
    );
    let step2 = ap(
        list_ty(nn()),
        list_ty(nn()),
        f_snoc,
        ra(var(1), iota_l.clone()),
        var(1),
        h_ra_id,
    );

    let result = id_trans(list_ty(nn()), a_val, mid, target, step1, step2);
    let proof = lam(list_ty(nn()), lam(nat_ty(), result));
    (prop, proof)
}

pub fn llen_snoc() -> (Term, Term) {
    let prop = pi(
        nn(),
        pi(
            list_ty(nn()),
            id_ty(
                nat_ty(),
                llen(nn(), lsnoc(nn(), var(0), var(1))),
                nat_s(llen(nn(), var(0))),
            ),
        ),
    );
    let motive = lam(
        list_ty(nn()),
        id_ty(
            nat_ty(),
            llen(nn(), lsnoc(nn(), var(0), var(2))),
            nat_s(llen(nn(), var(0))),
        ),
    );
    let m_nil = refl(nat_ty(), nat_s(llen(nn(), lnil(nn()))));
    let ih_ty = id_ty(
        nat_ty(),
        llen(nn(), lsnoc(nn(), var(0), var(3))),
        nat_s(llen(nn(), var(0))),
    );
    let m_cons = lam(
        nn(),
        lam(
            list_ty(nn()),
            lam(
                ih_ty,
                ap(
                    nat_ty(),
                    nat_ty(),
                    lam(nat_ty(), nat_s(var(0))),
                    llen(nn(), lsnoc(nn(), var(1), var(4))),
                    nat_s(llen(nn(), var(1))),
                    var(0),
                ),
            ),
        ),
    );
    let proof = lam(
        nn(),
        lam(
            list_ty(nn()),
            apps(rec(LIST, 0), vec![nn(), motive, m_nil, m_cons, var(0)]),
        ),
    );
    (prop, proof)
}

