pub fn run_locals_len() -> (Term, Term) {
    let prop = pi(
        list_ty(op_ty()),
        pi(
            list_ty(nn()),
            id_ty(
                nat_ty(),
                llen(nn(), run_locals(var(1), var(0))),
                app2(nat_add(), llen(nn(), var(0)), llen(op_ty(), var(1))),
            ),
        ),
    );
    let motive = lam(
        list_ty(op_ty()),
        pi(
            list_ty(nn()),
            id_ty(
                nat_ty(),
                llen(nn(), run_locals(var(1), var(0))),
                app2(nat_add(), llen(nn(), var(0)), llen(op_ty(), var(1))),
            ),
        ),
    );
    let m_nil = lam(list_ty(nn()), refl(nat_ty(), llen(nn(), var(0))));
    let ih_ty = pi(
        list_ty(nn()),
        id_ty(
            nat_ty(),
            llen(nn(), run_locals(var(1), var(0))),
            app2(nat_add(), llen(nn(), var(0)), llen(op_ty(), var(1))),
        ),
    );
    let lp = || lsnoc(nn(), var(0), op_encode(var(3), var(0)));
    let (_, lls) = llen_snoc();
    let llen_snoc_inst = apps(lls, vec![op_encode(var(3), var(0)), var(0)]);
    let step2 = ap(
        nat_ty(),
        nat_ty(),
        lam(nat_ty(), app2(nat_add(), var(0), llen(op_ty(), var(3)))),
        llen(nn(), lp()),
        nat_s(llen(nn(), var(0))),
        llen_snoc_inst,
    );
    let (_, nasl) = nat_add_succ_l();
    let step3 = apps(nasl, vec![llen(nn(), var(0)), llen(op_ty(), var(2))]);
    let inner = id_trans(
        nat_ty(),
        llen(nn(), run_locals(var(2), lp())),
        app2(nat_add(), llen(nn(), lp()), llen(op_ty(), var(2))),
        app2(nat_add(), nat_s(llen(nn(), var(0))), llen(op_ty(), var(2))),
        app(var(1), lp()),
        step2,
    );
    let body = id_trans(
        nat_ty(),
        llen(nn(), run_locals(var(2), lp())),
        app2(nat_add(), nat_s(llen(nn(), var(0))), llen(op_ty(), var(2))),
        nat_s(app2(nat_add(), llen(nn(), var(0)), llen(op_ty(), var(2)))),
        inner,
        step3,
    );
    let m_cons = lam(
        op_ty(),
        lam(list_ty(op_ty()), lam(ih_ty, lam(list_ty(nn()), body))),
    );
    let proof = lam(
        list_ty(op_ty()),
        lam(
            list_ty(nn()),
            app(
                apps(rec(LIST, 0), vec![op_ty(), motive, m_nil, m_cons, var(1)]),
                var(0),
            ),
        ),
    );
    (prop, proof)
}

