pub fn nat_zs_absurd() -> (Term, Term) {
    let dfam = |y: Term| {
        apps(
            rec(NAT, 1),
            vec![
                lam(nat_ty(), Term::Prop),
                id_ty(nat_ty(), nat_z(), nat_z()),
                lam(nat_ty(), lam(Term::Prop, var(6))),
                y,
            ],
        )
    };
    let motive = lam(
        nat_ty(),
        lam(id_ty(nat_ty(), nat_z(), var(0)), dfam(var(1))),
    );
    let prop = pi(
        Term::Prop,
        pi(
            nat_ty(),
            pi(id_ty(nat_ty(), nat_z(), nat_s(var(0))), var(2)),
        ),
    );
    let proof = lam(
        Term::Prop,
        lam(
            nat_ty(),
            lam(
                id_ty(nat_ty(), nat_z(), nat_s(var(0))),
                apps(
                    rec(ID, 0),
                    vec![
                        nat_ty(),
                        nat_z(),
                        motive,
                        refl(nat_ty(), nat_z()),
                        nat_s(var(1)),
                        var(0),
                    ],
                ),
            ),
        ),
    );
    (prop, proof)
}

