pub fn rv_zero_inv() -> (Term, Term) {
    let m = lam(
        sval_ty(),
        lam(
            nn(),
            lam(
                realizes_val(var(1), var(0)),
                pi(
                    id_ty(nat_ty(), sv_cidx(var(2)), nat_z()),
                    id_ty(nn(), var(2), n0()),
                ),
            ),
        ),
    );
    let method_z = lam(
        nat_ty(),
        lam(id_ty(nat_ty(), nat_z(), nat_z()), refl(nn(), n0())),
    );
    let (_, zs) = nat_zs_absurd();
    let method_s = lam(
        nat_ty(),
        lam(
            sval_ty(),
            lam(
                nn(),
                lam(
                    realizes_val(var(1), var(0)),
                    lam(
                        apps(m.clone(), vec![var(2), var(1), var(0)]),
                        lam(
                            id_ty(nat_ty(), nat_s(nat_z()), nat_z()),
                            apps(
                                zs,
                                vec![
                                    id_ty(nn(), nsucc(var(3)), n0()),
                                    nat_z(),
                                    id_sym(nat_ty(), nat_s(nat_z()), nat_z(), var(0)),
                                ],
                            ),
                        ),
                    ),
                ),
            ),
        ),
    );
    let prop = pi(
        nat_ty(),
        pi(
            nn(),
            pi(
                realizes_val(sv_constr(var(1), nat_lit(0), svnil()), var(0)),
                id_ty(nn(), var(1), n0()),
            ),
        ),
    );
    let proof = lam(
        nat_ty(),
        lam(
            nn(),
            lam(
                realizes_val(sv_constr(var(1), nat_lit(0), svnil()), var(0)),
                app(
                    apps(
                        rec(RV, 0),
                        vec![
                            m,
                            method_z,
                            method_s,
                            sv_constr(var(2), nat_lit(0), svnil()),
                            var(1),
                            var(0),
                        ],
                    ),
                    refl(nat_ty(), nat_z()),
                ),
            ),
        ),
    );
    (prop, proof)
}

pub fn rv_functional() -> (Term, Term) {
    let (_, rzi) = rv_zero_inv();
    let (_, rsi) = rv_succ_inv();

    let motive = lam(
        sval_ty(),
        lam(
            nn(),
            lam(
                realizes_val(var(1), var(0)),
                pi(
                    nn(),
                    pi(realizes_val(var(3), var(0)), id_ty(nn(), var(3), var(1))),
                ),
            ),
        ),
    );

    let mz = lam(
        nat_ty(),
        lam(
            nn(),
            lam(
                realizes_val(sv_constr(var(1), nat_lit(0), svnil()), var(0)),
                id_sym(nn(), var(1), n0(), apps(rzi, vec![var(2), var(1), var(0)])),
            ),
        ),
    );

    let ih_ty = pi(
        nn(),
        pi(realizes_val(var(3), var(0)), id_ty(nn(), var(3), var(1))),
    );
    let sig = apps(rsi, vec![var(6), var(5), var(1), var(0)]);
    let n_prime = fst(sig.clone());
    let rest = snd(sig);
    let eq = fst(rest.clone());
    let rvpred = snd(rest);
    let ih_eq = apps(var(2), vec![n_prime.clone(), rvpred]);
    let nsucc_fn = lam(nn(), nsucc(var(0)));
    let cong = ap(nn(), nn(), nsucc_fn, var(4), n_prime.clone(), ih_eq);
    let eq_sym = id_sym(nn(), var(1), nsucc(n_prime.clone()), eq);
    let s_body = id_trans(nn(), nsucc(var(4)), nsucc(n_prime), var(1), cong, eq_sym);
    let ms = lam(
        nat_ty(),
        lam(
            sval_ty(),
            lam(
                nn(),
                lam(
                    realizes_val(var(1), var(0)),
                    lam(
                        ih_ty,
                        lam(
                            nn(),
                            lam(
                                realizes_val(
                                    sv_constr(var(5), nat_lit(1), svcons(var(4), svnil())),
                                    var(0),
                                ),
                                s_body,
                            ),
                        ),
                    ),
                ),
            ),
        ),
    );

    let prop = pi(
        sval_ty(),
        pi(
            nn(),
            pi(
                realizes_val(var(1), var(0)),
                pi(
                    nn(),
                    pi(realizes_val(var(3), var(0)), id_ty(nn(), var(3), var(1))),
                ),
            ),
        ),
    );
    let proof = lam(
        sval_ty(),
        lam(
            nn(),
            lam(
                realizes_val(var(1), var(0)),
                apps(rec(RV, 0), vec![motive, mz, ms, var(2), var(1), var(0)]),
            ),
        ),
    );
    (prop, proof)
}

pub fn jiota_clause_z() -> (Term, Term) {
    let tys = vec![
        nat_ty(),
        sval_ty(),
        sval_ty(),
        sval_ty(),
        pi(nat_ty(), pi(nat_ty(), nat_ty())),
        nat_ty(),
        realizes_val(var(3), app(nat_to_n(), var(0))),
        nat_ty(),
        realizes_val(
            sv_constr(var(7), nat_lit(0), svnil()),
            app(nat_to_n(), var(0)),
        ),
    ];
    let concl = realizes_val(
        var(6),
        app(nat_to_n(), apps(nrec(), vec![var(4), var(3), var(1)])),
    );
    let prop = pis(&tys, concl);
    let (_, rzi_l) = rv_zero_inv();
    let (_, inj_l) = nat_to_n_inj();
    let rzi = apps(rzi_l, vec![var(8), app(nat_to_n(), var(1)), var(0)]);
    let ek = apps(inj_l, vec![var(1), nat_z(), rzi]);
    let sym_ek = id_sym(nat_ty(), var(1), nat_z(), ek);
    let f_fam = lam(
        nat_ty(),
        realizes_val(
            var(7),
            app(nat_to_n(), apps(nrec(), vec![var(5), var(4), var(0)])),
        ),
    );
    let body = transport(nat_ty(), f_fam, nat_z(), var(1), sym_ek, var(2));
    let proof = lams(&tys, body);
    (prop, proof)
}

