fn job_ty() -> Term {
    ind(JOB)
}

fn m_app_peel(level: usize, base: usize, env: &Term, e: &Term, val: &Term) -> Term {
    let u0 = || Term::Universe(0);
    let honest = |d: usize| p_jeval_guarded(lift(d, 0, env), lift(d, 0, e), lift(d, 0, val));
    let app_body = if level < 3 {
        m_app_peel(level + 1, base + 4, env, e, val)
    } else {
        honest(base + 4)
    };
    let rec_body = if level == 3 {
        p_jeval_app_rec_disp(
            lift(base + 1, 0, env),
            lift(base + 1, 0, e),
            lift(base + 1, 0, val),
        )
    } else {
        honest(base + 1)
    };
    apps(
        rec(ETERM, 2),
        vec![
            lam(eterm_ty(), u0()),
            honest(base),
            lam(nat_ty(), honest(base + 1)),
            lam(eterm_ty(), lam(u0(), honest(base + 2))),
            lam(eterm_ty(), lam(eterm_ty(), lam(u0(), lam(u0(), app_body)))),
            lam(nat_ty(), lam(nat_ty(), honest(base + 2))),
            lam(nat_ty(), rec_body),
            var(3),
        ],
    )
}

fn jeval_clause(env: Term, e: Term, val: Term) -> Term {
    let triv = || realizes_val(sv_constr(nat_z(), nat_lit(0), svnil()), n0());
    let u0 = || Term::Universe(0);
    let pj2 = p_jeval(lift(2, 0, &env), lift(2, 0, &e), lift(2, 0, &val));
    let m_app = lam(
        eterm_ty(),
        lam(
            eterm_ty(),
            lam(u0(), lam(u0(), m_app_peel(0, 4, &env, &e, &val))),
        ),
    );
    let m_constr = lam(
        nat_ty(),
        lam(
            nat_ty(),
            apps(
                rec(NAT, 2),
                vec![
                    lam(nat_ty(), u0()),
                    pj2,
                    lam(nat_ty(), lam(u0(), triv())),
                    var(0),
                ],
            ),
        ),
    );
    apps(
        rec(ETERM, 2),
        vec![
            lam(eterm_ty(), u0()),
            triv(),
            lam(nat_ty(), p_jeval_var_disp(lift(1, 0, &env), var(0))),
            lam(eterm_ty(), lam(u0(), triv())),
            m_app,
            m_constr,
            lam(nat_ty(), triv()),
            e,
        ],
    )
}

fn sim_motive() -> Term {
    let inner_motive = lam(job_ty(), pi(sval_ty(), Term::Universe(0)));
    let m_jeval = lam(
        svlist_ty(),
        lam(
            eterm_ty(),
            lam(sval_ty(), jeval_clause(var(2), var(1), var(0))),
        ),
    );
    let todo = || realizes_val(sv_constr(nat_z(), nat_lit(0), svnil()), n0());
    let m_japp = lam(
        sval_ty(),
        lam(
            sval_ty(),
            lam(
                sval_ty(),
                apps(
                    rec(SVAL, 2),
                    vec![
                        lam(sval_ty(), Term::Universe(0)),
                        todo(),
                        lam(
                            svlist_ty(),
                            lam(
                                eterm_ty(),
                                jeval_clause(svcons(var(3), var(1)), var(0), var(2)),
                            ),
                        ),
                        lam(nat_ty(), lam(nat_ty(), lam(svlist_ty(), todo()))),
                        lam(
                            nat_ty(),
                            lam(
                                svlist_ty(),
                                apps(
                                    rec(BOOL, 2),
                                    vec![
                                        lam(bb(), Term::Universe(0)),
                                        todo(),
                                        clause_a(var(0), var(3), var(2)),
                                        app(svl_lenis(3), var(0)),
                                    ],
                                ),
                            ),
                        ),
                        var(2),
                    ],
                ),
            ),
        ),
    );
    let m_jiota = lam(
        nat_ty(),
        lam(
            svlist_ty(),
            lam(sval_ty(), lam(sval_ty(), clause_a(var(2), var(1), var(0)))),
        ),
    );
    lam(
        job_ty(),
        lam(
            sval_ty(),
            app(
                apps(
                    rec(JOB, 2),
                    vec![inner_motive, m_jeval, m_japp, m_jiota, var(1)],
                ),
                var(0),
            ),
        ),
    )
}

fn sim_p(job: Term, val: Term) -> Term {
    app2(sim_motive(), job, val)
}

