pub fn p_jeval_constr_s1() -> (Term, Term) {
    let vz = || sv_constr(nat_lit(10), nat_lit(0), svnil());
    let e = || {
        et_app(
            et_constr(nat_lit(10), nat_lit(1)),
            et_constr(nat_lit(10), nat_lit(0)),
        )
    };
    let v = || sv_constr(nat_lit(10), nat_lit(1), svcons(vz(), svnil()));
    let prop = p_jeval(svnil(), e(), v());
    let tys = vec![
        list_ty(func_ty()),
        slotenv_ty(),
        list_ty(nn()),
        expr_ty(),
        list_ty(sframe_ty()),
        nat_ty(),
        realizes_env(svnil(), var(4), var(3)),
    ];
    let loc = || var(4);
    let enc0 = || apps(s_encode(), vec![btrue(), nat_lit(0), lnil(nat_ty()), loc()]);
    let l1 = || lsnoc(nn(), loc(), enc0());
    let s_idx = || llen(nn(), loc());
    let enc1 = || {
        apps(
            s_encode(),
            vec![
                btrue(),
                nat_lit(1),
                lcons(nat_ty(), s_idx(), lnil(nat_ty())),
                l1(),
            ],
        )
    };
    let l2 = || lsnoc(nn(), l1(), enc1());
    let slot_s = || nat_s(llen(nn(), loc()));
    let llen_l1 = || llen(nn(), l1());

    let (_ops, _slot, rloc) = pjeval_run_terms(e());
    let rhs = apps(
        s_run(),
        vec![var(6), var(1), mk_sstate(mk_sframe(rloc, var(3)), var(2))],
    );
    let idproof = refl(optn(), rhs);

    let (_, crz) = constr_realizes_z();
    let crz_inst = apps(crz, vec![nat_lit(10), loc()]);
    let (_, ngs) = n_get_snoc();
    let ngs0 = apps(ngs.clone(), vec![enc0(), loc()]);
    let sym0 = id_sym(nn(), app2(n_get(), l1(), s_idx()), enc0(), ngs0);
    let pfam_z = lam(nn(), realizes_val(vz(), var(0)));
    let premise = transport(
        nn(),
        pfam_z,
        enc0(),
        app2(n_get(), l1(), s_idx()),
        sym0,
        crz_inst,
    );
    let (_, crs) = constr_realizes_s();
    let crs_inst = apps(crs, vec![nat_lit(10), s_idx(), l1(), vz(), premise]);

    let ngs1 = apps(ngs, vec![enc1(), l1()]);
    let sym_h1 = id_sym(nn(), app2(n_get(), l2(), llen_l1()), enc1(), ngs1);
    let (_, lls) = llen_snoc();
    let lls0 = apps(lls, vec![enc0(), loc()]);
    let f_nget = lam(nat_ty(), app2(n_get(), lift(1, 0, &l2()), var(0)));
    let ap_idx = ap(nat_ty(), nn(), f_nget, llen_l1(), slot_s(), lls0);
    let path = id_trans(
        nn(),
        enc1(),
        app2(n_get(), l2(), llen_l1()),
        app2(n_get(), l2(), slot_s()),
        sym_h1,
        ap_idx,
    );
    let pfam_v = lam(nn(), realizes_val(v(), var(0)));
    let rvproof = transport(
        nn(),
        pfam_v,
        enc1(),
        app2(n_get(), l2(), slot_s()),
        path,
        crs_inst,
    );

    let witness = pair_of(pjeval_concl(e(), v()), idproof, rvproof);
    let proof = lams(&tys, witness);
    (prop, proof)
}

