pub fn s_run_state_case2_s() -> (Term, Term) {
    let tys = vec![
        list_ty(func_ty()),
        nat_ty(),
        list_ty(nn()),
        nat_ty(),
        expr_ty(),
        expr_ty(),
        list_ty(sframe_ty()),
    ];
    let scrutval7 = app2(n_get(), var(4), var(3));
    let h_ty = id_ty(bb(), app2(n_eqb(), scrutval7, n0()), bfalse());
    let state_in = mk_sstate(
        mk_sframe(var(5), e_case2(btrue(), var(4), var(3), var(2))),
        var(1),
    );
    let lhs = apps(s_run_state(), vec![var(7), nat_s(var(6)), state_in]);
    let scrutval8 = app2(n_get(), var(5), var(4));
    let state_out = mk_sstate(
        mk_sframe(lsnoc(nn(), var(5), n_dec(scrutval8.clone())), var(2)),
        var(1),
    );
    let rhs = apps(s_run_state(), vec![var(7), var(6), state_out]);
    let scrutval_f = app2(n_get(), var(6), var(5));
    let newlocals_f = case_bool(
        list_ty(nn()),
        lsnoc(nn(), var(6), n_dec(scrutval_f)),
        var(6),
        var(0),
    );
    let ctrl_f = case_bool(expr_ty(), var(3), var(4), var(0));
    let state_f = mk_sstate(mk_sframe(newlocals_f, ctrl_f), var(2));
    let f = lam(bb(), apps(s_run_state(), vec![var(8), var(7), state_f]));
    let is_z8 = app2(n_eqb(), scrutval8, n0());
    let proof_inner = ap(bb(), sopt_state(), f, is_z8, bfalse(), var(0));
    let prop = pis(&tys, pi(h_ty.clone(), id_ty(sopt_state(), lhs, rhs)));
    let proof = lams(&tys, lam(h_ty, proof_inner));
    (prop, proof)
}

