pub fn recfunc_realizes_cont_gen_bridged_sym(
    recidx_of: &dyn Fn(&Term) -> Term,
    hfs_proof: Term,
    major_slot: Term,
) -> (Term, Term) {
    let (_, cont_proof) = recfunc_realizes_cont_gen_sym(recidx_of, hfs_proof, major_slot.clone());

    let prog = var(7);
    let l = var(6);
    let maj = var(4);
    let cloc = var(3);
    let cc = var(1);
    let stk = var(0);

    let fuel1 = app2(rec_fuel(), nat_lit(1), maj.clone());
    let entry_slots = lsnoc(
        nat_ty(),
        iota_fwd(llen(nn(), l.clone())),
        major_slot.clone(),
    );
    let entry_body = e_let(op_call(recidx_of(&prog), entry_slots), cc.clone());
    let a_entry = apps(
        s_run(),
        vec![
            prog.clone(),
            nat_s(fuel1),
            mk_sstate(mk_sframe(cloc.clone(), entry_body), stk.clone()),
        ],
    );

    let s_succ = lam(nat_ty(), lam(nat_ty(), nat_s(var(0))));
    let hsm_refl = lam(
        nat_ty(),
        lam(
            nat_ty(),
            refl(nn(), app2(n_add(), app(nat_to_n(), var(0)), npos(xh()))),
        ),
    );
    let mrec_v = apps(mrec(), vec![sm_incr(), n0(), maj.clone()]);
    let nrec_v = app(
        nat_to_n(),
        apps(nrec(), vec![s_succ.clone(), nat_z(), maj.clone()]),
    );
    let body_out_m = apps(
        s_run(),
        vec![
            prog.clone(),
            nat_lit(1),
            mk_sstate(
                mk_sframe(lsnoc(nn(), cloc.clone(), mrec_v.clone()), cc.clone()),
                stk.clone(),
            ),
        ],
    );
    let body_out_n = apps(
        s_run(),
        vec![
            prog.clone(),
            nat_lit(1),
            mk_sstate(
                mk_sframe(lsnoc(nn(), cloc.clone(), nrec_v.clone()), cc.clone()),
                stk.clone(),
            ),
        ],
    );

    let cont_args: Vec<Term> = (0..=8u32).rev().map(|i| var(i as usize)).collect();
    let cont_applied = apps(cont_proof, cont_args);

    let (_, rrg) = rec_realizes_gen();
    let bridge = apps(rrg, vec![s_succ, sm_incr(), nat_z(), hsm_refl, maj.clone()]);
    let f_val = lam(
        nn(),
        apps(
            s_run(),
            vec![
                lift(1, 0, &prog),
                nat_lit(1),
                mk_sstate(
                    mk_sframe(lsnoc(nn(), lift(1, 0, &cloc), var(0)), lift(1, 0, &cc)),
                    lift(1, 0, &stk),
                ),
            ],
        ),
    );
    let ap_bridge = ap(nn(), optn(), f_val, mrec_v, nrec_v, bridge);
    let body = id_trans(
        optn(),
        a_entry.clone(),
        body_out_m,
        body_out_n.clone(),
        cont_applied,
        ap_bridge,
    );

    let prog_ty = list_ty(func_ty());
    let hmem_t = lg_hmem_sym(recidx_of, &id_bodyz_of, &id_bodys_tail_of, &var(1), &var(0));
    let t_entry_slots = lsnoc(nat_ty(), iota_fwd(llen(nn(), var(3))), major_slot.clone());
    let h_cap_ty = id_ty(
        list_ty(nn()),
        apps(read_args(), vec![var(0), t_entry_slots]),
        lsnoc(nn(), var(3), app(nat_to_n(), var(1))),
    );

    let proof = lam(
        nat_ty(),
        lam(
            prog_ty.clone(),
            lam(
                list_ty(nn()),
                lam(
                    hmem_t.clone(),
                    lam(
                        nat_ty(),
                        lam(
                            list_ty(nn()),
                            lam(
                                h_cap_ty.clone(),
                                lam(expr_ty(), lam(list_ty(sframe_ty()), body)),
                            ),
                        ),
                    ),
                ),
            ),
        ),
    );
    let prop = pi(
        nat_ty(),
        pi(
            prog_ty,
            pi(
                list_ty(nn()),
                pi(
                    hmem_t,
                    pi(
                        nat_ty(),
                        pi(
                            list_ty(nn()),
                            pi(
                                h_cap_ty,
                                pi(
                                    expr_ty(),
                                    pi(list_ty(sframe_ty()), id_ty(optn(), a_entry, body_out_n)),
                                ),
                            ),
                        ),
                    ),
                ),
            ),
        ),
    );
    (prop, proof)
}

