#[allow(clippy::too_many_arguments)]
pub fn recfunc_realizes_gen(
    np: usize,
    major_idx: usize,
    tail_steps: usize,
    bodyz: Term,
    bodys_tail: Term,
    argslots: &[usize],
    fuel: Term,
    smf: Term,
    zb: Term,
    sf: Term,
    zb_src: Term,
    hsm: Term,
    recidx_of: &dyn Fn(&Term) -> Term,
    hfs_proof: Term,
    hzero_proof: Term,
    hsucc_proof: Term,
) -> (Term, Term) {
    let arity = np + 1;
    let majslot = np;

    let mk_bfull = |prog: &Term| {
        e_case2(
            btrue(),
            nat_lit(majslot),
            bodyz.clone(),
            e_let(
                op_call(recidx_of(prog), nat_idx_list(argslots)),
                bodys_tail.clone(),
            ),
        )
    };
    let mk_recfunc = |prog: &Term| {
        mk_func(
            nat_lit(arity),
            e_case2(
                btrue(),
                nat_lit(majslot),
                bodyz.clone(),
                e_let(
                    op_call(recidx_of(prog), nat_idx_list(argslots)),
                    bodys_tail.clone(),
                ),
            ),
        )
    };

    let prog = var(np + 1);
    let hmem = var(np);
    let na = |s: usize| app(nat_to_n(), var(np - 1 - s));
    let maj = var(np - 1 - major_idx);
    let carried: Vec<Term> = (0..np).map(&na).collect();
    let carried_cons = lg_cons(&carried);

    let mut entry_arg_slots: Vec<usize> = (0..np).collect();
    entry_arg_slots.push(major_idx);
    let entry_body = e_let(
        op_call(recidx_of(&prog), nat_idx_list(&entry_arg_slots)),
        e_ret(nat_lit(np)),
    );
    let fuel1 = app2(fuel.clone(), nat_lit(1), maj.clone());

    let a_entry = apps(
        s_run(),
        vec![
            prog.clone(),
            nat_s(fuel1.clone()),
            mk_sstate(
                mk_sframe(carried_cons.clone(), entry_body),
                lnil(sframe_ty()),
            ),
        ],
    );
    let callee = lsnoc(nn(), carried_cons.clone(), app(nat_to_n(), maj.clone()));
    let body_entry = apps(
        s_run(),
        vec![
            prog.clone(),
            fuel1.clone(),
            mk_sstate(
                mk_sframe(callee, mk_bfull(&prog)),
                lcons(
                    sframe_ty(),
                    mk_sframe(carried_cons.clone(), e_ret(nat_lit(np))),
                    lnil(sframe_ty()),
                ),
            ),
        ],
    );

    let (_, scall) = srun_call();
    let entry_call = apps(
        scall,
        vec![
            prog.clone(),
            fuel1.clone(),
            carried_cons.clone(),
            recidx_of(&prog),
            nat_idx_list(&entry_arg_slots),
            e_ret(nat_lit(np)),
            lnil(sframe_ty()),
            mk_recfunc(&prog),
            hmem.clone(),
        ],
    );

    let sval = apps(
        mrec(),
        vec![smf.clone(), app(nat_to_n(), zb_src.clone()), maj.clone()],
    );
    let mid = apps(
        s_run(),
        vec![
            prog.clone(),
            nat_lit(1),
            mk_sstate(
                mk_sframe(
                    lsnoc(nn(), carried_cons.clone(), sval.clone()),
                    e_ret(nat_lit(np)),
                ),
                lnil(sframe_ty()),
            ),
        ],
    );
    let v_src = app(
        nat_to_n(),
        apps(nrec(), vec![sf.clone(), zb_src.clone(), maj.clone()]),
    );
    let final_v = some_n(v_src.clone());

    let (_, drive) = recfunc_loop_drive(
        arity,
        majslot,
        tail_steps,
        bodyz.clone(),
        bodys_tail.clone(),
        argslots,
        fuel.clone(),
        smf.clone(),
        zb.clone(),
        recidx_of,
        hfs_proof,
        hzero_proof,
        hsucc_proof,
    );
    let mut h1_args = vec![
        var(np + 2),
        prog.clone(),
        hmem.clone(),
        maj.clone(),
        nat_lit(1),
        carried_cons.clone(),
        e_ret(nat_lit(np)),
        lnil(sframe_ty()),
    ];
    for s in 0..np {
        h1_args.push(na(s));
    }
    let h1 = apps(drive, h1_args);

    let (_, srh) = srun_ret_halt();
    let h2 = apps(
        srh,
        vec![
            prog.clone(),
            nat_lit(0),
            lsnoc(nn(), carried_cons.clone(), sval.clone()),
            nat_lit(np),
        ],
    );

    let (_, rrg) = rec_realizes_gen();
    let bridge = apps(
        rrg,
        vec![sf.clone(), smf.clone(), zb_src.clone(), hsm, maj.clone()],
    );
    let f_some = lam(nn(), some_n(var(0)));
    let bridge_some = ap(nn(), optn(), f_some, sval.clone(), v_src.clone(), bridge);

    let chain_23 = id_trans(
        optn(),
        mid.clone(),
        some_n(sval.clone()),
        final_v.clone(),
        h2,
        bridge_some,
    );
    let chain_1 = id_trans(
        optn(),
        body_entry.clone(),
        mid,
        final_v.clone(),
        h1,
        chain_23,
    );
    let body = id_trans(
        optn(),
        a_entry.clone(),
        body_entry,
        final_v.clone(),
        entry_call,
        chain_1,
    );

    let prog_ty = list_ty(func_ty());
    let h_mem_ty = lg_hmem(recidx_of, &mk_recfunc, var(0));
    let nat_binders = vec![nat_ty(); np];
    let proof = lam(
        nat_ty(),
        lam(
            prog_ty.clone(),
            lam(h_mem_ty.clone(), lams(&nat_binders, body)),
        ),
    );
    let prop = pi(
        nat_ty(),
        pi(
            prog_ty,
            pi(h_mem_ty, pis(&nat_binders, id_ty(optn(), a_entry, final_v))),
        ),
    );
    (prop, proof)
}

