fn set_nth(a: Term, list: Term, idx: Term, x: Term) -> Term {
    let la = list_ty(a.clone());
    let nat_to_la = pi(nat_ty(), la.clone());
    let on_z = lcons(a.clone(), var(6), var(2));
    let on_s = lam(
        nat_ty(),
        lam(la.clone(), lcons(a.clone(), var(5), app(var(3), var(1)))),
    );
    let idx_rec = apps(
        rec(NAT, 1),
        vec![lam(nat_ty(), la.clone()), on_z, on_s, var(0)],
    );
    let on_cons = lam(
        a.clone(),
        lam(la.clone(), lam(nat_to_la.clone(), lam(nat_ty(), idx_rec))),
    );
    let list_rec = apps(
        rec(LIST, 1),
        vec![
            a.clone(),
            lam(la.clone(), nat_to_la),
            lam(nat_ty(), lnil(a.clone())),
            on_cons,
            var(1),
        ],
    );
    let fn_ = lam(a.clone(), lam(la, lam(nat_ty(), app(list_rec, var(0)))));
    apps(fn_, vec![x, list, idx])
}

fn build_args(args: Term) -> Term {
    let argres = sigma(list_ty(nat_ty()), cstate_ty());
    let ret = pi(slotenv_ty(), pi(nat_ty(), pi(cstate_ty(), argres.clone())));
    let on_nil = lam(
        slotenv_ty(),
        lam(
            nat_ty(),
            lam(cstate_ty(), pair_of(argres.clone(), lnil(nat_ty()), var(0))),
        ),
    );
    let body2 = pair_of(
        argres.clone(),
        lcons(nat_ty(), fst(var(1)), fst(var(0))),
        snd(var(0)),
    );
    let r2let = app(
        lam(argres.clone(), body2),
        apps(var(4), vec![var(3), var(2), snd(var(0))]),
    );
    let r1let = app(
        lam(slotst_ty(), r2let),
        apps(var(5), vec![var(2), var(1), var(0)]),
    );
    let on_cons = lam(slotenv_ty(), lam(nat_ty(), lam(cstate_ty(), r1let)));
    case_list(thunk_ty(), ret, on_nil, on_cons, args)
}

fn thunk_reach_tf(t: Term) -> Term {
    let t3 = lift(3, 0, &t);
    let ba = apps(t3, vec![var(2), var(1), var(0)]);
    let out_ops = fst(snd(ba));
    let inreach = prog_reach(&fst(var(0)));
    let outreach = prog_reach(&lift(1, 0, &out_ops));
    pi(
        slotenv_ty(),
        pi(nat_ty(), pi(cstate_ty(), pi(inreach, outreach))),
    )
}

fn allreach_tf(args: Term) -> Term {
    let motive = lam(arglist_ty(), Term::Universe(0));
    let nil_arm = nat_ty();
    let cons_arm = lam(
        thunk_ty(),
        lam(
            arglist_ty(),
            lam(Term::Universe(0), sigma(thunk_reach_tf(var(2)), var(1))),
        ),
    );
    apps(
        rec(LIST, 2),
        vec![thunk_ty(), motive, nil_arm, cons_arm, args],
    )
}

fn bar_motive(args: &Term) -> Term {
    let hall_ty = allreach_tf(args.clone());
    let hin_ty = prog_reach(&fst(var(0)));
    let args5 = lift(5, 0, args);
    let ba = apps(build_args(args5), vec![var(3), var(2), var(1)]);
    let out_ops = fst(snd(ba));
    let outreach = prog_reach(&out_ops);
    pi(
        hall_ty,
        pi(
            slotenv_ty(),
            pi(nat_ty(), pi(cstate_ty(), pi(hin_ty, outreach))),
        ),
    )
}

pub fn build_args_reach_tf() -> (Term, Term) {
    let motive = lam(arglist_ty(), bar_motive(&var(0)));
    let m_nil = lam(
        nat_ty(),
        lam(
            slotenv_ty(),
            lam(
                nat_ty(),
                lam(cstate_ty(), lam(prog_reach(&fst(var(0))), var(0))),
            ),
        ),
    );
    let ih_ty = bar_motive(&var(0));
    let hall_ty_cons = allreach_tf(lcons(thunk_ty(), var(2), var(1)));
    let hin_ty_cons = prog_reach(&fst(var(0)));
    let inner = apps(
        var(5),
        vec![
            snd(var(4)),
            var(3),
            var(2),
            snd(apps(var(7), vec![var(3), var(2), var(1)])),
            apps(fst(var(4)), vec![var(3), var(2), var(1), var(0)]),
        ],
    );
    let body = lam(
        hall_ty_cons,
        lam(
            slotenv_ty(),
            lam(nat_ty(), lam(cstate_ty(), lam(hin_ty_cons, inner))),
        ),
    );
    let m_cons = lam(thunk_ty(), lam(arglist_ty(), lam(ih_ty, body)));
    let proof = lam(
        arglist_ty(),
        apps(
            rec(LIST, 0),
            vec![thunk_ty(), motive, m_nil, m_cons, var(0)],
        ),
    );
    let prop = pi(arglist_ty(), bar_motive(&var(0)));
    (prop, proof)
}

fn p_reach_tf_for(e: &Term) -> Term {
    let hall_ty = allreach_tf(var(0));
    let hin_ty = prog_reach(&fst(var(0)));
    let e6 = lift(6, 0, e);
    let result = apps(app(cbuild(e6), var(5)), vec![var(3), var(2), var(1)]);
    let out_ops = fst(snd(result));
    let outreach = prog_reach(&out_ops);
    pi(
        arglist_ty(),
        pi(
            hall_ty,
            pi(
                slotenv_ty(),
                pi(nat_ty(), pi(cstate_ty(), pi(hin_ty, outreach))),
            ),
        ),
    )
}

fn p_reach_tf_id_tel() -> Vec<Term> {
    vec![
        arglist_ty(),
        allreach_tf(var(0)),
        slotenv_ty(),
        nat_ty(),
        cstate_ty(),
        prog_reach(&fst(var(0))),
    ]
}

pub fn p_reach_tf_box() -> (Term, Term) {
    let goal = p_reach_tf_for(&et_box());
    let proof = lams(&p_reach_tf_id_tel(), var(0));
    (goal, proof)
}

pub fn p_reach_tf_var() -> (Term, Term) {
    let goal = pi(nat_ty(), p_reach_tf_for(&et_var(var(0))));
    let proof = lam(nat_ty(), lams(&p_reach_tf_id_tel(), var(0)));
    (goal, proof)
}

pub fn p_reach_tf_lam() -> (Term, Term) {
    let goal = pi(
        eterm_ty(),
        pi(p_reach_tf_for(&var(0)), p_reach_tf_for(&et_lam(var(1)))),
    );
    let proof = lam(eterm_ty(), lam(p_reach_tf_for(&var(0)), var(0)));
    (goal, proof)
}

pub fn p_reach_tf_constr() -> (Term, Term) {
    let goal = pi(
        nat_ty(),
        pi(nat_ty(), p_reach_tf_for(&et_constr(var(1), var(0)))),
    );
    let (_, batf) = build_args_reach_tf();
    let (_, rsc) = reach_single_constr_t();
    let (_, pra) = prog_reach_append();

    let ba_body = apps(build_args(var(5)), vec![var(3), var(2), var(1)]);
    let ba_ops = fst(snd(ba_body.clone()));
    let op = op_constr(btrue(), var(6), fst(ba_body));

    let step1 = apps(batf, vec![var(5), var(4), var(3), var(2), var(1), var(0)]);

    let step2 = lam(
        list_ty(func_ty()),
        lam(
            list_ty(sframe_ty()),
            apps(
                rsc,
                vec![
                    var(1),
                    btrue(),
                    var(8),
                    fst(apps(build_args(var(7)), vec![var(5), var(4), var(3)])),
                    var(0),
                ],
            ),
        ),
    );

    let single = lcons(op_ty(), op, lnil(op_ty()));
    let step3 = apps(pra, vec![ba_ops, single, step1, step2]);

    let inner = lams(&p_reach_tf_id_tel(), step3);
    let proof = lam(nat_ty(), lam(nat_ty(), inner));
    (goal, proof)
}

pub fn p_reach_tf_app() -> (Term, Term) {
    let goal = pi(
        eterm_ty(),
        pi(
            eterm_ty(),
            pi(
                p_reach_tf_for(&var(1)),
                pi(
                    p_reach_tf_for(&var(1)),
                    p_reach_tf_for(&et_app(var(3), var(2))),
                ),
            ),
        ),
    );
    let thunk_x = app(cbuild(var(8)), lnil(thunk_ty()));
    let args_ext = lcons(thunk_ty(), thunk_x, var(5));
    let xreach = apps(var(6), vec![lnil(thunk_ty()), nat_z()]);
    let hall_ext = pair_of(allreach_tf(args_ext.clone()), xreach, var(4));
    let inner = apps(
        var(7),
        vec![args_ext, hall_ext, var(3), var(2), var(1), var(0)],
    );
    let body = lams(&p_reach_tf_id_tel(), inner);
    let proof = lam(
        eterm_ty(),
        lam(
            eterm_ty(),
            lam(p_reach_tf_for(&var(1)), lam(p_reach_tf_for(&var(1)), body)),
        ),
    );
    (goal, proof)
}

pub fn reach_to_srun() -> (Term, Term) {
    let tel = vec![
        list_ty(op_ty()),
        prog_reach(&var(0)),
        list_ty(func_ty()),
        list_ty(sframe_ty()),
        list_ty(nn()),
        expr_ty(),
        nat_ty(),
    ];
    let d = var(6);
    let h = var(5);
    let p = var(4);
    let stk = var(3);
    let locals = var(2);
    let cc = var(1);
    let m = var(0);
    let sealed = fa_st(
        locals.clone(),
        seal_cont(d.clone(), cc.clone()),
        stk.clone(),
    );
    let exit = fa_st(
        run_locals(d.clone(), locals.clone()),
        cc.clone(),
        stk.clone(),
    );
    let k = ops_fuel(d.clone(), nat_z());
    let concl = id_ty(
        optn(),
        s_run_app(
            p.clone(),
            apps(nat_add(), vec![m.clone(), k.clone()]),
            sealed,
        ),
        s_run_app(p.clone(), m.clone(), exit.clone()),
    );
    let h_some = apps(
        h,
        vec![p.clone(), stk.clone(), locals.clone(), cc.clone(), nat_z()],
    );
    let (_, fa) = fuel_additivity();
    let body = apps(
        fa,
        vec![p, k, locals, seal_cont(d, cc), stk, exit, h_some, m],
    );
    let proof = lams(&tel, body);
    let prop = pis(&tel, concl);
    (prop, proof)
}

