fn result_a0(o: Term) -> Term {
    case_opt_state(
        optn(),
        none_n(),
        some_n(app2(
            read_reg(),
            st_regs(var(0)),
            n_of_u64(crate::target::A0 as u64),
        )),
        o,
    )
}

pub fn refines_a0(init: Term, fuel: Term, spec_val: Term) -> (Term, Term) {
    let executed = result_a0(app2(run(), fuel, init));
    let spec = some_n(spec_val);
    let prop = id_ty(optn(), executed, spec.clone());
    let proof = refl(optn(), spec);
    (prop, proof)
}

pub fn runf() -> Term {
    let motive = lam(nat_ty(), pi(state_ty(), opt_state()));
    let m_o = lam(state_ty(), none_state());
    let m_s = lam(
        nat_ty(),
        lam(
            pi(state_ty(), opt_state()),
            lam(
                state_ty(),
                case_opt_state(
                    opt_state(),
                    some_state(var(0)),
                    app(var(2), var(0)),
                    app(var(5), var(0)),
                ),
            ),
        ),
    );
    lam(
        pi(state_ty(), opt_state()),
        lam(
            nat_ty(),
            lam(
                state_ty(),
                app(apps(rec(NAT, 1), vec![motive, m_o, m_s, var(1)]), var(0)),
            ),
        ),
    )
}

fn runf_app(f: usize, k: usize, s: usize) -> Term {
    apps(runf(), vec![var(f), var(k), var(s)])
}

pub fn never_halts_generic() -> (Term, Term) {
    let ft = pi(state_ty(), opt_state());
    let prop = pi(
        ft.clone(),
        pi(
            state_ty(),
            pi(
                id_ty(opt_state(), some_state(var(0)), app(var(1), var(0))),
                pi(
                    nat_ty(),
                    id_ty(opt_state(), runf_app(3, 0, 2), none_state()),
                ),
            ),
        ),
    );

    let motive = lam(
        nat_ty(),
        id_ty(opt_state(), runf_app(4, 0, 3), none_state()),
    );
    let base = refl(opt_state(), none_state());

    let p_motive = lam(
        opt_state(),
        lam(
            id_ty(opt_state(), some_state(var(5)), var(0)),
            id_ty(
                opt_state(),
                apps(
                    rec(OPTION, 1),
                    vec![
                        state_ty(),
                        lam(opt_state(), opt_state()),
                        some_state(var(6)),
                        lam(state_ty(), runf_app(8, 4, 0)),
                        var(1),
                    ],
                ),
                none_state(),
            ),
        ),
    );
    let jterm = apps(
        rec(ID, 0),
        vec![
            opt_state(),
            some_state(var(4)),
            p_motive,
            var(0),
            app(var(5), var(4)),
            var(3),
        ],
    );
    let step_method = lam(
        nat_ty(),
        lam(id_ty(opt_state(), runf_app(4, 0, 3), none_state()), jterm),
    );

    let proof = lam(
        ft,
        lam(
            state_ty(),
            lam(
                id_ty(opt_state(), some_state(var(0)), app(var(1), var(0))),
                lam(
                    nat_ty(),
                    apps(rec(NAT, 0), vec![motive, base, step_method, var(0)]),
                ),
            ),
        ),
    );
    (prop, proof)
}

pub fn add1_nonzero() -> (Term, Term) {
    let guard = |m: Term| {
        id_ty(
            bb(),
            app2(n_eqb(), app2(n_add(), m, npos(xh())), n0()),
            bfalse(),
        )
    };
    let motive = lam(nn(), guard(var(0)));
    let base = refl(bb(), bfalse());
    let step = lam(p(), refl(bb(), bfalse()));
    let prop = pi(nn(), guard(var(0)));
    let proof = lam(nn(), apps(rec(N, 0), vec![motive, base, step, var(0)]));
    (prop, proof)
}

