pub fn n_to_nat_add1() -> (Term, Term) {
    let goal = |w: Term| {
        id_ty(
            nat_ty(),
            app(n_to_nat(), app2(n_add(), w.clone(), npos(xh()))),
            nat_s(app(n_to_nat(), w)),
        )
    };
    let motive = lam(nn(), goal(var(0)));
    let m_n0 = refl(nat_ty(), nat_s(nat_z()));
    let (_, paf) = pos_add_1r_flip();
    let (_, pts) = pos_to_nat_succ();
    let ap_pts = ap(
        p(),
        nat_ty(),
        pos_to_nat(),
        app(succ(), var(0)),
        app2(pos_add(), var(0), xh()),
        app(paf, var(0)),
    );
    let sym = id_sym(
        nat_ty(),
        app(pos_to_nat(), app(succ(), var(0))),
        app(pos_to_nat(), app2(pos_add(), var(0), xh())),
        ap_pts,
    );
    let chain = id_trans(
        nat_ty(),
        app(pos_to_nat(), app2(pos_add(), var(0), xh())),
        app(pos_to_nat(), app(succ(), var(0))),
        nat_s(app(pos_to_nat(), var(0))),
        sym,
        app(pts, var(0)),
    );
    let m_npos = lam(p(), chain);
    let prop = pi(nn(), goal(var(0)));
    let proof = lam(nn(), apps(rec(N, 0), vec![motive, m_n0, m_npos, var(0)]));
    (prop, proof)
}

pub fn lemma_r() -> (Term, Term) {
    let goal = |k: Term| id_ty(nat_ty(), app(n_to_nat(), app(nat_to_n(), k.clone())), k);
    let motive = lam(nat_ty(), goal(var(0)));
    let m_z = refl(nat_ty(), nat_z());
    let (_, add1) = n_to_nat_add1();
    let xn = app(nat_to_n(), var(1));
    let ap_s = ap(
        nat_ty(),
        nat_ty(),
        constr(NAT, 1),
        app(n_to_nat(), xn.clone()),
        var(1),
        var(0),
    );
    let trans = id_trans(
        nat_ty(),
        app(n_to_nat(), app2(n_add(), xn.clone(), npos(xh()))),
        nat_s(app(n_to_nat(), xn.clone())),
        nat_s(var(1)),
        app(add1, xn),
        ap_s,
    );
    let m_s = lam(nat_ty(), lam(goal(var(0)), trans));
    let prop = pi(nat_ty(), goal(var(0)));
    let proof = lam(nat_ty(), apps(rec(NAT, 0), vec![motive, m_z, m_s, var(0)]));
    (prop, proof)
}

pub fn nat_to_n_inj() -> (Term, Term) {
    let hyp = id_ty(nn(), app(nat_to_n(), var(1)), app(nat_to_n(), var(0)));
    let prop = pi(
        nat_ty(),
        pi(nat_ty(), pi(hyp.clone(), id_ty(nat_ty(), var(2), var(1)))),
    );
    let (_, r) = lemma_r();
    let nm = || app(n_to_nat(), app(nat_to_n(), var(2)));
    let nk = || app(n_to_nat(), app(nat_to_n(), var(1)));
    let r_m = app(r.clone(), var(2));
    let r_n = app(r, var(1));
    let ap_h = ap(
        nn(),
        nat_ty(),
        n_to_nat(),
        app(nat_to_n(), var(2)),
        app(nat_to_n(), var(1)),
        var(0),
    );
    let sym_rm = id_sym(nat_ty(), nm(), var(2), r_m);
    let t1 = id_trans(nat_ty(), var(2), nm(), nk(), sym_rm, ap_h);
    let t2 = id_trans(nat_ty(), var(2), nk(), var(1), t1, r_n);
    let proof = lam(nat_ty(), lam(nat_ty(), lam(hyp, t2)));
    (prop, proof)
}

