pub fn elim_tag_correct() -> (Term, Term) {
    let goal = |v: Term| {
        id_ty(
            bb(),
            app2(n_eqb(), app(nat_to_n(), v.clone()), n0()),
            app(nat_is_zero(), v),
        )
    };
    let motive = lam(nat_ty(), goal(var(0)));
    let m_z = refl(bb(), btrue());
    let (_, a1nz) = add1_nonzero();
    let m_s = lam(
        nat_ty(),
        lam(goal(var(0)), app(a1nz, app(nat_to_n(), var(1)))),
    );
    let prop = pi(nat_ty(), goal(var(0)));
    let proof = lam(nat_ty(), apps(rec(NAT, 0), vec![motive, m_z, m_s, var(0)]));
    (prop, proof)
}

pub fn pred_realizes_gen() -> (Term, Term) {
    let hdec = pi(
        nn(),
        id_ty(nn(), app(var(1), app2(n_add(), var(0), npos(xh()))), var(0)),
    );
    let goalbody = id_ty(
        nn(),
        app2(mpred_gen(), var(2), app(nat_to_n(), var(0))),
        app(nat_to_n(), app(npred(), var(0))),
    );
    let prop = pi(pi(nn(), nn()), pi(hdec.clone(), pi(nat_ty(), goalbody)));

    let (_, a1nz) = add1_nonzero();
    let motive = lam(
        nat_ty(),
        id_ty(
            nn(),
            app2(mpred_gen(), var(3), app(nat_to_n(), var(0))),
            app(nat_to_n(), app(npred(), var(0))),
        ),
    );
    let m_z = refl(nn(), n0());
    let t_succ = app(nat_to_n(), nat_s(var(1)));
    let x = app2(mpred_gen(), var(4), t_succ.clone());
    let y = app(var(4), t_succ.clone());
    let z = app(nat_to_n(), var(1));
    let f = lam(
        bb(),
        case_bool(
            nn(),
            app(var(5), app(nat_to_n(), nat_s(var(2)))),
            n0(),
            var(0),
        ),
    );
    let guard = app2(n_eqb(), t_succ, n0());
    let collapse = ap(
        bb(),
        nn(),
        f,
        guard,
        bfalse(),
        app(a1nz, app(nat_to_n(), var(1))),
    );
    let hdec_inst = app(var(3), app(nat_to_n(), var(1)));
    let s_body = id_trans(nn(), x, y, z, collapse, hdec_inst);
    let m_s_goal = id_ty(
        nn(),
        app2(mpred_gen(), var(3), app(nat_to_n(), var(0))),
        app(nat_to_n(), app(npred(), var(0))),
    );
    let m_s = lam(nat_ty(), lam(m_s_goal, s_body));
    let proof = lam(
        pi(nn(), nn()),
        lam(
            hdec.clone(),
            lam(nat_ty(), apps(rec(NAT, 0), vec![motive, m_z, m_s, var(0)])),
        ),
    );
    (prop, proof)
}

pub fn pred_realizes() -> (Term, Term) {
    let (_, gen) = pred_realizes_gen();
    let (_, dcr) = decr();
    let proof = apps(gen, vec![mpred_dec(), dcr]);
    let goal = |v: Term| {
        id_ty(
            nn(),
            app(mpred(), app(nat_to_n(), v.clone())),
            app(nat_to_n(), app(npred(), v)),
        )
    };
    let prop = pi(nat_ty(), goal(var(0)));
    (prop, proof)
}

