pub fn inner_add_realizes() -> (Term, Term) {
    let nt = |x: Term| app(nat_to_n(), x);
    let na = |x: Term, y: Term| app2(nat_add(), x, y);
    let nadd = |x: Term, y: Term| app2(n_add(), x, y);
    let inner_at = |b: Term, acc: Term| app(app(inner_spec(), b), acc);
    let bnd_ty =
        |m: Term, b: Term, room: Term| id_ty(nn(), nadd(nt(na(m, b)), npos(room)), n_pow2(64));
    let goal_ty = |b: Term, m: Term| id_ty(nn(), inner_at(b.clone(), nt(m.clone())), nt(na(m, b)));

    let prop = pi(
        nat_ty(),
        pi(
            nat_ty(),
            pi(
                p(),
                pi(bnd_ty(var(1), var(2), var(0)), goal_ty(var(3), var(2))),
            ),
        ),
    );

    let motive = lam(
        nat_ty(),
        pi(
            nat_ty(),
            pi(
                p(),
                pi(bnd_ty(var(1), var(2), var(0)), goal_ty(var(3), var(2))),
            ),
        ),
    );
    let base = lam(
        nat_ty(),
        lam(
            p(),
            lam(bnd_ty(var(1), nat_z(), var(0)), refl(nn(), nt(var(2)))),
        ),
    );
    let ih_ty = pi(
        nat_ty(),
        pi(
            p(),
            pi(bnd_ty(var(1), var(2), var(0)), goal_ty(var(3), var(2))),
        ),
    );

    let (_, nasl) = nat_add_succ_l();
    let (_, h) = nat_to_n_add();
    let (_, incr) = incr_realizes_succ();
    let (_, nlab) = n_lt_of_add_bound();

    let s_body = {
        let k = || var(4);
        let ih = || var(3);
        let m = || var(2);
        let room = || var(1);
        let bnd = || var(0);
        let eq_swap = id_sym(
            nat_ty(),
            na(nat_s(m()), k()),
            nat_s(na(m(), k())),
            apps(nasl.clone(), vec![m(), k()]),
        );
        let step1 = ap(
            nat_ty(),
            nn(),
            nat_to_n(),
            na(m(), nat_s(k())),
            na(nat_s(m()), k()),
            eq_swap.clone(),
        );
        let step2 = apps(h.clone(), vec![nat_s(m()), k()]);
        let r1 = id_trans(
            nn(),
            nt(na(m(), nat_s(k()))),
            nt(na(nat_s(m()), k())),
            nadd(nt(nat_s(m())), nt(k())),
            step1.clone(),
            step2,
        );
        let ap_r1 = ap(
            nn(),
            nn(),
            lam(nn(), nadd(var(0), npos(var(2)))),
            nt(na(m(), nat_s(k()))),
            nadd(nt(nat_s(m())), nt(k())),
            r1,
        );
        let bnd_prime = id_trans(
            nn(),
            nadd(nadd(nt(nat_s(m())), nt(k())), npos(room())),
            nadd(nt(na(m(), nat_s(k()))), npos(room())),
            n_pow2(64),
            id_sym(
                nn(),
                nadd(nt(na(m(), nat_s(k()))), npos(room())),
                nadd(nadd(nt(nat_s(m())), nt(k())), npos(room())),
                ap_r1,
            ),
            bnd(),
        );
        let guard_proof = apps(
            nlab.clone(),
            vec![nt(nat_s(m())), nt(k()), room(), n_pow2(64), bnd_prime],
        );
        let coll = apps(incr.clone(), vec![m(), guard_proof]);
        let b_step = ap(
            nn(),
            nn(),
            lam(nn(), inner_at(var(5), var(0))),
            app2(wrap_add(), nt(m()), n_of_u64(1)),
            nt(nat_s(m())),
            coll,
        );
        let ap_s = ap(
            nn(),
            nn(),
            lam(nn(), nadd(var(0), npos(var(2)))),
            nt(na(m(), nat_s(k()))),
            nt(na(nat_s(m()), k())),
            step1,
        );
        let bnd_dprime = id_trans(
            nn(),
            nadd(nt(na(nat_s(m()), k())), npos(room())),
            nadd(nt(na(m(), nat_s(k()))), npos(room())),
            n_pow2(64),
            id_sym(
                nn(),
                nadd(nt(na(m(), nat_s(k()))), npos(room())),
                nadd(nt(na(nat_s(m()), k())), npos(room())),
                ap_s,
            ),
            bnd(),
        );
        let c_step = apps(ih(), vec![nat_s(m()), room(), bnd_dprime]);
        let d_step = ap(
            nat_ty(),
            nn(),
            nat_to_n(),
            na(nat_s(m()), k()),
            na(m(), nat_s(k())),
            id_sym(nat_ty(), na(m(), nat_s(k())), na(nat_s(m()), k()), eq_swap),
        );
        let bc = id_trans(
            nn(),
            inner_at(k(), app2(wrap_add(), nt(m()), n_of_u64(1))),
            inner_at(k(), nt(nat_s(m()))),
            nt(na(nat_s(m()), k())),
            b_step,
            c_step,
        );
        id_trans(
            nn(),
            inner_at(k(), app2(wrap_add(), nt(m()), n_of_u64(1))),
            nt(na(nat_s(m()), k())),
            nt(na(m(), nat_s(k()))),
            bc,
            d_step,
        )
    };
    let m_s = lam(
        nat_ty(),
        lam(
            ih_ty,
            lam(
                nat_ty(),
                lam(p(), lam(bnd_ty(var(1), nat_s(var(3)), var(0)), s_body)),
            ),
        ),
    );
    let proof = lam(nat_ty(), apps(rec(NAT, 0), vec![motive, base, m_s, var(0)]));
    (prop, proof)
}

