    fn empty_mem() -> Term {
        leaf()
    }

    fn wr(m: Term, k: u64, v: u64) -> Term {
        apps(mem_write(), vec![m, n_of_u64(k), n_of_u64(v)])
    }

    fn rd(m: Term, k: u64) -> Term {
        app2(mem_read(), m, n_of_u64(k))
    }

