    #[test]
    fn arithmetic_64bit() {
        let sig = numerals_sig();
        let add_cases = [
            (1u64 << 40, 1u64 << 40),
            ((1u64 << 48) - 1, 1),
            (0xFFFF_FFFF_FFFF, 0xFFFF_FFFF_FFFF),
            (0x1234_5678_9ABC, 0x0123_4567_89AB),
            (0x7FFF_FFFF_FFFF_FFFF, 0x7FFF_FFFF_FFFF_FFFF),
        ];
        for (a, b) in add_cases {
            assert_eq!(
                norm(&sig, &app2(n_add(), n_of_u64(a), n_of_u64(b))),
                n_of_u64(a + b)
            );
        }
        let cmp_cases = [
            (0xFFFF_FFFF_FFFF_FFFFu64, 0xFFFF_FFFF_FFFF_FFFEu64),
            (0x8000_0000_0000_0000, 0x7FFF_FFFF_FFFF_FFFF),
            (1u64 << 63, 1u64 << 63),
            (0, 0xFFFF_FFFF_FFFF_FFFF),
        ];
        for (a, b) in cmp_cases {
            assert_eq!(
                norm(&sig, &app2(n_compare(), n_of_u64(a), n_of_u64(b))),
                cmp_lit(a.cmp(&b))
            );
            assert_eq!(
                norm(&sig, &app2(n_sub(), n_of_u64(a), n_of_u64(b))),
                n_of_u64(a.saturating_sub(b))
            );
        }
    }

