    fn expected_instr(i: crate::target::Instr) -> Term {
        use crate::target::Instr::*;
        let n = |x: u32| n_of_u64(x as u64);
        let s = |x: i32| n_of_u64(x as i64 as u64);
        match i {
            Addi(rd, rs1, imm) => apps(constr(INSTR, 0), vec![n(rd), n(rs1), s(imm)]),
            Add(rd, rs1, rs2) => apps(constr(INSTR, 1), vec![n(rd), n(rs1), n(rs2)]),
            Sub(rd, rs1, rs2) => apps(constr(INSTR, 2), vec![n(rd), n(rs1), n(rs2)]),
            Lui(rd, imm) => apps(constr(INSTR, 3), vec![n(rd), s(imm)]),
            Beq(rs1, rs2, off) => apps(constr(INSTR, 4), vec![n(rs1), n(rs2), s(off)]),
            Bne(rs1, rs2, off) => apps(constr(INSTR, 5), vec![n(rs1), n(rs2), s(off)]),
            Blt(rs1, rs2, off) => apps(constr(INSTR, 6), vec![n(rs1), n(rs2), s(off)]),
            Jal(rd, off) => apps(constr(INSTR, 7), vec![n(rd), s(off)]),
            Jalr(rd, rs1, imm) => apps(constr(INSTR, 8), vec![n(rd), n(rs1), s(imm)]),
            Ld(rd, rs1, off) => apps(constr(INSTR, 9), vec![n(rd), n(rs1), s(off)]),
            Sd(rs2, rs1, off) => apps(constr(INSTR, 10), vec![n(rs2), n(rs1), s(off)]),
            Ecall => constr(INSTR, 11),
            Unknown(w) => app(constr(INSTR, 12), n(w)),
        }
    }

