    #[test]
    fn decode_matches_target_encoder() {
        use crate::target::{Instr, A0, A1, RA, SP, T0, T1, T2, ZERO};
        let sig = numerals_sig();
        let prog = [
            Instr::Addi(A0, SP, -2048),
            Instr::Addi(T0, ZERO, 2047),
            Instr::Add(A0, T1, T2),
            Instr::Sub(RA, A0, A1),
            Instr::Lui(T0, 0x1_2345),
            Instr::Lui(A0, -1),
            Instr::Beq(T0, T1, 48),
            Instr::Bne(A0, A1, -16),
            Instr::Blt(T1, T2, 4094),
            Instr::Blt(SP, RA, -4096),
            Instr::Jal(RA, -32),
            Instr::Jal(ZERO, 1048574),
            Instr::Jalr(ZERO, RA, 0),
            Instr::Jalr(A0, T0, -1),
            Instr::Ld(T0, SP, 0),
            Instr::Ld(A0, T1, -8),
            Instr::Sd(RA, SP, 16),
            Instr::Sd(T0, SP, -24),
            Instr::Ecall,
        ];
        for i in prog {
            let w = crate::target::encode(i);
            assert_eq!(
                norm(&sig, &app(decode(), n_of_u64(w as u64))),
                expected_instr(i),
                "decode mismatch for {:?} (word {:#010x})",
                i,
                w
            );
        }
        for w in [0u32, 0x0000_0017, 0xffff_ffff] {
            assert_eq!(
                norm(&sig, &app(decode(), n_of_u64(w as u64))),
                expected_instr(crate::target::decode(w))
            );
        }
    }

    fn unwrap_opt_state(t: &Term) -> Option<Term> {
        match t {
            Term::App(f, inner) => match &**f {
                Term::App(g, _) if matches!(**g, Term::Constr(5, 1)) => Some((**inner).clone()),
                _ => None,
            },
            _ => None,
        }
    }

    fn init_state(prog: &[crate::target::Instr]) -> Term {
        let bytes = crate::target::assemble(prog);
        let mut m = leaf();
        for (a, b) in bytes.iter().enumerate() {
            m = apps(
                mem_write(),
                vec![m, n_of_u64(a as u64), n_of_u64(*b as u64)],
            );
        }
        let regs = apps(
            mem_write(),
            vec![
                leaf(),
                n_of_u64(crate::target::SP as u64),
                n_of_u64(0x10_0000),
            ],
        );
        mk_state(regs, n_of_u64(0), m)
    }

    fn run_inlogic(sig: &Rc<Sig>, prog: &[crate::target::Instr], fuel: usize) -> Term {
        let st = step();
        let mut s = norm(sig, &init_state(prog));
        for _ in 0..fuel {
            let r = norm(sig, &app(st.clone(), s.clone()));
            match unwrap_opt_state(&r) {
                Some(s2) => s = s2,
                None => return s,
            }
        }
        s
    }

    fn inlogic_reg(sig: &Rc<Sig>, s: &Term, r: u32) -> u64 {
        let v = norm(
            sig,
            &app2(read_reg(), st_regs(s.clone()), n_of_u64(r as u64)),
        );
        n_to_u64(&v).unwrap()
    }

    fn inlogic_pc(sig: &Rc<Sig>, s: &Term) -> u64 {
        n_to_u64(&norm(sig, &st_pc(s.clone()))).unwrap()
    }

