    #[test]
    fn step_matches_target_exec() {
        use crate::target::Instr::*;
        use crate::target::{A0, A1, RA, SP, T0, T1, T2, ZERO};
        let sig = numerals_sig();
        let countdown = vec![
            Addi(A0, ZERO, 0),
            Addi(T0, ZERO, 5),
            Beq(T0, ZERO, 16),
            Add(A0, A0, T0),
            Addi(T0, T0, -1),
            Jal(ZERO, -12),
            Ecall,
        ];
        let stack_call = vec![
            Addi(T0, ZERO, 3),
            Sd(T0, SP, -24),
            Addi(T0, ZERO, 4),
            Sd(T0, SP, -16),
            Addi(SP, SP, -24),
            Jal(RA, 12),
            Addi(SP, SP, 24),
            Ecall,
            Sd(RA, SP, 16),
            Ld(T0, SP, 0),
            Ld(T1, SP, 8),
            Add(A0, T0, T1),
            Ld(RA, SP, 16),
            Jalr(ZERO, RA, 0),
        ];
        let arith = vec![
            Lui(A0, 0x1_2345),
            Lui(A1, -2),
            Addi(T0, ZERO, 7),
            Addi(T1, ZERO, 9),
            Sub(A0, T1, T0),
            Bne(T0, T1, 8),
            Addi(T2, ZERO, 111),
            Blt(T0, T1, 8),
            Addi(T2, ZERO, 222),
            Addi(RA, ZERO, -5),
            Blt(RA, ZERO, 8),
            Addi(A1, ZERO, 1),
            Addi(A1, ZERO, 2),
            Ecall,
        ];
        let branches = vec![
            Addi(T0, ZERO, 5),
            Addi(T1, ZERO, 5),
            Beq(T0, T1, 8),
            Addi(A0, ZERO, 100),
            Bne(T0, T1, 8),
            Addi(A1, ZERO, 7),
            Blt(T0, T1, 8),
            Addi(T2, ZERO, 9),
            Ecall,
        ];
        for prog in [countdown, stack_call, arith, branches] {
            let bytes = crate::target::assemble(&prog);
            let cpu = crate::target::run(&bytes, 1000).unwrap();
            let s = run_inlogic(&sig, &prog, 1000);
            for r in 0..32u32 {
                assert_eq!(
                    inlogic_reg(&sig, &s, r),
                    cpu.reg(r) as u64,
                    "{:?}: reg x{} mismatch",
                    prog,
                    r
                );
            }
            assert_eq!(inlogic_pc(&sig, &s), cpu.pc, "{:?}: pc mismatch", prog);
        }
    }

