    #[test]
    fn run_matches_target_inlogic() {
        use crate::target::Instr::*;
        use crate::target::{A0, RA, SP, T0, T1, ZERO};
        let sig = numerals_sig();
        let countdown = vec![
            Addi(A0, ZERO, 0),
            Addi(T0, ZERO, 5),
            Beq(T0, ZERO, 16),
            Add(A0, A0, T0),
            Addi(T0, T0, -1),
            Jal(ZERO, -12),
            Ecall,
        ];
        let stack_call = vec![
            Addi(T0, ZERO, 3),
            Sd(T0, SP, -24),
            Addi(T0, ZERO, 4),
            Sd(T0, SP, -16),
            Addi(SP, SP, -24),
            Jal(RA, 12),
            Addi(SP, SP, 24),
            Ecall,
            Sd(RA, SP, 16),
            Ld(T0, SP, 0),
            Ld(T1, SP, 8),
            Add(A0, T0, T1),
            Ld(RA, SP, 16),
            Jalr(ZERO, RA, 0),
        ];
        for (prog, fuel) in [(countdown, 40usize), (stack_call, 40usize)] {
            let bytes = crate::target::assemble(&prog);
            let cpu = crate::target::run(&bytes, 1000).unwrap();
            let out = norm(&sig, &app2(run(), nat_lit(fuel), init_state(&prog)));
            let final_state = unwrap_opt_state(&out).expect("run halts with Some(state)");
            for r in 0..32u32 {
                assert_eq!(
                    inlogic_reg(&sig, &final_state, r),
                    cpu.reg(r) as u64,
                    "{:?}: reg x{} mismatch",
                    prog,
                    r
                );
            }
            assert_eq!(
                inlogic_pc(&sig, &final_state),
                cpu.pc,
                "{:?}: pc mismatch",
                prog
            );
        }
    }

    #[test]
    fn nested_mul_loop_grounds() {
        use crate::target::Instr::*;
        use crate::target::{A0, A1, T0, T1, ZERO};
        let sig = numerals_sig();
        let mem = nested_mem();
        let st = step();
        for (a, b) in [(2u64, 3u64), (1, 1), (0, 5), (3, 0)] {
            let mut regs = apps(write_reg(), vec![leaf(), n_of_u64(A0 as u64), n_of_u64(0)]);
            regs = apps(write_reg(), vec![regs, n_of_u64(T0 as u64), n_of_u64(0)]);
            regs = apps(write_reg(), vec![regs, n_of_u64(T1 as u64), n_of_u64(a)]);
            regs = apps(write_reg(), vec![regs, n_of_u64(A1 as u64), n_of_u64(b)]);
            let entry = mk_state(regs, n_of_u64(8), mem.clone());
            let mut s = norm(&sig, &entry);
            let mut halted = false;
            for _ in 0..400 {
                let r = norm(&sig, &app(st.clone(), s.clone()));
                match unwrap_opt_state(&r) {
                    Some(s2) => s = s2,
                    None => {
                        halted = true;
                        break;
                    }
                }
            }
            assert!(halted, "in-logic mul({}, {}) did not halt", a, b);
            assert_eq!(
                inlogic_reg(&sig, &s, A0),
                a * b,
                "in-logic mul({}, {}) wrong A0",
                a,
                b
            );
        }
        for (a, b) in [(2u64, 3u64), (3, 4), (0, 5), (5, 0), (1, 1), (4, 2), (6, 6)] {
            let baked = vec![
                Addi(A0, ZERO, 0),
                Addi(T1, ZERO, a as i32),
                Addi(A1, ZERO, b as i32),
                Beq(T1, ZERO, 32),
                Add(T0, A1, ZERO),
                Beq(T0, ZERO, 16),
                Addi(A0, A0, 1),
                Addi(T0, T0, -1),
                Jal(ZERO, -12),
                Addi(T1, T1, -1),
                Jal(ZERO, -28),
                Ecall,
            ];
            let cpu = crate::target::run(&crate::target::assemble(&baked), 5000).unwrap();
            assert_eq!(
                cpu.reg(A0) as u64,
                a * b,
                "reference mul({}, {}) wrong A0",
                a,
                b
            );
        }
    }

    #[test]
    fn countdown_refinement_certificate_is_kernel_checked() {
        use crate::target::Instr::*;
        use crate::target::{A0, T0, ZERO};
        let sig = numerals_sig();
        let ctx = Context::with_sig(sig.clone());
        let countdown = vec![
            Addi(A0, ZERO, 0),
            Addi(T0, ZERO, 5),
            Beq(T0, ZERO, 16),
            Add(A0, A0, T0),
            Addi(T0, T0, -1),
            Jal(ZERO, -12),
            Ecall,
        ];
        let (prop, proof) = refines_a0(
            init_state(&countdown),
            nat_lit(40),
            app(sum_to(), nat_lit(5)),
        );
        assert!(infer(&ctx, &proof).is_ok());
        assert!(crate::check(&ctx, &proof, &crate::eval(&sig, &Vec::new(), &prop)).is_ok());

        let (wrong_prop, wrong_proof) =
            refines_a0(init_state(&countdown), nat_lit(40), n_of_u64(16));
        assert!(crate::check(
            &ctx,
            &wrong_proof,
            &crate::eval(&sig, &Vec::new(), &wrong_prop)
        )
        .is_err());
    }

    fn state_of(prog: &[crate::target::Instr]) -> Term {
        let bytes = crate::target::assemble(prog);
        let mut mem = leaf();
        for (k, b) in bytes.iter().enumerate() {
            mem = apps(
                mem_write(),
                vec![mem, n_of_u64(k as u64), n_of_u64(*b as u64)],
            );
        }
        mk_state(leaf(), n_of_u64(0), mem)
    }

    #[test]
    fn never_halts_generic_typechecks() {
        let sig = numerals_sig();
        let ctx = Context::with_sig(sig.clone());
        assert_eq!(
            crate::quote(0, &infer(&ctx, &runf()).unwrap()),
            pi(
                pi(state_ty(), opt_state()),
                pi(nat_ty(), pi(state_ty(), opt_state()))
            )
        );
        let (prop, proof) = never_halts_generic();
        assert!(infer(&ctx, &proof).is_ok());
        assert!(crate::check(&ctx, &proof, &crate::eval(&sig, &Vec::new(), &prop)).is_ok());
    }

    #[test]
    fn never_halts_instantiated_at_real_step() {
        use crate::target::Instr::*;
        use crate::target::ZERO;
        let sig = numerals_sig();
        let ctx = Context::with_sig(sig.clone());
        let nf = |t: &Term| crate::quote(0, &crate::eval(&sig, &Vec::new(), t));

        let s0 = state_of(&[Jal(ZERO, 0)]);
        assert_eq!(nf(&app(step(), s0.clone())), nf(&some_state(s0.clone())));
        assert_eq!(
            nf(&apps(runf(), vec![step(), nat_lit(5), s0.clone()])),
            nf(&app2(run(), nat_lit(5), s0.clone()))
        );

        let (_, generic) = never_halts_generic();
        let proof_inst = apps(
            generic.clone(),
            vec![
                step(),
                s0.clone(),
                refl(opt_state(), some_state(s0.clone())),
            ],
        );
        assert!(infer(&ctx, &proof_inst).is_ok());

        let goal5 = id_ty(
            opt_state(),
            apps(runf(), vec![step(), nat_lit(5), s0.clone()]),
            none_state(),
        );
        let inst5 = app(proof_inst, nat_lit(5));
        assert!(crate::check(&ctx, &inst5, &crate::eval(&sig, &Vec::new(), &goal5)).is_ok());

        let s_halt = state_of(&[Ecall]);
        let bad = apps(
            generic,
            vec![
                step(),
                s_halt.clone(),
                refl(opt_state(), some_state(s_halt)),
            ],
        );
        assert!(infer(&ctx, &bad).is_err());
    }

