    #[test]
    fn list_stdlib_is_kernel_checked() {
        let sig = numerals_sig();
        let ctx = Context::with_sig(sig.clone());
        let lty = app(ind(LIST), bb());
        let opt_b = app(ind(OPTION), bb());
        let nil = app(constr(LIST, 0), bb());
        let cons = |h: Term, t: Term| apps(constr(LIST, 1), vec![bb(), h, t]);
        let some_b = |v: Term| app2(constr(OPTION, 1), bb(), v);
        let none_b = app(constr(OPTION, 0), bb());

        let ground = |ty: Term, lhs: Term, val: Term| {
            let goal = id_ty(ty.clone(), lhs, val.clone());
            assert!(
                crate::check(&ctx, &refl(ty, val), &crate::eval(&sig, &Vec::new(), &goal)).is_ok()
            );
        };

        ground(
            lty.clone(),
            lsnoc(bb(), cons(bfalse(), nil.clone()), btrue()),
            cons(bfalse(), cons(btrue(), nil.clone())),
        );
        ground(
            lty.clone(),
            lappend(
                bb(),
                cons(btrue(), nil.clone()),
                cons(bfalse(), nil.clone()),
            ),
            cons(btrue(), cons(bfalse(), nil.clone())),
        );
        let two = cons(btrue(), cons(bfalse(), nil.clone()));
        ground(
            opt_b.clone(),
            lnth(bb(), two.clone(), nat_lit(0)),
            some_b(btrue()),
        );
        ground(
            opt_b.clone(),
            lnth(bb(), two.clone(), nat_lit(1)),
            some_b(bfalse()),
        );
        ground(opt_b, lnth(bb(), two, nat_lit(2)), none_b);
    }

