    #[test]
    fn slot_step_transitions_are_kernel_checked() {
        let sig = numerals_sig();
        let ctx = Context::with_sig(sig.clone());
        let ground = |lhs: Term, rhs: Term| {
            let goal = id_ty(sopt_state(), lhs, rhs.clone());
            assert!(crate::check(
                &ctx,
                &refl(sopt_state(), rhs),
                &crate::eval(&sig, &Vec::new(), &goal)
            )
            .is_ok());
        };
        let nval = |k: usize| app(nat_to_n(), nat_lit(k));
        let ln = |vs: Vec<Term>| {
            vs.into_iter()
                .rev()
                .fold(lnil(nn()), |acc, v| lcons(nn(), v, acc))
        };
        let stk = |fs: Vec<Term>| {
            fs.into_iter()
                .rev()
                .fold(lnil(sframe_ty()), |acc, f| lcons(sframe_ty(), f, acc))
        };
        let nil_nat = lnil(nat_ty());
        let step2 = |prog: Term, st: Term| apps(s_step(), vec![prog, st]);

        let prog0 = lnil(func_ty());

        ground(
            step2(
                prog0.clone(),
                mk_sstate(
                    mk_sframe(
                        ln(vec![]),
                        e_let(
                            op_constr(btrue(), nat_lit(0), nil_nat.clone()),
                            e_ret(nat_lit(0)),
                        ),
                    ),
                    stk(vec![]),
                ),
            ),
            some_sstate(mk_sstate(
                mk_sframe(ln(vec![n0()]), e_ret(nat_lit(0))),
                stk(vec![]),
            )),
        );

        ground(
            step2(
                prog0.clone(),
                mk_sstate(
                    mk_sframe(
                        ln(vec![nval(3)]),
                        e_case2(btrue(), nat_lit(0), e_ret(nat_lit(5)), e_ret(nat_lit(9))),
                    ),
                    stk(vec![]),
                ),
            ),
            some_sstate(mk_sstate(
                mk_sframe(ln(vec![nval(3), nval(2)]), e_ret(nat_lit(9))),
                stk(vec![]),
            )),
        );

        ground(
            step2(
                prog0.clone(),
                mk_sstate(
                    mk_sframe(
                        ln(vec![n0()]),
                        e_case2(btrue(), nat_lit(0), e_ret(nat_lit(5)), e_ret(nat_lit(9))),
                    ),
                    stk(vec![]),
                ),
            ),
            some_sstate(mk_sstate(
                mk_sframe(ln(vec![n0()]), e_ret(nat_lit(5))),
                stk(vec![]),
            )),
        );

        let func0 = pair_of(func_ty(), nat_lit(1), e_ret(nat_lit(0)));
        let prog1 = lcons(func_ty(), func0, lnil(func_ty()));
        ground(
            step2(
                prog1,
                mk_sstate(
                    mk_sframe(
                        ln(vec![nval(7)]),
                        e_let(
                            op_call(nat_lit(0), lcons(nat_ty(), nat_lit(0), nil_nat.clone())),
                            e_ret(nat_lit(1)),
                        ),
                    ),
                    stk(vec![]),
                ),
            ),
            some_sstate(mk_sstate(
                mk_sframe(ln(vec![nval(7)]), e_ret(nat_lit(0))),
                stk(vec![mk_sframe(ln(vec![nval(7)]), e_ret(nat_lit(1)))]),
            )),
        );

        ground(
            step2(
                prog0,
                mk_sstate(
                    mk_sframe(ln(vec![nval(4)]), e_ret(nat_lit(0))),
                    stk(vec![mk_sframe(ln(vec![nval(1)]), e_ret(nat_lit(2)))]),
                ),
            ),
            some_sstate(mk_sstate(
                mk_sframe(ln(vec![nval(1), nval(4)]), e_ret(nat_lit(2))),
                stk(vec![]),
            )),
        );
    }

