    #[test]
    fn realizes_val_signature_is_kernel_checked() {
        let sig = numerals_sig();
        assert!(check_signature(&sig).is_ok());
        let ctx = Context::with_sig(sig.clone());
        fn sval_nat(k: usize) -> Term {
            if k == 0 {
                sv_constr(nat_lit(10), nat_lit(0), svnil())
            } else {
                sv_constr(nat_lit(10), nat_lit(1), svcons(sval_nat(k - 1), svnil()))
            }
        }
        fn rv_deriv(k: usize) -> Term {
            if k == 0 {
                rv_z(nat_lit(10))
            } else {
                rv_s(
                    nat_lit(10),
                    sval_nat(k - 1),
                    app(nat_to_n(), nat_lit(k - 1)),
                    rv_deriv(k - 1),
                )
            }
        }
        for k in 0..4 {
            let goal = realizes_val(sval_nat(k), app(nat_to_n(), nat_lit(k)));
            assert!(
                crate::check(&ctx, &rv_deriv(k), &crate::eval(&sig, &Vec::new(), &goal)).is_ok()
            );
        }
    }

