    #[test]
    fn recfunc_bridged_bp_identity_is_term_identical_to_original() {
        let recidx = |p: &Term| lift(1, 0, p);
        let s_succ = || lam(nat_ty(), lam(nat_ty(), nat_s(var(0))));
        let hsm_refl = || {
            lam(
                nat_ty(),
                lam(
                    nat_ty(),
                    refl(nn(), app2(n_add(), app(nat_to_n(), var(0)), npos(xh()))),
                ),
            )
        };
        let hzero_of = |p: &Term, c: &Term| lg_hzero_cr_sym(&recidx, p.clone(), c.clone());
        let hsucc_of = |_p: &Term, c: &Term| lg_hsucc_constr_sym(&sm_incr(), _p.clone(), c.clone());

        let (_, hfs_a) = rec_fuel_succ_t();
        let (p_orig, pf_orig) = recfunc_realizes_cont_gen_bridged_sym_ms(&recidx, hfs_a);
        let (_, hfs_b) = rec_fuel_succ_t();
        let (p_bp, pf_bp) = recfunc_realizes_cont_gen_bridged_sym_ms_bp(
            2,
            &id_bodyz_of,
            &id_bodys_tail_of,
            rec_fuel(),
            sm_incr(),
            &|_: &Term| n0(),
            &|_: &Term| nat_z(),
            s_succ(),
            hsm_refl(),
            &recidx,
            hfs_b,
            &hzero_of,
            &hsucc_of,
        );
        assert_eq!(
            p_orig, p_bp,
            "bridged_sym_ms_bp prop drifts from original at identity"
        );
        assert_eq!(
            pf_orig, pf_bp,
            "bridged_sym_ms_bp proof drifts from original at identity"
        );

        let (_, hfs_c) = rec_fuel_succ_t();
        let (pk_orig, pfk_orig) = recfunc_realizes_cont_gen_bridged_sym_ms_k(&recidx, hfs_c);
        let (_, hfs_d) = rec_fuel_succ_t();
        let (pk_bp, pfk_bp) = recfunc_realizes_cont_gen_bridged_sym_ms_k_bp(
            2,
            &id_bodyz_of,
            &id_bodys_tail_of,
            rec_fuel(),
            sm_incr(),
            &|_: &Term| n0(),
            &|_: &Term| nat_z(),
            s_succ(),
            hsm_refl(),
            &recidx,
            hfs_d,
            &hzero_of,
            &hsucc_of,
        );
        assert_eq!(
            pk_orig, pk_bp,
            "bridged_sym_ms_k_bp prop drifts from original at identity"
        );
        assert_eq!(
            pfk_orig, pfk_bp,
            "bridged_sym_ms_k_bp proof drifts from original at identity"
        );
    }

