    #[test]
    fn pjeval_app_rec_exists_leaf_concrete_senv_is_kernel_checked() {
        let sig = numerals_sig();
        let ctx = Context::with_sig(sig.clone());
        let major_slot = nat_lit(0);
        let (_, hfs) = rec_fuel_succ_t();
        let (_, cgb) = recfunc_realizes_cont_gen_bridged_sym(
            &|p: &Term| lift(1, 0, p),
            hfs,
            major_slot.clone(),
        );
        let s_succ = || lam(nat_ty(), lam(nat_ty(), nat_s(var(0))));
        let val = sv_constr(nat_lit(10), nat_lit(0), svnil());

        let senv = lcons(nat_ty(), nat_lit(0), lnil(nat_ty()));
        let step = et_lam(et_lam(et_app(
            et_constr(nat_lit(10), nat_lit(1)),
            et_var(nat_lit(0)),
        )));
        let e = et_app(
            et_app(
                et_app(
                    et_app(et_rec(nat_lit(10)), et_box()),
                    et_constr(nat_lit(10), nat_lit(0)),
                ),
                step,
            ),
            et_var(nat_lit(0)),
        );

        let prog = || var(6);
        let l = || var(5);
        let cc = || var(4);
        let stk = || var(3);
        let maj = || var(2);

        let result = apps(
            app(cbuild(e), lnil(thunk_ty())),
            vec![senv, llen(nn(), l()), mk_cstate(lnil(op_ty()), prog())],
        );
        let ops = fst(snd(result.clone()));
        let funcs = snd(snd(result));

        let recidx = llen(func_ty(), prog());
        let recfunc = lsym_recfunc(
            &id_bodyz_of,
            &id_bodys_tail_of,
            &|_p: &Term| llen(func_ty(), var(6)),
            &prog(),
            &l(),
        );
        let (_, lsn) = lnth_set_nth_lsnoc();
        let hmem = apps(lsn, vec![recfunc, placeholder_func(), prog()]);

        let entry_slots = lsnoc(nat_ty(), iota_fwd(llen(nn(), l())), major_slot.clone());
        let ra_es = apps(read_args(), vec![l(), entry_slots]);
        let major_val = app2(n_get(), l(), major_slot.clone());
        let mid_hc = lsnoc(nn(), l(), major_val.clone());
        let tgt_hc = lsnoc(nn(), l(), app(nat_to_n(), maj()));
        let (_, erb) = entry_renv_bridge();
        let erb_inst = apps(erb, vec![l(), major_slot.clone()]);
        let f_maj_snoc = lam(nn(), lsnoc(nn(), lift(1, 0, &l()), var(0)));
        let ap_hmaj = ap(
            nn(),
            list_ty(nn()),
            f_maj_snoc,
            major_val,
            app(nat_to_n(), maj()),
            var(1),
        );
        let h_cap = id_trans(list_ty(nn()), ra_es, mid_hc, tgt_hc, erb_inst, ap_hmaj);

        let idty_proof = apps(
            cgb,
            vec![
                recidx,
                funcs.clone(),
                l(),
                hmem,
                maj(),
                l(),
                h_cap,
                cc(),
                stk(),
            ],
        );

        let fw = nat_s(app2(rec_fuel(), nat_lit(1), maj()));
        let ww = app(nat_to_n(), apps(nrec(), vec![s_succ(), nat_z(), maj()]));

        let inner_at = |extra: usize, fuel: Term, w: Term| {
            let f = lift(extra, 0, &funcs);
            let o = lift(extra, 0, &ops);
            let lc = lift(extra, 0, &l());
            let c = lift(extra, 0, &cc());
            let s = lift(extra, 0, &stk());
            let v = lift(extra, 0, &val);
            let lhs = apps(
                s_run(),
                vec![
                    f.clone(),
                    fuel,
                    mk_sstate(mk_sframe(lc.clone(), seal_cont(o, c.clone())), s.clone()),
                ],
            );
            let rhs = apps(
                s_run(),
                vec![
                    f,
                    nat_lit(1),
                    mk_sstate(mk_sframe(lsnoc(nn(), lc, w.clone()), c), s),
                ],
            );
            let rvty = realizes_val(v, w);
            sigma(id_ty(optn(), lhs, rhs), lift(1, 0, &rvty))
        };
        let inner_anno = inner_at(0, fw.clone(), ww.clone());
        let mid_anno = sigma(nn(), inner_at(1, lift(1, 0, &fw), var(0)));
        let outer_anno = sigma(nat_ty(), sigma(nn(), inner_at(2, var(1), var(0))));

        let witness = pair_of(
            outer_anno.clone(),
            fw,
            pair_of(mid_anno, ww, pair_of(inner_anno, idty_proof, var(0))),
        );

        let h_maj_ty = id_ty(
            nn(),
            app2(n_get(), var(3), major_slot),
            app(nat_to_n(), var(0)),
        );
        let rv_ty = realizes_val(
            val.clone(),
            app(nat_to_n(), apps(nrec(), vec![s_succ(), nat_z(), var(1)])),
        );
        let tys = vec![
            list_ty(func_ty()),
            list_ty(nn()),
            expr_ty(),
            list_ty(sframe_ty()),
            nat_ty(),
            h_maj_ty,
            rv_ty,
        ];
        let inst = lams(&tys, witness);
        assert!(infer(&ctx, &inst).is_ok());
    }

