    fn sim_motive_v2_enriched() -> Term {
        let inner_motive = lam(job_ty(), pi(sval_ty(), Term::Universe(0)));
        let m_jeval = lam(
            svlist_ty(),
            lam(
                eterm_ty(),
                lam(sval_ty(), jeval_clause_v2(var(2), var(1), var(0))),
            ),
        );
        let todo = || realizes_val(sv_constr(nat_z(), nat_lit(0), svnil()), n0());
        let enrich = |a: Term| sigma(a, idty_placeholder_v1());
        let m_japp = lam(
            sval_ty(),
            lam(
                sval_ty(),
                lam(
                    sval_ty(),
                    apps(
                        rec(SVAL, 2),
                        vec![
                            lam(sval_ty(), Term::Universe(0)),
                            todo(),
                            lam(
                                svlist_ty(),
                                lam(
                                    eterm_ty(),
                                    jeval_clause_v2(svcons(var(3), var(1)), var(0), var(2)),
                                ),
                            ),
                            lam(nat_ty(), lam(nat_ty(), lam(svlist_ty(), todo()))),
                            lam(
                                nat_ty(),
                                lam(
                                    svlist_ty(),
                                    apps(
                                        rec(BOOL, 2),
                                        vec![
                                            lam(bb(), Term::Universe(0)),
                                            todo(),
                                            enrich(clause_a(var(0), var(3), var(2))),
                                            app(svl_lenis(3), var(0)),
                                        ],
                                    ),
                                ),
                            ),
                            var(2),
                        ],
                    ),
                ),
            ),
        );
        let m_jiota = lam(
            nat_ty(),
            lam(
                svlist_ty(),
                lam(
                    sval_ty(),
                    lam(sval_ty(), enrich(clause_a(var(2), var(1), var(0)))),
                ),
            ),
        );
        lam(
            job_ty(),
            lam(
                sval_ty(),
                app(
                    apps(
                        rec(JOB, 2),
                        vec![inner_motive, m_jeval, m_japp, m_jiota, var(1)],
                    ),
                    var(0),
                ),
            ),
        )
    }

