    #[test]
    fn ev_v2_arm_tys_wf_enriched_obligations_is_kernel_checked() {
        let sig = numerals_sig();
        let ctx = Context::with_sig(sig.clone());
        let enriched = ev_v2_arm_tys_wf_enriched(&ctx);
        assert_eq!(enriched.len(), 14, "enriched motive must yield 14 arms");
        let plain = ev_v2_arm_tys_wf(&ctx);
        assert_eq!(plain.len(), 14);
        let is_sigma_concl = |arm: &Term| -> bool {
            let (_tele, concl) = peel_pis(arm);
            matches!(concl, Term::Sigma(_, _))
        };
        for i in [11usize, 12, 13] {
            assert!(
                is_sigma_concl(&enriched[i]),
                "arm {} conclusion must become a Sigma (clause_a ∧ idty) under enrichment",
                i
            );
            assert!(
                !is_sigma_concl(&plain[i]),
                "arm {} conclusion must NOT be a Sigma in the plain motive",
                i
            );
        }
    }

