    fn peel_pis(t: &Term) -> (Vec<Term>, Term) {
        let mut tele: Vec<Term> = Vec::new();
        let mut cur = t.clone();
        loop {
            match cur {
                Term::Pi(d, b) => {
                    tele.push(*d);
                    cur = *b;
                }
                other => return (tele, other),
            }
        }
    }

    fn peel_n(t: &Term, n: usize) -> (Vec<Term>, Term) {
        let mut tele: Vec<Term> = Vec::new();
        let mut cur = t.clone();
        for _ in 0..n {
            match cur {
                Term::Pi(d, b) => {
                    tele.push(*d);
                    cur = *b;
                }
                _ => panic!("peel_n: fewer than {} leading Pi binders", n),
            }
        }
        (tele, cur)
    }

    fn jiota_clause_s_v2() -> (Term, Term) {
        let arm_tys = vec![
            nat_ty(),
            sval_ty(),
            sval_ty(),
            sval_ty(),
            sval_ty(),
            sval_ty(),
            sval_ty(),
            sval_ty(),
            ev_prop(
                jiota(
                    var(7),
                    svcons(var(6), svcons(var(5), svcons(var(4), svnil()))),
                    var(3),
                ),
                var(2),
            ),
            ev_prop(japp(var(5), var(4)), var(2)),
            ev_prop(japp(var(3), var(4)), var(2)),
            sim_p_v2(
                jiota(
                    var(10),
                    svcons(var(9), svcons(var(8), svcons(var(7), svnil()))),
                    var(6),
                ),
                var(5),
            ),
            sim_p_v2(japp(var(8), var(7)), var(5)),
            sim_p_v2(japp(var(6), var(7)), var(5)),
        ];
        let concl = clause_a(
            svcons(var(12), svcons(var(11), svcons(var(10), svnil()))),
            sv_constr(var(13), nat_lit(1), svcons(var(9), svnil())),
            var(6),
        );
        let prop = pis(&arm_tys, concl);
        let (_, core) = jiota_step_core();
        let inner_tys = vec![
            pi(nat_ty(), pi(nat_ty(), nat_ty())),
            nat_ty(),
            realizes_val(var(13), app(nat_to_n(), var(0))),
            reflects(var(13), var(2)),
            nn(),
            realizes_val(
                sv_constr(var(18), nat_lit(1), svcons(var(14), svnil())),
                var(0),
            ),
        ];
        let core_args = vec![
            var(19),
            var(18),
            var(17),
            var(16),
            var(15),
            var(14),
            var(13),
            var(12),
            var(5),
            var(4),
            var(3),
            var(2),
            apps(var(8), vec![var(5), var(4), var(3), var(2)]),
            var(10),
            var(9),
            var(1),
            var(0),
        ];
        let body = lams(&inner_tys, apps(core, core_args));
        let proof = lams(&arm_tys, body);
        (prop, proof)
    }

