    #[test]
    fn fire_probe_constr0_zero_h_base_meshes() {
        let sig = numerals_sig();
        let ctx = Context::with_sig(sig.clone());
        let binders = vec![
            svlist_ty(),
            nat_ty(),
            list_ty(func_ty()),
            slotenv_ty(),
            list_ty(op_ty()),
            list_ty(nn()),
            nat_ty(),
            expr_ty(),
            list_ty(sframe_ty()),
            nat_ty(),
            realizes_env(var(9), var(6), var(4)),
        ];
        let env = || var(10);
        let tag = || var(9);
        let prog = || var(8);
        let senv0 = || var(7);
        let major_ops = || var(6);
        let locals_spine = || var(5);
        let major_slot = || var(4);
        let caller_cont = || var(3);
        let stk = || var(2);
        let f_exit = || var(1);
        let h_renv = || var(0);

        let c = || run_locals(major_ops(), locals_spine());
        let slots_list = || lsnoc(nat_ty(), iota_fwd(llen(nn(), c())), major_slot());
        let callee_locals = || apps(read_args(), vec![c(), slots_list()]);
        let full_stk = || lcons(sframe_ty(), mk_sframe(c(), caller_cont()), stk());

        let cb_result = apps(
            app(cbuild(et_constr(tag(), nat_lit(0))), lnil(thunk_ty())),
            vec![
                senv0(),
                llen(nn(), callee_locals()),
                mk_cstate(lnil(op_ty()), prog()),
            ],
        );
        let base_slot = fst(cb_result.clone());
        let base_ops = fst(snd(cb_result.clone()));

        let (_, rcf) = renv_callee_frame();
        let renv_proof = apps(
            rcf,
            vec![
                env(),
                senv0(),
                major_ops(),
                locals_spine(),
                major_slot(),
                h_renv(),
            ],
        );

        let (_, c0) = p_jeval_constr0_gen_v2();
        let witness = apps(
            c0,
            vec![
                env(),
                tag(),
                prog(),
                senv0(),
                callee_locals(),
                e_ret(base_slot.clone()),
                full_stk(),
                nat_s(f_exit()),
                renv_proof,
            ],
        );
        let h_base = fst(snd(snd(witness)));

        let bz = seal_ops(base_ops.clone(), base_slot.clone());
        let el = lsnoc(nn(), callee_locals(), n0());
        let state_z = mk_sstate(mk_sframe(callee_locals(), bz), full_stk());
        let state_ret = mk_sstate(mk_sframe(el, e_ret(base_slot.clone())), full_stk());
        let lhs_fuel = app2(
            nat_add(),
            ops_fuel(base_ops.clone(), nat_s(f_exit())),
            nat_lit(0),
        );
        let lhs = apps(s_run(), vec![prog(), lhs_fuel, state_z]);
        let rhs = apps(s_run(), vec![prog(), nat_s(f_exit()), state_ret]);
        let goal_concl = id_ty(optn(), lhs, rhs);

        let goal = pis(&binders, goal_concl);
        let proof = lams(&binders, h_base);
        if let Err(e) = crate::check(&ctx, &proof, &crate::eval(&sig, &Vec::new(), &goal)) {
            let inf = infer(&ctx, &proof).map(|t| crate::quote(0, &t));
            panic!("CHECK ERR: {:?}\nINFER: {:?}", e, inf);
        }
    }

