        binders.push(h_major_ty);
        binders.push(h_rec_ty);
        binders.push(h_step_ty);

        let major_op = app2(n_get(), apps(read_args(), vec![var(13), var(12)]), var(17));
        let (_, rsi) = rv_succ_inv();
        let inv = apps(rsi, vec![nat_z(), pred_arg, major_op.clone(), var(2)]);
        let mm = fst(inv.clone());
