    #[test]
    fn p_jeval_guarded_closure_vacuous_is_kernel_checked() {
        let sig = numerals_sig();
        let ctx = Context::with_sig(sig.clone());

        let env_c = svnil();
        let clo = sv_closure(svnil(), et_box());
        let e_c = et_app(et_box(), et_box());

        let cod = lift(2, 0, &pjeval_concl(e_c.clone(), clo.clone()));
        let goal_branch = lift(5, 0, &cod);

        let triv = || realizes_val(sv_constr(nat_z(), nat_lit(0), svnil()), n0());
        let d_inner = apps(
            rec(SVAL, 2),
            vec![
                lam(sval_ty(), Term::Universe(0)),
                triv(),
                lam(svlist_ty(), lam(eterm_ty(), goal_branch)),
                lam(nat_ty(), lam(nat_ty(), lam(svlist_ty(), triv()))),
                lam(nat_ty(), lam(svlist_ty(), triv())),
                var(2),
            ],
        );
        let d_motive = lam(
            sval_ty(),
            lam(nn(), lam(realizes_val(var(1), var(0)), d_inner)),
        );
        let rm = app(rec(RV, 1), d_motive);

        let tys7 = vec![
            list_ty(func_ty()),
            slotenv_ty(),
            list_ty(nn()),
            expr_ty(),
            list_ty(sframe_ty()),
            nat_ty(),
            realizes_env(lift(6, 0, &env_c), var(4), var(3)),
        ];
        let h_ty = realizes_val(clo.clone(), var(0));
        let mut tele9 = tys7.clone();
        tele9.push(nn());
        tele9.push(h_ty.clone());

        let mut head = rm;
        for _ in 0..2 {
            let mut tail = crate::quote(
                0,
                &infer(&ctx, &lams(&tele9, head.clone()))
                    .expect("vacuous rv-discriminator (under telescope) must typecheck"),
            );
            for _ in 0..tele9.len() {
                match tail {
                    Term::Pi(_, body) => tail = (*body).clone(),
                    _ => panic!("expected the 9-binder telescope prefix"),
                }
            }
            let arm = match tail {
                Term::Pi(dom, _) => (*dom).clone(),
                _ => panic!("expected an arm binder on rec(RV,1)"),
            };
            let mut binders: Vec<Term> = Vec::new();
            let mut t = arm;
            while let Term::Pi(dom, body) = t {
                binders.push((*dom).clone());
                t = (*body).clone();
            }
            head = app(head, lams(&binders, rv_z(nat_z())));
        }
        let exfalso = apps(head, vec![clo.clone(), var(1), var(0)]);

        let proof = lams(&tys7, lam(nn(), lam(h_ty, exfalso)));
        let goal = p_jeval_guarded(env_c, e_c, clo);
        assert!(crate::check(&ctx, &proof, &crate::eval(&sig, &Vec::new(), &goal)).is_ok());
    }

    #[test]
    fn dv_app_honest_leaf_reductions_is_kernel_checked() {
        let sig = numerals_sig();
        let ctx = Context::with_sig(sig.clone());
        let audit = |ctx_tys: Vec<Term>, f: Term, env: Term, x: Term, v: Term| {
            let e = et_app(f, x);
            let sim = sim_p(jeval(env.clone(), e.clone()), v.clone());
            let honest = p_jeval_guarded(env, e, v);
            let coerce = lams(&ctx_tys, lam(honest.clone(), var(0)));
            let coerce_ty = pis(&ctx_tys, pi(honest, lift(1, 0, &sim)));
            assert!(
                crate::check(&ctx, &coerce, &crate::eval(&sig, &Vec::new(), &coerce_ty)).is_ok()
            );
        };
        audit(
            vec![svlist_ty(), eterm_ty(), sval_ty()],
            et_box(),
            var(2),
            var(1),
            var(0),
        );
        audit(
            vec![nat_ty(), svlist_ty(), eterm_ty(), sval_ty()],
            et_var(var(3)),
            var(2),
            var(1),
            var(0),
        );
        audit(
            vec![eterm_ty(), svlist_ty(), eterm_ty(), sval_ty()],
            et_lam(var(3)),
            var(2),
            var(1),
            var(0),
        );
        audit(
            vec![nat_ty(), nat_ty(), svlist_ty(), eterm_ty(), sval_ty()],
            et_constr(var(4), var(3)),
            var(2),
            var(1),
            var(0),
        );
    }

    fn ev_japp_box_absurd_pf(ctx: &Context) -> (Term, Term) {
        let triv = || realizes_val(sv_constr(nat_z(), nat_lit(0), svnil()), n0());
        let goal_inner = pi(
            svlist_ty(),
            pi(
                eterm_ty(),
                p_jeval(var(1), et_app(et_box(), var(0)), var(5)),
            ),
        );
        let inner = apps(
            rec(SVAL, 2),
            vec![
                lam(sval_ty(), Term::Universe(0)),
                goal_inner,
                lam(svlist_ty(), lam(eterm_ty(), triv())),
                lam(nat_ty(), lam(nat_ty(), lam(svlist_ty(), triv()))),
                lam(nat_ty(), lam(svlist_ty(), triv())),
                var(1),
            ],
        );
        let m_japp = lam(sval_ty(), lam(sval_ty(), inner));
        let m_jeval = lam(svlist_ty(), lam(eterm_ty(), triv()));
        let m_jiota = lam(nat_ty(), lam(svlist_ty(), lam(sval_ty(), triv())));
        let d_body = apps(
            rec(JOB, 2),
            vec![
                lam(job_ty(), Term::Universe(0)),
                m_jeval,
                m_japp,
                m_jiota,
                var(2),
            ],
        );
        let d_motive = lam(
            job_ty(),
            lam(sval_ty(), lam(ev_prop(var(1), var(0)), d_body)),
        );
        let rm = app(rec(EV, 1), d_motive);
        let ty = crate::quote(
            0,
            &infer(ctx, &rm).expect("ev_japp_box_absurd motive must typecheck"),
        );
        let mut arm_tys: Vec<Term> = Vec::new();
        let mut tail = ty;
        for _ in 0..14 {
            match tail {
                Term::Pi(dom, body) => {
                    arm_tys.push((*dom).clone());
                    tail = (*body).clone();
                }
                _ => panic!("expected 14 arm binders on rec(EV,1)"),
            }
        }
        let mut methods: Vec<Term> = Vec::new();
        for arm in &arm_tys {
            let mut binders: Vec<Term> = Vec::new();
            let mut t = arm.clone();
            while let Term::Pi(dom, body) = t {
                binders.push((*dom).clone());
                t = (*body).clone();
            }
            methods.push(lams(&binders, rv_z(nat_z())));
        }
        let mut core_args = methods;
        core_args.push(japp(sv_box(), var(2)));
        core_args.push(var(1));
        core_args.push(var(0));
        let core_outer = vec![
            sval_ty(),
            sval_ty(),
            ev_prop(japp(sv_box(), var(1)), var(0)),
        ];
        let core_proof = lams(&core_outer, apps(rm, core_args));
        let wrap_outer = vec![
            svlist_ty(),
            eterm_ty(),
            sval_ty(),
            sval_ty(),
            ev_prop(japp(sv_box(), var(1)), var(0)),
        ];
        let wrap_proof = lams(
            &wrap_outer,
            apps(core_proof, vec![var(2), var(1), var(0), var(4), var(3)]),
        );
        let wrap_goal = pis(
            &wrap_outer,
            p_jeval(var(4), et_app(et_box(), var(3)), var(1)),
        );
        (wrap_goal, wrap_proof)
    }

