    fn dv_app_constr1_method_pf(ctx: &Context) -> (Term, Term) {
        let (_, var_inv) = ev_jeval_var_inv_pf(ctx);
        let (_, veq) = constr1_v_eq_pf(ctx);
        let (_, xbox) = dv_app_constr1_xbox_head_pf(ctx);
        let (_, xvar) = dv_app_constr1_xvar_head_pf(ctx);
        let (_, xlam) = dv_app_constr1_xlam_head_pf(ctx);
        let (_, xapp) = dv_app_constr1_xapp_head_pf();
        let (_, xrec) = dv_app_constr1_xrec_head_pf(ctx);
        let (_, xconstr) = constr1_xconstr_arm_pf(ctx);
        let j1 = || nat_s(nat_z());

        let outer = vec![
            svlist_ty(),
            nat_ty(),
            eterm_ty(),
            sval_ty(),
            sval_ty(),
            sval_ty(),
            ev_prop(jeval(var(5), et_constr(var(4), j1())), var(2)),
            ev_prop(jeval(var(6), var(4)), var(2)),
            ev_prop(japp(var(4), var(3)), var(2)),
            sim_p_v2(jeval(var(8), var(6)), var(4)),
        ];

        let m = lam(
            eterm_ty(),
            pi(
                ev_prop(jeval(var(10), var(0)), var(6)),
                pi(
                    sim_p_v2(jeval(var(11), var(1)), var(7)),
                    p_jeval_guarded_v2(var(12), et_app(et_constr(var(11), j1()), var(2)), var(7)),
                ),
            ),
        );

        let arm_box = lam(
            ev_prop(jeval(var(9), et_box()), var(5)),
            lam(
                sim_p_v2(jeval(var(10), et_box()), var(6)),
                apps(
                    xbox,
                    vec![
                        var(11),
                        var(10),
                        var(8),
                        var(7),
                        var(6),
                        var(5),
                        var(1),
                        var(3),
                    ],
                ),
            ),
        );

        let p_var = lam(
            sval_ty(),
            p_jeval_guarded_v2(
                var(13),
                et_app(et_constr(var(12), j1()), et_var(var(3))),
                var(0),
            ),
        );
        let vx_eq_v = apps(var_inv, vec![var(12), var(2), var(8), var(1)]);
        let v_eq_v = apps(
            veq.clone(),
            vec![var(12), var(11), var(9), var(8), var(7), var(6), var(4)],
        );
        let xvar_res = apps(xvar, vec![var(12), var(11), var(2)]);
        let x_from_v = sv_constr(var(11), j1(), svcons(lookup_sval(var(12), var(2)), svnil()));
        let x_mid_v = sv_constr(var(11), j1(), svcons(var(8), svnil()));
        let f_v = lam(sval_ty(), sv_constr(var(12), j1(), svcons(var(0), svnil())));
        let ap_v = ap(
            sval_ty(),
            sval_ty(),
            f_v,
            lookup_sval(var(12), var(2)),
            var(8),
            id_sym(sval_ty(), var(8), lookup_sval(var(12), var(2)), vx_eq_v),
        );
        let h_v = id_trans(
            sval_ty(),
            x_from_v.clone(),
            x_mid_v.clone(),
            var(7),
            ap_v,
            id_sym(sval_ty(), var(7), x_mid_v, v_eq_v),
        );
        let body_var = transport(sval_ty(), p_var, x_from_v, var(7), h_v, xvar_res);
        let arm_var = lam(
            nat_ty(),
            lam(
                ev_prop(jeval(var(10), et_var(var(0))), var(6)),
                lam(sim_p_v2(jeval(var(11), et_var(var(1))), var(7)), body_var),
            ),
        );

        let arm_lam = lam(
            eterm_ty(),
            lam(
                app(lift(1, 0, &m), var(0)),
                lam(
                    ev_prop(jeval(var(11), et_lam(var(1))), var(7)),
                    lam(
                        sim_p_v2(jeval(var(12), et_lam(var(2))), var(8)),
                        apps(
                            xlam,
                            vec![
                                var(13),
                                var(12),
                                var(3),
                                var(10),
                                var(9),
                                var(8),
                                var(7),
                                var(1),
                                var(5),
                            ],
                        ),
                    ),
                ),
            ),
        );

        let p_app = lam(
            sval_ty(),
            p_jeval_guarded_v2(
                var(16),
                et_app(et_constr(var(15), j1()), et_app(var(6), var(5))),
                var(0),
            ),
        );
        let v_eq_a = apps(
            veq.clone(),
            vec![var(15), var(14), var(12), var(11), var(10), var(9), var(7)],
        );
        let xapp_res = apps(
            xapp,
            vec![var(15), var(14), var(5), var(4), var(11), var(0)],
        );
        let x_from_a = sv_constr(var(14), j1(), svcons(var(11), svnil()));
        let body_app = transport(
            sval_ty(),
            p_app,
            x_from_a.clone(),
            var(10),
            id_sym(sval_ty(), var(10), x_from_a, v_eq_a),
            xapp_res,
        );
        let arm_app = lam(
            eterm_ty(),
            lam(
                eterm_ty(),
                lam(
                    app(lift(2, 0, &m), var(1)),
                    lam(
                        app(lift(3, 0, &m), var(1)),
                        lam(
                            ev_prop(jeval(var(13), et_app(var(3), var(2))), var(9)),
                            lam(
                                sim_p_v2(jeval(var(14), et_app(var(4), var(3))), var(10)),
                                body_app,
                            ),
                        ),
                    ),
                ),
            ),
        );

        let arm_constr = lam(
            nat_ty(),
            lam(
                nat_ty(),
                lam(
                    ev_prop(jeval(var(11), et_constr(var(1), var(0))), var(7)),
                    lam(
                        sim_p_v2(jeval(var(12), et_constr(var(2), var(1))), var(8)),
                        apps(
                            xconstr,
                            vec![
                                var(13),
                                var(12),
                                var(3),
                                var(2),
                                var(10),
                                var(9),
                                var(8),
                                var(7),
                                var(1),
                                var(5),
                            ],
                        ),
                    ),
                ),
            ),
        );

        let arm_rec = lam(
            nat_ty(),
            lam(
                ev_prop(jeval(var(10), et_rec(var(0))), var(6)),
                lam(
                    sim_p_v2(jeval(var(11), et_rec(var(1))), var(7)),
                    apps(
                        xrec,
                        vec![
                            var(12),
                            var(11),
                            var(2),
                            var(9),
                            var(8),
                            var(7),
                            var(6),
                            var(1),
                            var(4),
                        ],
                    ),
                ),
            ),
        );

        let dispatch = apps(
            rec(ETERM, 1),
            vec![
                m,
                arm_box,
                arm_var,
                arm_lam,
                arm_app,
                arm_constr,
                arm_rec,
                var(7),
            ],
        );
        let body = apps(dispatch, vec![var(2), var(0)]);
        let proof = lams(&outer, body);
        let goal = pis(
            &outer,
            p_jeval_guarded_v2(var(9), et_app(et_constr(var(8), j1()), var(7)), var(4)),
        );
        (goal, proof)
    }

