    fn dv_app_constr_head_pf(ctx: &Context) -> (Term, Term) {
        let (_, c0head) = dv_app_constr0_head_pf(ctx);
        let (_, m1) = dv_app_constr1_method_pf(ctx);
        let (_, sshead) = dv_app_constr_ss_head_pf(ctx);

        let outer = vec![
            svlist_ty(),
            nat_ty(),
            nat_ty(),
            eterm_ty(),
            sval_ty(),
            sval_ty(),
            sval_ty(),
            ev_prop(jeval(var(6), et_constr(var(5), var(4))), var(2)),
            ev_prop(jeval(var(7), var(4)), var(2)),
            ev_prop(japp(var(4), var(3)), var(2)),
            sim_p_v2(jeval(var(9), var(6)), var(4)),
        ];

        let m_j = lam(
            nat_ty(),
            pi(
                ev_prop(jeval(var(11), et_constr(var(10), var(0))), var(7)),
                p_jeval_guarded_v2(var(12), et_app(et_constr(var(11), var(1)), var(9)), var(6)),
            ),
        );

        let arm_j0 = lam(
            ev_prop(jeval(var(10), et_constr(var(9), nat_z())), var(6)),
            apps(
                c0head,
                vec![
                    var(11),
                    var(10),
                    var(8),
                    var(7),
                    var(6),
                    var(5),
                    var(0),
                    var(2),
                ],
            ),
        );

        let m_jss = lam(
            nat_ty(),
            pi(
                ev_prop(jeval(var(13), et_constr(var(12), nat_s(var(0)))), var(9)),
                p_jeval_guarded_v2(
                    var(14),
                    et_app(et_constr(var(13), nat_s(var(1))), var(11)),
                    var(8),
                ),
            ),
        );

        let arm_j1 = lam(
            ev_prop(jeval(var(12), et_constr(var(11), nat_s(nat_z()))), var(8)),
            apps(
                m1,
                vec![
                    var(13),
                    var(12),
                    var(10),
                    var(9),
                    var(8),
                    var(7),
                    var(0),
                    var(5),
                    var(4),
                    var(3),
                ],
            ),
        );

        let arm_jge2 = lam(
            nat_ty(),
            lam(
                app(lift(1, 0, &m_jss), var(0)),
                lam(
                    ev_prop(
                        jeval(var(14), et_constr(var(13), nat_s(nat_s(var(1))))),
                        var(10),
                    ),
                    apps(
                        sshead,
                        vec![
                            var(15),
                            var(14),
                            var(2),
                            var(12),
                            var(11),
                            var(10),
                            var(9),
                            var(0),
                            var(6),
                        ],
                    ),
                ),
            ),
        );

        let sub_rec = apps(rec(NAT, 1), vec![m_jss, arm_j1, arm_jge2, var(1)]);
        let arm_jss = lam(nat_ty(), lam(app(lift(1, 0, &m_j), var(0)), sub_rec));

        let result = apps(rec(NAT, 1), vec![m_j, arm_j0, arm_jss, var(8)]);
        let body = app(result, var(3));
        let proof = lams(&outer, body);
        let goal = pis(
            &outer,
            p_jeval_guarded_v2(var(10), et_app(et_constr(var(9), var(8)), var(7)), var(4)),
        );
        (goal, proof)
    }

