    fn dv_app_gconstr_head_pf(ctx: &Context) -> (Term, Term) {
        let (_, cps) = ev_jeval_app_cps_pf(ctx);
        let (_, constr_inv) = ev_jeval_constr_inv_pf(ctx);
        let (_, apconstr_inv) = ev_japp_apconstr_inv_pf(ctx);
        let (_, rv2f) = rv_2field_false_pf(ctx);
        let (_, zs) = nat_zs_absurd_set();
        let fls = || id_ty(nat_ty(), nat_z(), nat_s(nat_z()));

        let method_outer = vec![
            svlist_ty(),
            nat_ty(),
            nat_ty(),
            eterm_ty(),
            eterm_ty(),
            sval_ty(),
            sval_ty(),
            sval_ty(),
            ev_prop(
                jeval(var(7), et_app(et_constr(var(6), var(5)), var(4))),
                var(2),
            ),
            ev_prop(jeval(var(8), var(4)), var(2)),
            ev_prop(japp(var(4), var(3)), var(2)),
            id_ty(bb(), head_callable(et_constr(var(9), var(8))), btrue()),
        ];
        let t_concl = p_jeval_guarded_v2(
            var(11),
            et_app(et_app(et_constr(var(10), var(9)), var(8)), var(7)),
            var(4),
        );
        let (tele9, c_ty) = peel_n(&t_concl, 9);

        let dom_g = ev_prop(jeval(var(22), et_constr(var(21), var(20))), var(1));
        let dom_y = ev_prop(jeval(var(23), var(20)), var(1));
        let dom_japp = ev_prop(japp(var(3), var(2)), var(19));

        let vg_eq = apps(constr_inv, vec![var(25), var(24), var(23), var(4), var(2)]);
        let motive_g = lam(sval_ty(), ev_prop(japp(var(0), var(4)), var(21)));
        let p_japp1 = transport(
            sval_ty(),
            motive_g,
            var(4),
            sv_constr(var(24), var(23), svnil()),
            vg_eq,
            var(0),
        );
        let vf_eq = apps(
            apconstr_inv.clone(),
            vec![var(24), var(23), svnil(), var(3), var(20), p_japp1],
        );
        let motive_f = lam(sval_ty(), ev_prop(japp(var(0), var(20)), var(19)));
        let p_japp2 = transport(
            sval_ty(),
            motive_f,
            var(20),
            sv_constr(var(24), var(23), snoc_sval(svnil(), var(3))),
            vf_eq,
            var(15),
        );
        let v_eq = apps(
            apconstr_inv,
            vec![
                var(24),
                var(23),
                snoc_sval(svnil(), var(3)),
                var(19),
                var(18),
                p_japp2,
            ],
        );
        let motive_v = lam(sval_ty(), realizes_val(var(0), var(7)));
        let rv2 = transport(
            sval_ty(),
            motive_v,
            var(18),
            sv_constr(
                var(24),
                var(23),
                snoc_sval(snoc_sval(svnil(), var(3)), var(19)),
            ),
            v_eq,
            var(5),
        );
        let false_eq = apps(rv2f, vec![var(24), var(23), var(3), var(19), var(6), rv2]);

        let continuation = lams(&[sval_ty(), sval_ty(), dom_g, dom_y, dom_japp], false_eq);
        let cps_applied = apps(
            cps,
            vec![
                var(20),
                et_constr(var(19), var(18)),
                var(17),
                var(15),
                var(12),
            ],
        );
        let cps_result = apps(cps_applied, vec![fls(), continuation]);
        let body = apps(zs, vec![c_ty, nat_z(), cps_result]);
        let proof = lams(&method_outer, lams(&tele9, body));
        let goal = pis(&method_outer, t_concl);
        (goal, proof)
    }

