    fn dv_app_grec_head_pf(ctx: &Context) -> (Term, Term) {
        let (_, cps) = ev_jeval_app_cps_pf(ctx);
        let (_, rec_inv) = ev_jeval_rec_inv_pf(ctx);
        let (_, aprec0_inv) = ev_japp_aprec0_inv_pf(ctx);
        let (_, aprec1_inv) = ev_japp_aprec1_inv_pf(ctx);
        let (_, rvf) = rv_recapp_false_pf(ctx);
        let (_, zs) = nat_zs_absurd_set();
        let fls = || id_ty(nat_ty(), nat_z(), nat_s(nat_z()));

        let method_outer = vec![
            svlist_ty(),
            nat_ty(),
            eterm_ty(),
            eterm_ty(),
            sval_ty(),
            sval_ty(),
            sval_ty(),
            ev_prop(jeval(var(6), et_app(et_rec(var(5)), var(4))), var(2)),
            ev_prop(jeval(var(7), var(4)), var(2)),
            ev_prop(japp(var(4), var(3)), var(2)),
            id_ty(bb(), head_callable(et_rec(var(8))), btrue()),
        ];
        let t_concl = p_jeval_guarded_v2(
            var(10),
            et_app(et_app(et_rec(var(9)), var(8)), var(7)),
            var(4),
        );
        let (tele9, c_ty) = peel_n(&t_concl, 9);

        let dom_g = ev_prop(jeval(var(21), et_rec(var(20))), var(1));
        let dom_y = ev_prop(jeval(var(22), var(20)), var(1));
        let dom_japp = ev_prop(japp(var(3), var(2)), var(19));

        let vg_eq = apps(rec_inv, vec![var(24), var(23), var(4), var(2)]);
        let motive_g = lam(sval_ty(), ev_prop(japp(var(0), var(4)), var(21)));
        let p_japp1 = transport(
            sval_ty(),
            motive_g,
            var(4),
            sv_recapp(var(23), svnil()),
            vg_eq,
            var(0),
        );
        let vf_eq = apps(aprec0_inv, vec![var(23), var(3), var(20), p_japp1]);
        let motive_f = lam(sval_ty(), ev_prop(japp(var(0), var(20)), var(19)));
        let p_japp2 = transport(
            sval_ty(),
            motive_f,
            var(20),
            sv_recapp(var(23), snoc_sval(svnil(), var(3))),
            vf_eq,
            var(15),
        );
        let v_eq = apps(aprec1_inv, vec![var(23), var(3), var(19), var(18), p_japp2]);
        let motive_v = lam(sval_ty(), realizes_val(var(0), var(7)));
        let spine_v = snoc_sval(svcons(var(3), svnil()), var(19));
        let rv2 = transport(
            sval_ty(),
            motive_v,
            var(18),
            sv_recapp(var(23), spine_v.clone()),
            v_eq,
            var(5),
        );
        let false_eq = apps(rvf, vec![var(23), spine_v, var(6), rv2]);

        let continuation = lams(&[sval_ty(), sval_ty(), dom_g, dom_y, dom_japp], false_eq);
        let cps_applied = apps(
            cps,
            vec![var(19), et_rec(var(18)), var(17), var(15), var(12)],
        );
        let cps_result = apps(cps_applied, vec![fls(), continuation]);
        let body = apps(zs, vec![c_ty, nat_z(), cps_result]);
        let proof = lams(&method_outer, lams(&tele9, body));
        let goal = pis(&method_outer, t_concl);
        (goal, proof)
    }

