    fn dvapp_spine_app_arm_p_pf() -> (Term, Term) {
        let goal = pi(
            svlist_ty(),
            pi(
                eterm_ty(),
                pi(
                    eterm_ty(),
                    pi(
                        dvapp_m_args_p(&var(2), &var(1)),
                        pi(
                            dvapp_m_args_p(&var(3), &var(1)),
                            dvapp_m_args_p(&var(4), &et_app(var(3), var(2))),
                        ),
                    ),
                ),
            ),
        );
        let (binders, _concl) = peel_n(&goal, 10);
        let xl = lcons(eterm_ty(), var(7), var(4));
        let sigma_ty = sigma(
            dvapp_simjob(&var(9), &var(7)),
            lift(1, 0, &dvapp_allsim(&var(9), &var(4))),
        );
        let simjob_x = apps(var(5), vec![lnil(eterm_ty()), nat_z()]);
        let hl_new = pair_of(sigma_ty, simjob_x, var(3));
        let body = apps(var(6), vec![xl, hl_new, var(2), var(1), var(0)]);
        let proof = lams(&binders, body);
        (goal, proof)
    }

