    fn wf_app_spine_false_pf() -> (Term, Term) {
        let r_body = pi(
            eterm_ty(),
            pi(
                eterm_ty(),
                pi(
                    id_ty(bb(), head_callable(var(1)), bfalse()),
                    id_ty(
                        bb(),
                        wf_eterm(apps_eterm(var(2), lcons(eterm_ty(), var(1), var(3)))),
                        bfalse(),
                    ),
                ),
            ),
        );
        let h_binder = id_ty(bb(), head_callable(var(1)), bfalse());
        let motive = lam(list_ty(eterm_ty()), r_body.clone());

        let nil_arm = {
            let rprime = and_b(wf_eterm(var(2)), wf_eterm(var(1)));
            let hc = head_callable(var(2));
            let h_prime = id_sym(bb(), hc.clone(), bfalse(), var(0));
            let motive = lam(
                bb(),
                lam(
                    id_ty(bb(), bfalse(), var(0)),
                    id_ty(bb(), and_b(var(1), lift(2, 0, &rprime)), bfalse()),
                ),
            );
            let body = apps(
                rec(ID, 0),
                vec![bb(), bfalse(), motive, refl(bb(), bfalse()), hc, h_prime],
            );
            lams(&[eterm_ty(), eterm_ty(), h_binder.clone()], body)
        };

        let cons_arm = {
            let body = apps(var(3), vec![et_app(var(2), var(1)), var(5), var(0)]);
            let inner = lams(&[eterm_ty(), eterm_ty(), h_binder.clone()], body);
            lams(&[eterm_ty(), list_ty(eterm_ty()), r_body.clone()], inner)
        };

        let rec_term = apps(
            rec(LIST, 0),
            vec![eterm_ty(), motive, nil_arm, cons_arm, var(3)],
        );
        let inner_body = apps(rec_term, vec![var(2), var(1), var(0)]);
        let proof = lams(
            &[
                list_ty(eterm_ty()),
                eterm_ty(),
                eterm_ty(),
                h_binder.clone(),
            ],
            inner_body,
        );
        let goal = pi(list_ty(eterm_ty()), r_body);
        (goal, proof)
    }

