    fn dvapp_constr_cons_fire_nil_p_pf(ctx: &Context) -> (Term, Term) {
        let (_, pkg_inv) = ev_jeval_app_pkg_pf(ctx);
        let (_, constr_head) = dv_app_constr_head_pf(ctx);

        let nt = dvapp_n_tail_p(
            &var(3),
            &et_constr(var(2), var(1)),
            &lcons(eterm_ty(), var(0), lnil(eterm_ty())),
        );
        let (nt_binders, _) = peel_n(&nt, 4);

        let pkg = apps(
            pkg_inv,
            vec![var(7), et_constr(var(6), var(5)), var(4), var(2), var(1)],
        );
        let vf = fst(pkg.clone());
        let vx = fst(snd(pkg.clone()));
        let ev_f = fst(snd(snd(pkg.clone())));
        let ev_x = fst(snd(snd(snd(pkg.clone()))));
        let ev_app = snd(snd(snd(snd(pkg))));
        let sim_x = apps(fst(var(3)), vec![vx.clone(), ev_x.clone(), var(0)]);
        let body = apps(
            constr_head,
            vec![
                var(7),
                var(6),
                var(5),
                var(4),
                vf,
                vx,
                var(2),
                ev_f,
                ev_x,
                ev_app,
                sim_x,
            ],
        );

        let proof = lams(
            &[svlist_ty(), nat_ty(), nat_ty(), eterm_ty()],
            lams(&nt_binders, body),
        );
        let goal = pis(&[svlist_ty(), nat_ty(), nat_ty(), eterm_ty()], nt);
        (goal, proof)
    }

