    fn ev_v2_capstone_wf_modulo_fire_pf(ctx: &Context) -> (Term, Term) {
        let arm_tys = ev_v2_arm_tys_wf(ctx);
        let triv = |i: usize| {
            let (tele, _) = peel_pis(&arm_tys[i]);
            lams(&tele, rv_z(nat_z()))
        };
        let (_, aeb_l) = and_b_elim_l();

        let plain_var = ev_v2_arm_var_plain_proof(ctx);
        let (tele1, _) = peel_n(&arm_tys[1], 3);
        let arm1 = lams(&tele1, apps(plain_var, vec![var(2), var(1)]));

        let plain3 = ev_v2_arm_constr_plain_proof();
        let (tele3, _) = peel_n(&arm_tys[3], 4);
        let arm3 = lams(&tele3, apps(plain3, vec![var(3), var(2), var(1)]));

        let (_, dvapp) = dv_app_arm5_wf_modulo_fire_pf(ctx);

        let (tele6, _) = peel_n(&arm_tys[6], 7);
        let disch6 = apps(
            aeb_l.clone(),
            vec![wf_eterm(var(5)), wf_val(var(4)), var(0)],
        );
        let arm6 = lams(&tele6, app(var(1), disch6));

        let (tele11, _) = peel_n(&arm_tys[11], 9);
        let spine11 = svcons(var(7), svcons(var(6), svcons(var(5), svnil())));
        let guard11 = apps(
            aeb_l.clone(),
            vec![wf_svlist(spine11), wf_val(var(4)), var(0)],
        );
        let arm11 = lams(&tele11, app(var(1), guard11));

        let (_, plain12) = jiota_clause_z_n();
        let (tele12, _) = peel_n(&arm_tys[12], 5);
        let arm12 = lams(&tele12, apps(plain12, vec![var(4), var(3), var(2), var(1)]));

        let arm13 = ev_v2_arm_iotas_wf_proof(ctx);

        let arms = vec![
            sim_motive_wf(),
            triv(0),
            arm1,
            triv(2),
            arm3,
            triv(4),
            app(dvapp, var(0)),
            arm6,
            triv(7),
            triv(8),
            triv(9),
            triv(10),
            arm11,
            arm12,
            arm13,
        ];
        let capstone = lam(dvapp_fire_ty(), apps(rec(EV, 1), arms));
        let result_ty = pi(
            job_ty(),
            pi(
                sval_ty(),
                pi(
                    ev_prop(var(1), var(0)),
                    pi(
                        id_ty(bb(), wf_job(var(2)), btrue()),
                        sim_p_v2(var(3), var(2)),
                    ),
                ),
            ),
        );
        let goal = pi(dvapp_fire_ty(), result_ty);
        (goal, capstone)
    }

