    fn constr1_idproof_bridge_pf() -> (Term, Term) {
        let (_, ofs) = ops_fuel_snoc();
        let (_, scs) = seal_cont_snoc();
        let (_, src) = srun_constr();
        let opf =
            |xslot: Term| op_constr(btrue(), nat_lit(1), lcons(nat_ty(), xslot, lnil(nat_ty())));

        let op_bt = opf(var(2));
        let ih_lhs_bt = apps(
            s_run(),
            vec![
                var(8),
                app2(nat_add(), ops_fuel(var(3), nat_s(var(7))), var(0)),
                mk_sstate(
                    mk_sframe(var(6), seal_cont(var(3), e_let(op_bt.clone(), var(5)))),
                    var(4),
                ),
            ],
        );
        let ih_rhs_bt = apps(
            s_run(),
            vec![
                var(8),
                nat_s(var(7)),
                mk_sstate(mk_sframe(var(1), e_let(op_bt, var(5))), var(4)),
            ],
        );
        let outer = vec![
            list_ty(func_ty()),
            nat_ty(),
            list_ty(nn()),
            expr_ty(),
            list_ty(sframe_ty()),
            list_ty(op_ty()),
            nat_ty(),
            list_ty(nn()),
            nat_ty(),
            id_ty(optn(), ih_lhs_bt, ih_rhs_bt),
        ];

        let op_b = opf(var(3));
        let ops_e = lsnoc(op_ty(), var(4), op_b.clone());
        let enc = apps(
            s_encode(),
            vec![
                btrue(),
                nat_lit(1),
                lcons(nat_ty(), var(3), lnil(nat_ty())),
                var(2),
            ],
        );
        let lhs_e = apps(
            s_run(),
            vec![
                var(9),
                app2(nat_add(), ops_fuel(ops_e.clone(), var(8)), var(1)),
                mk_sstate(mk_sframe(var(7), seal_cont(ops_e.clone(), var(6))), var(5)),
            ],
        );
        let mid1 = apps(
            s_run(),
            vec![
                var(9),
                app2(nat_add(), ops_fuel(var(4), nat_s(var(8))), var(1)),
                mk_sstate(mk_sframe(var(7), seal_cont(ops_e.clone(), var(6))), var(5)),
            ],
        );
        let ih_lhs_b = apps(
            s_run(),
            vec![
                var(9),
                app2(nat_add(), ops_fuel(var(4), nat_s(var(8))), var(1)),
                mk_sstate(
                    mk_sframe(var(7), seal_cont(var(4), e_let(op_b.clone(), var(6)))),
                    var(5),
                ),
            ],
        );
        let ih_rhs_b = apps(
            s_run(),
            vec![
                var(9),
                nat_s(var(8)),
                mk_sstate(mk_sframe(var(2), e_let(op_b.clone(), var(6))), var(5)),
            ],
        );
        let final_rhs = apps(
            s_run(),
            vec![
                var(9),
                var(8),
                mk_sstate(mk_sframe(lsnoc(nn(), var(2), enc), var(6)), var(5)),
            ],
        );

        let ofs_inst = apps(ofs, vec![var(8), op_b.clone(), var(4)]);
        let f_fuel = lam(
            nat_ty(),
            apps(
                s_run(),
                vec![
                    var(10),
                    app2(nat_add(), var(0), var(2)),
                    mk_sstate(
                        mk_sframe(
                            var(8),
                            seal_cont(lsnoc(op_ty(), var(5), opf(var(4))), var(7)),
                        ),
                        var(6),
                    ),
                ],
            ),
        );
        let ap_fuel = ap(
            nat_ty(),
            optn(),
            f_fuel,
            ops_fuel(ops_e.clone(), var(8)),
            ops_fuel(var(4), nat_s(var(8))),
            ofs_inst,
        );

        let scs_inst = apps(scs, vec![var(6), op_b.clone(), var(4)]);
        let g_cont = lam(
            expr_ty(),
            apps(
                s_run(),
                vec![
                    var(10),
                    app2(nat_add(), ops_fuel(var(5), nat_s(var(9))), var(2)),
                    mk_sstate(mk_sframe(var(8), var(0)), var(6)),
                ],
            ),
        );
        let ap_cont = ap(
            expr_ty(),
            optn(),
            g_cont,
            seal_cont(ops_e, var(6)),
            seal_cont(var(4), e_let(op_b.clone(), var(6))),
            scs_inst,
        );

        let a_rewrite = id_trans(
            optn(),
            lhs_e.clone(),
            mid1,
            ih_lhs_b.clone(),
            ap_fuel,
            ap_cont,
        );
        let a_proof = id_trans(
            optn(),
            lhs_e.clone(),
            ih_lhs_b,
            ih_rhs_b.clone(),
            a_rewrite,
            var(0),
        );
        let src_inst = apps(
            src,
            vec![
                var(9),
                var(8),
                var(2),
                btrue(),
                nat_lit(1),
                lcons(nat_ty(), var(3), lnil(nat_ty())),
                var(6),
                var(5),
            ],
        );
        let idproof = id_trans(
            optn(),
            lhs_e.clone(),
            ih_rhs_b,
            final_rhs.clone(),
            a_proof,
            src_inst,
        );
        let proof = lams(&outer, idproof);
        let goal = pis(&outer, id_ty(optn(), lhs_e, final_rhs));
        (goal, proof)
    }

