    fn constr1_xconstr0_realizer_pf() -> (Term, Term) {
        let (_, crs) = constr_realizes_s();
        let (_, ngs) = n_get_snoc();
        let (_, lls) = llen_snoc();

        let vx = || sv_constr(var(1), nat_lit(0), svnil());
        let v = || sv_constr(var(2), nat_lit(1), svcons(vx(), svnil()));
        let localsp = || lsnoc(nn(), var(0), n0());
        let sl = || llen(nn(), var(0));
        let enc1 = || {
            apps(
                s_encode(),
                vec![
                    btrue(),
                    nat_lit(1),
                    lcons(nat_ty(), sl(), lnil(nat_ty())),
                    localsp(),
                ],
            )
        };
        let exit_l = || lsnoc(nn(), localsp(), enc1());
        let slot_e = || nat_s(sl());
        let nget_x = || app2(n_get(), localsp(), sl());

        let rvz = rv_z(var(1));
        let ngs1 = apps(ngs.clone(), vec![n0(), var(0)]);
        let fam_x = lam(nn(), realizes_val(lift(1, 0, &vx()), var(0)));
        let rv_x = transport(
            nn(),
            fam_x,
            n0(),
            nget_x(),
            id_sym(nn(), nget_x(), n0(), ngs1),
            rvz,
        );
        let crs_inst = apps(crs, vec![var(2), sl(), localsp(), vx(), rv_x]);

        let ngs2 = apps(ngs, vec![enc1(), localsp()]);
        let lls_inst = apps(lls, vec![n0(), var(0)]);
        let f_idx = lam(nat_ty(), app2(n_get(), lift(1, 0, &exit_l()), var(0)));
        let ap_idx = ap(
            nat_ty(),
            nn(),
            f_idx,
            llen(nn(), localsp()),
            slot_e(),
            lls_inst,
        );
        let h = id_trans(
            nn(),
            enc1(),
            app2(n_get(), exit_l(), llen(nn(), localsp())),
            app2(n_get(), exit_l(), slot_e()),
            id_sym(
                nn(),
                app2(n_get(), exit_l(), llen(nn(), localsp())),
                enc1(),
                ngs2,
            ),
            ap_idx,
        );
        let fam_v = lam(nn(), realizes_val(lift(1, 0, &v()), var(0)));
        let result = transport(
            nn(),
            fam_v,
            enc1(),
            app2(n_get(), exit_l(), slot_e()),
            h,
            crs_inst,
        );

        let outer = vec![nat_ty(), nat_ty(), list_ty(nn())];
        let goal = pis(&outer, realizes_val(v(), app2(n_get(), exit_l(), slot_e())));
        let proof = lams(&outer, result);
        (goal, proof)
    }

