    fn dv_app_constr1_xvar_head_pf(ctx: &Context) -> (Term, Term) {
        let (_, rsi) = rv_succ_inv();
        let (_, crs) = constr_realizes_s();
        let (_, ngs) = n_get_snoc();
        let (_, bridge) = constr1_idproof_bridge_pf();

        let e_low = || et_app(et_constr(var(1), nat_lit(1)), et_var(var(0)));
        let v_low = || {
            sv_constr(
                var(1),
                nat_lit(1),
                svcons(lookup_sval(var(2), var(0)), svnil()),
            )
        };

        let vx = || lookup_sval(var(11), var(9));
        let v12 = || sv_constr(var(10), nat_lit(1), svcons(vx(), svnil()));
        let s = apps(rsi, vec![var(10), vx(), var(1), var(0)]);
        let nprime = fst(s.clone());
        let rvprime = snd(snd(s));
        let rvx = apps(
            renv_lookup_honest(ctx, var(11), var(7), var(6), var(2)),
            vec![var(9), nprime, rvprime],
        );
        let sl12 = app2(nat_get(), var(7), var(9));
        let crs_inst = apps(crs, vec![var(10), sl12.clone(), var(6), vx(), rvx]);
        let enc12 = apps(
            s_encode(),
            vec![
                btrue(),
                nat_lit(1),
                lcons(nat_ty(), sl12, lnil(nat_ty())),
                var(6),
            ],
        );
        let exit12 = lsnoc(nn(), var(6), enc12.clone());
        let getpos = app2(n_get(), exit12, llen(nn(), var(6)));
        let ngs_inst = apps(ngs, vec![enc12.clone(), var(6)]);
        let fam_v = lam(nn(), realizes_val(lift(1, 0, &v12()), var(0)));
        let rvproof_g = transport(
            nn(),
            fam_v,
            enc12.clone(),
            getpos.clone(),
            id_sym(nn(), getpos, enc12, ngs_inst),
            crs_inst,
        );

        let xslot10 = || app2(nat_get(), var(5), var(7));
        let opb10 = || {
            op_constr(
                btrue(),
                nat_lit(1),
                lcons(nat_ty(), xslot10(), lnil(nat_ty())),
            )
        };
        let ih_rhs_bt10 = apps(
            s_run(),
            vec![
                var(6),
                nat_s(var(1)),
                mk_sstate(mk_sframe(var(4), e_let(opb10(), var(3))), var(2)),
            ],
        );
        let idproof_x = refl(optn(), ih_rhs_bt10);
        let idproof = apps(
            bridge,
            vec![
                var(6),
                var(1),
                var(4),
                var(3),
                var(2),
                lnil(op_ty()),
                xslot10(),
                var(4),
                nat_lit(0),
                idproof_x,
            ],
        );
        let enc10 = apps(
            s_encode(),
            vec![
                btrue(),
                nat_lit(1),
                lcons(nat_ty(), xslot10(), lnil(nat_ty())),
                var(4),
            ],
        );
        let rloc10 = lsnoc(nn(), var(4), enc10.clone());
        let (_, lls) = llen_snoc();
        let lenproof_u = apps(lls, vec![enc10, var(4)]);

        let witness = v2_wrap0_guarded(e_low(), v_low(), rloc10, idproof, rvproof_g, lenproof_u);

        let tys7 = vec![
            list_ty(func_ty()),
            slotenv_ty(),
            list_ty(nn()),
            expr_ty(),
            list_ty(sframe_ty()),
            nat_ty(),
            realizes_env(var(8), var(4), var(3)),
        ];
        let h_ty = realizes_val(lift(8, 0, &v_low()), var(0));
        let guarded = lams(&tys7, lam(nn(), lam(h_ty, witness)));

        let outer = vec![svlist_ty(), nat_ty(), nat_ty()];
        let proof = lams(&outer, guarded);
        let goal = pis(&outer, p_jeval_guarded_v2(var(2), e_low(), v_low()));
        (goal, proof)
    }

