    fn dv_app_constr1_xapp_head_pf() -> (Term, Term) {
        let (_, rsi) = rv_succ_inv();
        let (_, crs) = constr_realizes_s();
        let (_, ngs) = n_get_snoc();
        let (_, lls) = llen_snoc();
        let (_, bridge) = constr1_idproof_bridge_pf();

        let e6 = || et_app(et_constr(var(4), nat_lit(1)), et_app(var(3), var(2)));
        let v6 = || sv_constr(var(4), nat_lit(1), svcons(var(1), svnil()));
        let base = || llen(nn(), var(6));
        let v_full = || sv_constr(var(13), nat_lit(1), svcons(var(10), svnil()));

        let resx = apps(
            app(cbuild(et_app(var(12), var(11))), lnil(thunk_ty())),
            vec![var(7), base(), mk_cstate(lnil(op_ty()), var(8))],
        );
        let slot_x = fst(resx.clone());
        let x_ops = fst(snd(resx.clone()));
        let funcs_x = snd(snd(resx));
        let op_b = op_constr(
            btrue(),
            nat_lit(1),
            lcons(nat_ty(), slot_x.clone(), lnil(nat_ty())),
        );

        let s = apps(rsi, vec![var(13), var(10), var(1), var(0)]);
        let nprime = fst(s.clone());
        let rvprime = snd(snd(s));

        let ih_applied = apps(
            var(9),
            vec![
                var(8),
                var(7),
                var(6),
                e_let(op_b.clone(), var(5)),
                var(4),
                nat_s(var(3)),
                var(2),
                nprime,
                rvprime,
            ],
        );
        let fp_x = fst(ih_applied.clone());
        let exit_l_x = fst(snd(ih_applied.clone()));
        let core_x = snd(snd(ih_applied));
        let idproof_x = fst(core_x.clone());
        let rvproof_x = fst(snd(core_x.clone()));
        let lenproof_x = snd(snd(core_x));

        let idproof_out = apps(
            bridge,
            vec![
                funcs_x,
                var(3),
                var(6),
                var(5),
                var(4),
                x_ops.clone(),
                slot_x.clone(),
                exit_l_x.clone(),
                fp_x.clone(),
                idproof_x,
            ],
        );

        let enc = apps(
            s_encode(),
            vec![
                btrue(),
                nat_lit(1),
                lcons(nat_ty(), slot_x.clone(), lnil(nat_ty())),
                exit_l_x.clone(),
            ],
        );
        let exit_l_out = lsnoc(nn(), exit_l_x.clone(), enc.clone());
        let slot_full = app2(nat_add(), base(), llen(op_ty(), x_ops.clone()));

        let crs_inst = apps(
            crs,
            vec![
                var(13),
                slot_x.clone(),
                exit_l_x.clone(),
                var(10),
                rvproof_x,
            ],
        );
        let ngs_inst = apps(ngs, vec![enc.clone(), exit_l_x.clone()]);
        let getpos_llen = app2(n_get(), exit_l_out.clone(), llen(nn(), exit_l_x.clone()));
        let getpos_slot = app2(n_get(), exit_l_out.clone(), slot_full.clone());
        let f_slot = lam(nat_ty(), app2(n_get(), lift(1, 0, &exit_l_out), var(0)));
        let ap_slot = ap(
            nat_ty(),
            nn(),
            f_slot,
            llen(nn(), exit_l_x.clone()),
            slot_full.clone(),
            lenproof_x.clone(),
        );
        let h_real = id_trans(
            nn(),
            enc.clone(),
            getpos_llen.clone(),
            getpos_slot.clone(),
            id_sym(nn(), getpos_llen, enc.clone(), ngs_inst),
            ap_slot,
        );
        let fam_v = lam(nn(), realizes_val(lift(1, 0, &v_full()), var(0)));
        let rvproof_out = transport(nn(), fam_v, enc.clone(), getpos_slot, h_real, crs_inst);

        let lls_el = apps(lls, vec![enc, exit_l_x.clone()]);
        let ap_s_len = ap(
            nat_ty(),
            nat_ty(),
            lam(nat_ty(), nat_s(var(0))),
            llen(nn(), exit_l_x.clone()),
            slot_full,
            lenproof_x,
        );
        let ops_full = lsnoc(op_ty(), x_ops.clone(), op_b.clone());
        let (_, lls_op) = llen_snoc_ty(op_ty());
        let lls_ops = apps(lls_op, vec![op_b, x_ops.clone()]);
        let f_natadd = lam(nat_ty(), app2(nat_add(), llen(nn(), var(7)), var(0)));
        let mid = app2(nat_add(), base(), nat_s(llen(op_ty(), x_ops.clone())));
        let z_len = app2(nat_add(), base(), llen(op_ty(), ops_full.clone()));
        let ap_natadd = ap(
            nat_ty(),
            nat_ty(),
            f_natadd,
            llen(op_ty(), ops_full.clone()),
            nat_s(llen(op_ty(), x_ops)),
            lls_ops,
        );
        let lenproof_out = id_trans(
            nat_ty(),
            llen(nn(), exit_l_out.clone()),
            nat_s(llen(nn(), exit_l_x.clone())),
            z_len.clone(),
            lls_el,
            id_trans(
                nat_ty(),
                nat_s(llen(nn(), exit_l_x)),
                mid.clone(),
                z_len.clone(),
                ap_s_len,
                id_sym(nat_ty(), z_len, mid, ap_natadd),
            ),
        );

        let witness = v2_wrap_guarded_app(
            e6(),
            v6(),
            fp_x,
            exit_l_out,
            idproof_out,
            rvproof_out,
            lenproof_out,
        );

        let tys7 = vec![
            list_ty(func_ty()),
            slotenv_ty(),
            list_ty(nn()),
            expr_ty(),
            list_ty(sframe_ty()),
            nat_ty(),
            realizes_env(var(11), var(4), var(3)),
        ];
        let h_ty = realizes_val(lift(8, 0, &v6()), var(0));
        let guarded = lams(&tys7, lam(nn(), lam(h_ty, witness)));

        let ih_ty = p_jeval_guarded_v2(var(4), et_app(var(2), var(1)), var(0));
        let outer = vec![
            svlist_ty(),
            nat_ty(),
            eterm_ty(),
            eterm_ty(),
            sval_ty(),
            ih_ty,
        ];
        let proof = lams(&outer, guarded);
        let goal = pis(&outer, p_jeval_guarded_v2(var(5), e6(), v6()));
        (goal, proof)
    }

