    fn ev_jeval_box_inv_pf(ctx: &Context) -> (Term, Term) {
        let triv_prop = || id_ty(sval_ty(), sv_box(), sv_box());
        let inner_eterm = apps(
            rec(ETERM, 1),
            vec![
                lam(eterm_ty(), Term::Prop),
                id_ty(sval_ty(), var(3), sv_box()),
                lam(nat_ty(), triv_prop()),
                lam(eterm_ty(), lam(Term::Prop, triv_prop())),
                lam(
                    eterm_ty(),
                    lam(eterm_ty(), lam(Term::Prop, lam(Term::Prop, triv_prop()))),
                ),
                lam(nat_ty(), lam(nat_ty(), triv_prop())),
                lam(nat_ty(), triv_prop()),
                var(0),
            ],
        );
        let m_jeval = lam(svlist_ty(), lam(eterm_ty(), inner_eterm));
        let m_japp = lam(sval_ty(), lam(sval_ty(), triv_prop()));
        let m_jiota = lam(nat_ty(), lam(svlist_ty(), lam(sval_ty(), triv_prop())));
        let d_body = apps(
            rec(JOB, 1),
            vec![lam(job_ty(), Term::Prop), m_jeval, m_japp, m_jiota, var(2)],
        );
        let d_motive = lam(
            job_ty(),
            lam(sval_ty(), lam(ev_prop(var(1), var(0)), d_body)),
        );
        let rm = app(rec(EV, 0), d_motive);
        let ty = crate::quote(
            0,
            &infer(ctx, &rm).expect("ev_jeval_box_inv motive must typecheck"),
        );
        let mut arm_tys: Vec<Term> = Vec::new();
        let mut tail = ty;
        for _ in 0..14 {
            match tail {
                Term::Pi(dom, body) => {
                    arm_tys.push((*dom).clone());
                    tail = (*body).clone();
                }
                _ => panic!("expected 14 arm binders on rec(EV,1)"),
            }
        }
        let mut methods: Vec<Term> = Vec::new();
        for arm in &arm_tys {
            let mut binders: Vec<Term> = Vec::new();
            let mut t = arm.clone();
            while let Term::Pi(dom, body) = t {
                binders.push((*dom).clone());
                t = (*body).clone();
            }
            methods.push(lams(&binders, refl(sval_ty(), sv_box())));
        }
        let mut args = methods;
        args.push(jeval(var(2), et_box()));
        args.push(var(1));
        args.push(var(0));
        let outer = vec![
            svlist_ty(),
            sval_ty(),
            ev_prop(jeval(var(1), et_box()), var(0)),
        ];
        let proof = lams(&outer, apps(rm, args));
        let goal = pis(&outer, id_ty(sval_ty(), var(1), sv_box()));
        (goal, proof)
    }

