    fn ev_jeval_rec4_jiota_inv_pf(ctx: &Context) -> (Term, Term) {
        let (_, app_pkg) = ev_jeval_app_pkg_pf(ctx);
        let (_, rec_inv) = ev_jeval_rec_inv_pf(ctx);
        let (_, aprec0_inv) = ev_japp_aprec0_inv_pf(ctx);
        let (_, aprec1_inv) = ev_japp_aprec1_inv_pf(ctx);
        let (_, aprec2_inv) = ev_japp_aprec2_inv_pf(ctx);
        let (_, apfire_inv) = ev_japp_apfire_inv_pf(ctx);

        let et = || eterm_ty();
        let args3 = lcons(
            et(),
            var(5),
            lcons(et(), var(4), lcons(et(), var(3), lnil(et()))),
        );
        let args2 = lcons(et(), var(5), lcons(et(), var(4), lnil(et())));
        let args1 = lcons(et(), var(5), lnil(et()));
        let f3 = apps_eterm(et_rec(var(6)), args3);
        let f2 = apps_eterm(et_rec(var(6)), args2);
        let f1 = apps_eterm(et_rec(var(6)), args1);

        let vf = |pkg: &Term| fst(pkg.clone());
        let vx = |pkg: &Term| fst(snd(pkg.clone()));
        let evf = |pkg: &Term| fst(snd(snd(pkg.clone())));
        let evapp = |pkg: &Term| snd(snd(snd(snd(pkg.clone()))));

        let pkg0 = apps(app_pkg.clone(), vec![var(7), f3, var(2), var(1), var(0)]);
        let vf3 = vf(&pkg0);
        let sd = vx(&pkg0);
        let evf0 = evf(&pkg0);
        let evapp0 = evapp(&pkg0);

        let pkg1 = apps(app_pkg.clone(), vec![var(7), f2, var(3), vf3.clone(), evf0]);
        let vf2 = vf(&pkg1);
        let sc = vx(&pkg1);
        let evf1 = evf(&pkg1);
        let evapp1 = evapp(&pkg1);

        let pkg2 = apps(app_pkg.clone(), vec![var(7), f1, var(4), vf2.clone(), evf1]);
        let vf1 = vf(&pkg2);
        let sb = vx(&pkg2);
        let evf2 = evf(&pkg2);
        let evapp2 = evapp(&pkg2);

        let pkg3 = apps(
            app_pkg,
            vec![var(7), et_rec(var(6)), var(5), vf1.clone(), evf2],
        );
        let vf0 = vf(&pkg3);
        let sa = vx(&pkg3);
        let evf3 = evf(&pkg3);
        let evapp3 = evapp(&pkg3);

        let recapp = |spine: Term| sv_recapp(var(6), spine);
        let sp1 = svcons(sa.clone(), svnil());
        let sp2 = svcons(sa.clone(), svcons(sb.clone(), svnil()));
        let sp3 = svcons(sa.clone(), svcons(sb.clone(), svcons(sc.clone(), svnil())));

        let eq_vf0 = apps(rec_inv, vec![var(7), var(6), vf0.clone(), evf3]);
        let mot0 = lam(
            sval_ty(),
            ev_prop(japp(var(0), lift(1, 0, &sa)), lift(1, 0, &vf1)),
        );
        let t0 = transport(sval_ty(), mot0, vf0, recapp(svnil()), eq_vf0, evapp3);
        let eq_vf1 = apps(aprec0_inv, vec![var(6), sa.clone(), vf1.clone(), t0]);

        let mot1 = lam(
            sval_ty(),
            ev_prop(japp(var(0), lift(1, 0, &sb)), lift(1, 0, &vf2)),
        );
        let t1 = transport(sval_ty(), mot1, vf1, recapp(sp1), eq_vf1, evapp2);
        let eq_vf2 = apps(
            aprec1_inv,
            vec![var(6), sa.clone(), sb.clone(), vf2.clone(), t1],
        );

        let mot2 = lam(
            sval_ty(),
            ev_prop(japp(var(0), lift(1, 0, &sc)), lift(1, 0, &vf3)),
        );
        let t2 = transport(sval_ty(), mot2, vf2, recapp(sp2), eq_vf2, evapp1);
        let eq_vf3 = apps(
            aprec2_inv,
            vec![var(6), sa.clone(), sb.clone(), sc.clone(), vf3.clone(), t2],
        );

        let mot3 = lam(
            sval_ty(),
            ev_prop(japp(var(0), lift(1, 0, &sd)), lift(1, 0, &var(1))),
        );
        let t3 = transport(sval_ty(), mot3, vf3, recapp(sp3), eq_vf3, evapp0);
        let jiota_ev = apps(
            apfire_inv,
            vec![
                var(6),
                sa.clone(),
                sb.clone(),
                sc.clone(),
                sd.clone(),
                var(1),
                t3,
            ],
        );

        let spine_at = |la: usize, sa_t: &Term, sb_t: &Term, sc_t: &Term| {
            svcons(
                lift(la, 0, sa_t),
                svcons(lift(la, 0, sb_t), svcons(lift(la, 0, sc_t), svnil())),
            )
        };
        let core4 = ev_prop(
            jiota(
                lift(4, 0, &var(6)),
                svcons(var(3), svcons(var(2), svcons(var(1), svnil()))),
                var(0),
            ),
            lift(4, 0, &var(1)),
        );
        let t4 = sigma(
            sval_ty(),
            sigma(sval_ty(), sigma(sval_ty(), sigma(sval_ty(), core4))),
        );
        let core3 = {
            let sp = svcons(lift(3, 0, &sa), svcons(var(2), svcons(var(1), svnil())));
            ev_prop(jiota(lift(3, 0, &var(6)), sp, var(0)), lift(3, 0, &var(1)))
        };
        let t3ty = sigma(sval_ty(), sigma(sval_ty(), sigma(sval_ty(), core3)));
        let core2 = {
            let sp = svcons(
                lift(2, 0, &sa),
                svcons(lift(2, 0, &sb), svcons(var(1), svnil())),
            );
            ev_prop(jiota(lift(2, 0, &var(6)), sp, var(0)), lift(2, 0, &var(1)))
        };
        let t2ty = sigma(sval_ty(), sigma(sval_ty(), core2));
        let core1 = {
            let sp = spine_at(1, &sa, &sb, &sc);
            ev_prop(jiota(lift(1, 0, &var(6)), sp, var(0)), lift(1, 0, &var(1)))
        };
        let t1ty = sigma(sval_ty(), core1);

        let witness = pair_of(
            t4.clone(),
            sa,
            pair_of(t3ty, sb, pair_of(t2ty, sc, pair_of(t1ty, sd, jiota_ev))),
        );

        let outer = vec![
            svlist_ty(),
            nat_ty(),
            et(),
            et(),
            et(),
            et(),
            sval_ty(),
            ev_prop(
                jeval(
                    var(6),
                    apps_eterm(
                        et_rec(var(5)),
                        lcons(
                            et(),
                            var(4),
                            lcons(
                                et(),
                                var(3),
                                lcons(et(), var(2), lcons(et(), var(1), lnil(et()))),
                            ),
                        ),
                    ),
                ),
                var(0),
            ),
        ];
        let proof = lams(&outer, witness);
        let goal = pis(&outer, t4);
        (goal, proof)
    }

