    fn app_inv_pkg(env: &Term, f: &Term, x: &Term, val: &Term) -> Term {
        let e = |k: usize| lift(k, 0, env);
        let ff = |k: usize| lift(k, 0, f);
        let xx = |k: usize| lift(k, 0, x);
        let vv = |k: usize| lift(k, 0, val);
        sigma(
            sval_ty(),
            sigma(
                sval_ty(),
                sigma(
                    ev_prop(jeval(e(2), ff(2)), var(1)),
                    sigma(
                        ev_prop(jeval(e(3), xx(3)), var(1)),
                        ev_prop(japp(var(3), var(2)), vv(4)),
                    ),
                ),
            ),
        )
    }

    fn app_inv_pkg_t1(env: &Term, f: &Term, x: &Term, val: &Term, vf: &Term) -> Term {
        let e = |k: usize| lift(k, 0, env);
        let ff = |k: usize| lift(k, 0, f);
        let xx = |k: usize| lift(k, 0, x);
        let vv = |k: usize| lift(k, 0, val);
        let vff = |k: usize| lift(k, 0, vf);
        sigma(
            sval_ty(),
            sigma(
                ev_prop(jeval(e(1), ff(1)), vff(1)),
                sigma(
                    ev_prop(jeval(e(2), xx(2)), var(1)),
                    ev_prop(japp(vff(3), var(2)), vv(3)),
                ),
            ),
        )
    }

    fn app_inv_pkg_t2(env: &Term, f: &Term, x: &Term, val: &Term, vf: &Term, vx: &Term) -> Term {
        let e = |k: usize| lift(k, 0, env);
        let ff = |k: usize| lift(k, 0, f);
        let xx = |k: usize| lift(k, 0, x);
        let vv = |k: usize| lift(k, 0, val);
        let vff = |k: usize| lift(k, 0, vf);
        let vxx = |k: usize| lift(k, 0, vx);
        sigma(
            ev_prop(jeval(e(0), ff(0)), vff(0)),
            sigma(
                ev_prop(jeval(e(1), xx(1)), vxx(1)),
                ev_prop(japp(vff(2), vxx(2)), vv(2)),
            ),
        )
    }

    fn app_inv_pkg_t3(env: &Term, x: &Term, val: &Term, vf: &Term, vx: &Term) -> Term {
        let e = |k: usize| lift(k, 0, env);
        let xx = |k: usize| lift(k, 0, x);
        let vv = |k: usize| lift(k, 0, val);
        let vff = |k: usize| lift(k, 0, vf);
        let vxx = |k: usize| lift(k, 0, vx);
        sigma(
            ev_prop(jeval(e(0), xx(0)), vxx(0)),
            ev_prop(japp(vff(1), vxx(1)), vv(1)),
        )
    }

    fn ev_jeval_app_pkg_pf(ctx: &Context) -> (Term, Term) {
        let u0 = || Term::Universe(0);
        let triv = || nat_ty();
        let pkg_app = app_inv_pkg(&var(5), &var(3), &var(2), &var(7));
        let inner_arms = vec![
            triv(),
            lam(nat_ty(), triv()),
            lam(eterm_ty(), lam(u0(), triv())),
            lam(eterm_ty(), lam(eterm_ty(), lam(u0(), lam(u0(), pkg_app)))),
            lam(nat_ty(), lam(nat_ty(), triv())),
            lam(nat_ty(), triv()),
        ];
        let mut inner_args = vec![lam(eterm_ty(), u0())];
        inner_args.extend(inner_arms);
        inner_args.push(var(0));
        let inner_eterm = apps(rec(ETERM, 2), inner_args);
        let m_jeval = lam(svlist_ty(), lam(eterm_ty(), inner_eterm));
        let m_japp = lam(sval_ty(), lam(sval_ty(), triv()));
        let m_jiota = lam(nat_ty(), lam(svlist_ty(), lam(sval_ty(), triv())));
        let d_body = apps(
            rec(JOB, 2),
            vec![lam(job_ty(), u0()), m_jeval, m_japp, m_jiota, var(2)],
        );
        let d_motive = lam(
            job_ty(),
            lam(sval_ty(), lam(ev_prop(var(1), var(0)), d_body)),
        );
        let rm = app(rec(EV, 1), d_motive);
        let ty = crate::quote(
            0,
            &infer(ctx, &rm).expect("ev_jeval_app_pkg motive must typecheck"),
        );
        let mut arm_tys: Vec<Term> = Vec::new();
        let mut tail = ty;
        for _ in 0..14 {
            match tail {
                Term::Pi(dom, body) => {
                    arm_tys.push((*dom).clone());
                    tail = (*body).clone();
                }
                _ => panic!("expected 14 arm binders on rec(EV,1)"),
            }
        }
        let pkg0 = app_inv_pkg(&var(11), &var(10), &var(9), &var(6));
        let t1 = app_inv_pkg_t1(&var(11), &var(10), &var(9), &var(6), &var(8));
        let t2 = app_inv_pkg_t2(&var(11), &var(10), &var(9), &var(6), &var(8), &var(7));
        let t3 = app_inv_pkg_t3(&var(11), &var(9), &var(6), &var(8), &var(7));
        let special_leaf = pair_of(
            pkg0,
            var(8),
            pair_of(t1, var(7), pair_of(t2, var(5), pair_of(t3, var(4), var(3)))),
        );
        let mut methods: Vec<Term> = Vec::new();
        for (idx, arm) in arm_tys.iter().enumerate() {
            let mut binders: Vec<Term> = Vec::new();
            let mut t = arm.clone();
            while let Term::Pi(dom, body) = t {
                binders.push((*dom).clone());
                t = (*body).clone();
            }
            let leaf = if idx == 5 {
                special_leaf.clone()
            } else {
                nat_z()
            };
            methods.push(lams(&binders, leaf));
        }
        let mut args = methods;
        args.push(jeval(var(4), et_app(var(3), var(2))));
        args.push(var(1));
        args.push(var(0));
        let outer = vec![
            svlist_ty(),
            eterm_ty(),
            eterm_ty(),
            sval_ty(),
            ev_prop(jeval(var(3), et_app(var(2), var(1))), var(0)),
        ];
        let goal_codomain = app_inv_pkg(&var(4), &var(3), &var(2), &var(1));
        let proof = lams(&outer, apps(rm, args));
        let goal = pis(&outer, goal_codomain);
        (goal, proof)
    }

