    fn rv_nonnumeral_exfalso(
        ctx: &Context,
        sval_arm: usize,
        value: Term,
        n: Term,
        rv_proof: Term,
        goal: Term,
        frame: &[Term],
    ) -> Term {
        let triv = || realizes_val(sv_constr(nat_z(), nat_lit(0), svnil()), n0());
        let mut sval_arms = vec![
            triv(),
            lam(svlist_ty(), lam(eterm_ty(), triv())),
            lam(nat_ty(), lam(nat_ty(), lam(svlist_ty(), triv()))),
            lam(nat_ty(), lam(svlist_ty(), triv())),
        ];
        let goal_branch = lift(3, 0, &goal);
        sval_arms[sval_arm] = match sval_arm {
            0 => goal_branch,
            1 => lam(svlist_ty(), lam(eterm_ty(), lift(2, 0, &goal_branch))),
            2 => lam(
                nat_ty(),
                lam(nat_ty(), lam(svlist_ty(), lift(3, 0, &goal_branch))),
            ),
            3 => lam(nat_ty(), lam(svlist_ty(), lift(2, 0, &goal_branch))),
            _ => panic!("sval_arm out of range"),
        };
        let mut d_inner_args = vec![lam(sval_ty(), Term::Universe(0))];
        d_inner_args.extend(sval_arms);
        d_inner_args.push(var(2));
        let d_inner = apps(rec(SVAL, 2), d_inner_args);
        let d_motive = lam(
            sval_ty(),
            lam(nn(), lam(realizes_val(var(1), var(0)), d_inner)),
        );
        let rm = app(rec(RV, 1), d_motive);
        let mut head = rm;
        for _ in 0..2 {
            let mut tail = crate::quote(
                0,
                &infer(ctx, &lams(frame, head.clone()))
                    .expect("rv ex-falso discriminator (under frame) must typecheck"),
            );
            for _ in 0..frame.len() {
                match tail {
                    Term::Pi(_, body) => tail = (*body).clone(),
                    _ => panic!("expected the frame prefix"),
                }
            }
            let arm = match tail {
                Term::Pi(dom, _) => (*dom).clone(),
                _ => panic!("expected an arm binder on rec(RV,1)"),
            };
            let mut binders: Vec<Term> = Vec::new();
            let mut t = arm;
            while let Term::Pi(dom, body) = t {
                binders.push((*dom).clone());
                t = (*body).clone();
            }
            head = app(head, lams(&binders, rv_z(nat_z())));
        }
        apps(head, vec![value, n, rv_proof])
    }

    fn pjeval_of_realizable_exfalso_arm(
        ctx: &Context,
        bt: Term,
        n_frame: usize,
        eq_v: Term,
        value_to: Term,
        sval_arm: usize,
    ) -> (Term, Term) {
        let mut frame: Vec<Term> = Vec::new();
        let mut goal = bt.clone();
        for _ in 0..n_frame {
            match goal {
                Term::Pi(dom, body) => {
                    frame.push((*dom).clone());
                    goal = (*body).clone();
                }
                _ => panic!("expected n_frame binders on bt"),
            }
        }
        let p_fam = lam(sval_ty(), realizes_val(var(0), var(3)));
        let rv_proof = transport(sval_ty(), p_fam, var(4), value_to.clone(), eq_v, var(1));
        let exfalso =
            rv_nonnumeral_exfalso(ctx, sval_arm, value_to, var(2), rv_proof, goal, &frame);
        (bt, lams(&frame, exfalso))
    }

