    fn pjeval_of_realizable_constr_arm(ctx: &Context) -> (Term, Term) {
        let bts = pjeval_of_realizable_bts(ctx);
        let bt = bts[4].clone();
        let mut frame: Vec<Term> = Vec::new();
        let mut _goal = bt.clone();
        for _ in 0..8 {
            match _goal {
                Term::Pi(dom, body) => {
                    frame.push((*dom).clone());
                    _goal = (*body).clone();
                }
                _ => panic!("expected 8 binders on bt[4]"),
            }
        }
        let (_, constr_inv) = ev_jeval_constr_inv_pf(ctx);
        let (_, nilargs) = rv_nilargs_arity0_pf();
        let (_, constr0) = p_jeval_constr0_gen();
        let val_to = sv_constr(var(7), var(6), svnil());
        let eq_v = apps(constr_inv, vec![var(5), var(7), var(6), var(4), var(3)]);
        let p_fam = lam(sval_ty(), realizes_val(var(0), var(3)));
        let rv2 = transport(
            sval_ty(),
            p_fam,
            var(4),
            val_to.clone(),
            eq_v.clone(),
            var(1),
        );
        let eq_j0 = apps(nilargs, vec![var(7), var(6), var(2), rv2]);
        let hp = apps(constr0, vec![var(5), var(7)]);
        let p_j = lam(
            nat_ty(),
            p_jeval(
                var(6),
                et_constr(var(8), var(0)),
                sv_constr(var(8), var(0), svnil()),
            ),
        );
        let step1 = transport(
            nat_ty(),
            p_j,
            nat_lit(0),
            var(6),
            id_sym(nat_ty(), var(6), nat_lit(0), eq_j0),
            hp,
        );
        let p_v = lam(
            sval_ty(),
            p_jeval(var(6), et_constr(var(8), var(7)), var(0)),
        );
        let step2 = transport(
            sval_ty(),
            p_v,
            val_to.clone(),
            var(4),
            id_sym(sval_ty(), var(4), val_to, eq_v),
            step1,
        );
        (bt, lams(&frame, step2))
    }

