    fn renv_lookup_honest_m() -> Term {
        lam(
            svlist_ty(),
            lam(
                slotenv_ty(),
                lam(
                    list_ty(nn()),
                    lam(
                        realizes_env(var(2), var(1), var(0)),
                        pi(
                            nat_ty(),
                            pi(
                                nn(),
                                pi(
                                    realizes_val(lookup_sval(var(5), var(1)), var(0)),
                                    realizes_val(
                                        lookup_sval(var(6), var(2)),
                                        app2(n_get(), var(4), app2(nat_get(), var(5), var(2))),
                                    ),
                                ),
                            ),
                        ),
                    ),
                ),
            ),
        )
    }

    fn renv_lookup_honest_method_nil(ctx: &Context) -> Term {
        let frame = vec![
            list_ty(nn()),
            nat_ty(),
            nn(),
            realizes_val(sv_box(), var(0)),
        ];
        let goal = realizes_val(
            sv_box(),
            app2(n_get(), var(3), app2(nat_get(), lnil(nat_ty()), var(2))),
        );
        let exfalso = rv_nonnumeral_exfalso(ctx, 0, sv_box(), var(1), var(0), goal, &frame);
        lams(&frame, exfalso)
    }

    fn renv_lookup_honest_method_cons() -> Term {
        let cons_tys = vec![
            sval_ty(),
            nat_ty(),
            svlist_ty(),
            slotenv_ty(),
            list_ty(nn()),
            realizes_val(var(4), app2(n_get(), var(0), var(3))),
            realizes_env(var(3), var(2), var(1)),
            lnth_at(var(2), var(5)),
            pi(
                nat_ty(),
                pi(
                    nn(),
                    pi(
                        realizes_val(lookup_sval(var(7), var(1)), var(0)),
                        realizes_val(
                            lookup_sval(var(8), var(2)),
                            app2(n_get(), var(6), app2(nat_get(), var(7), var(2))),
                        ),
                    ),
                ),
            ),
        ];
        let body_at_slotm = pi(
            nn(),
            pi(
                realizes_val(lookup_sval(svcons(var(11), var(9)), var(1)), var(0)),
                realizes_val(
                    lookup_sval(svcons(var(12), var(10)), var(2)),
                    app2(
                        n_get(),
                        var(8),
                        app2(nat_get(), lcons(nat_ty(), var(11), var(9)), var(2)),
                    ),
                ),
            ),
        );
        let motive_cm = lam(nat_ty(), body_at_slotm.clone());
        let base = lam(nn(), lam(realizes_val(var(10), var(0)), var(6)));
        let step_cm = lam(nat_ty(), lam(body_at_slotm, app(var(3), var(1))));
        let cons_body = lam(
            nat_ty(),
            apps(rec(NAT, 1), vec![motive_cm, base, step_cm, var(0)]),
        );
        lams(&cons_tys, cons_body)
    }

    fn renv_lookup_honest(ctx: &Context, env: Term, senv: Term, locals: Term, h: Term) -> Term {
        apps(
            rec(RENV, 1),
            vec![
                renv_lookup_honest_m(),
                renv_lookup_honest_method_nil(ctx),
                renv_lookup_honest_method_cons(),
                env,
                senv,
                locals,
                h,
            ],
        )
    }

    fn renv_lookup_honest_pf(ctx: &Context) -> (Term, Term) {
        let tys = vec![
            svlist_ty(),
            slotenv_ty(),
            list_ty(nn()),
            realizes_env(var(2), var(1), var(0)),
            nat_ty(),
            nn(),
            realizes_val(lookup_sval(var(5), var(1)), var(0)),
        ];
        let concl = realizes_val(
            lookup_sval(var(6), var(2)),
            app2(n_get(), var(4), app2(nat_get(), var(5), var(2))),
        );
        let prop = pis(&tys, concl);
        let core = renv_lookup_honest(ctx, var(6), var(5), var(4), var(3));
        let applied = apps(core, vec![var(2), var(1), var(0)]);
        let proof = lams(&tys, applied);
        (prop, proof)
    }

