    fn ev_jeval_var_inv_pf(ctx: &Context) -> (Term, Term) {
        let triv_prop = || id_ty(nn(), n0(), n0());
        let inner_arms = vec![
            triv_prop(),
            lam(
                nat_ty(),
                id_ty(sval_ty(), var(4), lookup_sval(var(2), var(0))),
            ),
            lam(eterm_ty(), lam(Term::Prop, triv_prop())),
            lam(
                eterm_ty(),
                lam(eterm_ty(), lam(Term::Prop, lam(Term::Prop, triv_prop()))),
            ),
            lam(nat_ty(), lam(nat_ty(), triv_prop())),
            lam(nat_ty(), triv_prop()),
        ];
        let outer = vec![
            svlist_ty(),
            nat_ty(),
            sval_ty(),
            ev_prop(jeval(var(2), et_var(var(1))), var(0)),
        ];
        ev_jeval_simple_inv_pf(
            ctx,
            inner_arms,
            1,
            refl(sval_ty(), lookup_sval(var(1), var(0))),
            outer,
            jeval(var(3), et_var(var(2))),
            id_ty(sval_ty(), var(1), lookup_sval(var(3), var(2))),
        )
    }

