    fn pjeval_of_realizable_var_arm(ctx: &Context) -> (Term, Term) {
        let bts = pjeval_of_realizable_bts(ctx);
        let bt = bts[1].clone();
        let mut frame: Vec<Term> = Vec::new();
        let mut _goal = bt.clone();
        for _ in 0..7 {
            match _goal {
                Term::Pi(dom, body) => {
                    frame.push((*dom).clone());
                    _goal = (*body).clone();
                }
                _ => panic!("expected 7 binders on bt[1]"),
            }
        }
        let tys = vec![
            list_ty(func_ty()),
            slotenv_ty(),
            list_ty(nn()),
            expr_ty(),
            list_ty(sframe_ty()),
            nat_ty(),
            realizes_env(lift(6, 0, &var(5)), var(4), var(3)),
        ];
        let simp_inst = apps(
            var(7),
            vec![var(6), var(5), var(4), var(3), var(2), var(1), var(0)],
        );
        let (_, var_inv) = ev_jeval_var_inv_pf(ctx);
        let eq_v = apps(var_inv, vec![var(12), var(13), var(11), var(10)]);
        let p_fam1 = lam(sval_ty(), realizes_val(var(0), var(10)));
        let rv_lookup_n = transport(
            sval_ty(),
            p_fam1,
            var(11),
            lookup_sval(var(12), var(13)),
            eq_v.clone(),
            var(8),
        );
        let (_, rlh) = renv_lookup_honest_pf(ctx);
        let rlh_result = apps(
            rlh,
            vec![
                var(12),
                var(5),
                var(4),
                var(0),
                var(13),
                var(9),
                rv_lookup_n,
            ],
        );
        let p_fam2 = lam(
            sval_ty(),
            realizes_val(
                var(0),
                app2(n_get(), var(5), app2(nat_get(), var(6), var(14))),
            ),
        );
        let eq_v_sym = id_sym(sval_ty(), var(11), lookup_sval(var(12), var(13)), eq_v);
        let honest_rv = transport(
            sval_ty(),
            p_fam2,
            lookup_sval(var(12), var(13)),
            var(11),
            eq_v_sym,
            rlh_result,
        );
        let witness = pair_of(
            pjeval_concl(et_var(var(6)), var(4)),
            fst(simp_inst),
            honest_rv,
        );
        (bt, lams(&frame, lams(&tys, witness)))
    }

