    fn unguard_pjeval_proof(env: Term, g: Term, n: Term, rv: Term) -> Term {
        let tys = vec![
            list_ty(func_ty()),
            slotenv_ty(),
            list_ty(nn()),
            expr_ty(),
            list_ty(sframe_ty()),
            nat_ty(),
            realizes_env(lift(6, 0, &env), var(4), var(3)),
        ];
        let tys_vars: Vec<Term> = (0..=6).rev().map(var).collect();
        let g_applied = apps(lift(7, 0, &g), tys_vars);
        let body = apps(g_applied, vec![lift(7, 0, &n), lift(7, 0, &rv)]);
        lams(&tys, body)
    }

    fn unguard_roundtrip_pf() -> (Term, Term) {
        let env = || var(1);
        let i = || var(0);
        let e = || et_constr(i(), nat_lit(0));
        let vr = || sv_constr(i(), nat_lit(0), svnil());
        let (_, c0) = p_jeval_constr0_gen();
        let h_inst = apps(c0, vec![env(), i()]);
        let g = guard_pjeval_proof(env(), vr(), h_inst);
        let ung = unguard_pjeval_proof(env(), g, n0(), rv_z(i()));
        let prop = pi(svlist_ty(), pi(nat_ty(), p_jeval(env(), e(), vr())));
        let proof = lam(svlist_ty(), lam(nat_ty(), ung));
        (prop, proof)
    }

    #[test]
    fn unguard_roundtrip_is_kernel_checked() {
        let sig = numerals_sig();
        let ctx = Context::with_sig(sig.clone());
        let (prop, proof) = unguard_roundtrip_pf();
        assert!(crate::check(&ctx, &proof, &crate::eval(&sig, &Vec::new(), &prop)).is_ok());
    }

