    fn ge2_pkg(i: &Term, j: &Term, v: &Term) -> Term {
        let ii = |k: usize| lift(k, 0, i);
        let jj = |k: usize| lift(k, 0, j);
        let vv = |k: usize| lift(k, 0, v);
        sigma(
            sval_ty(),
            sigma(
                sval_ty(),
                sigma(
                    svlist_ty(),
                    id_ty(
                        sval_ty(),
                        vv(3),
                        sv_constr(ii(3), jj(3), svcons(var(2), svcons(var(1), var(0)))),
                    ),
                ),
            ),
        )
    }

    fn ge2_cant_realize_pf(ctx: &Context) -> (Term, Term) {
        let (_, rv_ge2f) = rv_ge2field_false_pf(ctx);
        let outer = vec![
            nat_ty(),
            nat_ty(),
            sval_ty(),
            ge2_pkg(&var(2), &var(1), &var(0)),
            nn(),
            realizes_val(var(2), var(0)),
        ];
        let g = var(2);
        let f0 = fst(g.clone());
        let f1 = fst(snd(g.clone()));
        let rest = fst(snd(snd(g.clone())));
        let eq = snd(snd(snd(g)));
        let target = sv_constr(
            var(5),
            var(4),
            svcons(f0.clone(), svcons(f1.clone(), rest.clone())),
        );
        let motive_v = lam(sval_ty(), realizes_val(var(0), var(2)));
        let transported = transport(sval_ty(), motive_v, var(3), target, eq, var(0));
        let body = apps(
            rv_ge2f,
            vec![var(5), var(4), f0, f1, rest, var(1), transported],
        );
        let proof = lams(&outer, body);
        let goal = pis(&outer, id_ty(nat_ty(), nat_z(), nat_s(nat_z())));
        (goal, proof)
    }

