    fn ge2_pkg_t1(i: &Term, j: &Term, v: &Term, f0: &Term) -> Term {
        sigma(
            sval_ty(),
            sigma(
                svlist_ty(),
                id_ty(
                    sval_ty(),
                    lift(2, 0, v),
                    sv_constr(
                        lift(2, 0, i),
                        lift(2, 0, j),
                        svcons(lift(2, 0, f0), svcons(var(1), var(0))),
                    ),
                ),
            ),
        )
    }

    fn ge2_pkg_t2(i: &Term, j: &Term, v: &Term, f0: &Term, f1: &Term) -> Term {
        sigma(
            svlist_ty(),
            id_ty(
                sval_ty(),
                lift(1, 0, v),
                sv_constr(
                    lift(1, 0, i),
                    lift(1, 0, j),
                    svcons(lift(1, 0, f0), svcons(lift(1, 0, f1), var(0))),
                ),
            ),
        )
    }

    fn spine_premise(env: &Term, i: &Term, j: &Term, head: &Term) -> Term {
        let inner_ev = ev_prop(jeval(lift(1, 0, env), lift(1, 0, head)), var(0));
        let concl = ge2_pkg(&lift(2, 0, i), &lift(2, 0, j), &var(1));
        pi(sval_ty(), pi(inner_ev, concl))
    }

    fn ge2_snoc_step_pf(ctx: &Context) -> (Term, Term) {
        let (_, pkg_inv) = ev_jeval_app_pkg_pf(ctx);
        let (_, apconstr_inv) = ev_japp_apconstr_inv_pf(ctx);
        let prem_ty = spine_premise(&var(6), &var(5), &var(4), &var(3));
        let outer = vec![
            svlist_ty(),
            nat_ty(),
            nat_ty(),
            eterm_ty(),
            eterm_ty(),
            sval_ty(),
            ev_prop(jeval(var(5), et_app(var(2), var(1))), var(0)),
            prem_ty,
        ];
        let pkg = apps(pkg_inv, vec![var(7), var(4), var(3), var(2), var(1)]);
        let vf = fst(pkg.clone());
        let vx = fst(snd(pkg.clone()));
        let ev_f = fst(snd(snd(pkg.clone())));
        let ev_japp = snd(snd(snd(snd(pkg))));
        let g_vf = apps(var(0), vec![vf.clone(), ev_f]);
        let g0 = fst(g_vf.clone());
        let g1 = fst(snd(g_vf.clone()));
        let grest = fst(snd(snd(g_vf.clone())));
        let geq = snd(snd(snd(g_vf)));
        let fields = svcons(g0.clone(), svcons(g1.clone(), grest.clone()));
        let target_constr = sv_constr(var(6), var(5), fields.clone());
        let motive_japp = lam(
            sval_ty(),
            ev_prop(japp(var(0), lift(1, 0, &vx)), lift(1, 0, &var(2))),
        );
        let japp_constr = transport(sval_ty(), motive_japp, vf, target_constr, geq, ev_japp);
        let veq = apps(
            apconstr_inv,
            vec![var(6), var(5), fields, vx.clone(), var(2), japp_constr],
        );
        let new_rest = snoc_sval(grest, vx);
        let inner = pair_of(
            ge2_pkg_t2(&var(6), &var(5), &var(2), &g0, &g1),
            new_rest,
            veq,
        );
        let mid = pair_of(ge2_pkg_t1(&var(6), &var(5), &var(2), &g0), g1, inner);
        let body = pair_of(ge2_pkg(&var(6), &var(5), &var(2)), g0, mid);
        let proof = lams(&outer, body);
        let goal = pis(&outer, ge2_pkg(&var(6), &var(5), &var(2)));
        (goal, proof)
    }

