    fn spine_concl(env: &Term, i: &Term, j: &Term, l: &Term) -> Term {
        let prem = spine_premise(&lift(2, 0, env), &lift(2, 0, i), &lift(2, 0, j), &var(1));
        let ev_hyp = ev_prop(
            jeval(lift(3, 0, env), apps_eterm(var(2), lift(3, 0, l))),
            var(1),
        );
        let concl = ge2_pkg(&lift(4, 0, i), &lift(4, 0, j), &var(2));
        pi(eterm_ty(), pi(sval_ty(), pi(prem, pi(ev_hyp, concl))))
    }

    fn spine_ge2_inv_pf(ctx: &Context) -> (Term, Term) {
        let (_, snoc_step) = ge2_snoc_step_pf(ctx);

        let motive = lam(
            list_ty(eterm_ty()),
            spine_concl(&var(4), &var(3), &var(2), &var(0)),
        );

        let nil_ty = spine_concl(&var(3), &var(2), &var(1), &lnil(eterm_ty()));
        let (nil_binders, _) = peel_n(&nil_ty, 4);
        let nil_arm = lams(&nil_binders, apps(var(1), vec![var(2), var(0)]));

        let ih_ty = spine_concl(&var(5), &var(4), &var(3), &var(0));
        let cons_ty = spine_concl(
            &var(6),
            &var(5),
            &var(4),
            &lcons(eterm_ty(), var(2), var(1)),
        );
        let (cons_binders, _) = peel_n(&cons_ty, 4);
        let ev_prime_ty = ev_prop(jeval(var(11), et_app(var(4), var(7))), var(0));
        let snoc_applied = apps(
            snoc_step,
            vec![
                var(12),
                var(11),
                var(10),
                var(5),
                var(8),
                var(1),
                var(0),
                var(3),
            ],
        );
        let prem_prime = lam(sval_ty(), lam(ev_prime_ty, snoc_applied));
        let cons_body = apps(
            var(4),
            vec![et_app(var(3), var(6)), var(2), prem_prime, var(0)],
        );
        let cons_inner = lams(&cons_binders, cons_body);
        let cons_arm = lam(eterm_ty(), lam(list_ty(eterm_ty()), lam(ih_ty, cons_inner)));

        let rec_term = apps(
            rec(LIST, 1),
            vec![eterm_ty(), motive, nil_arm, cons_arm, var(0)],
        );
        let outer = vec![svlist_ty(), nat_ty(), nat_ty(), list_ty(eterm_ty())];
        let proof = lams(&outer, rec_term);
        let goal = pis(&outer, spine_concl(&var(3), &var(2), &var(1), &var(0)));
        (goal, proof)
    }

