    fn dvapp_constr_base_ge2_pf(ctx: &Context) -> (Term, Term) {
        let (_, pkg_inv) = ev_jeval_app_pkg_pf(ctx);
        let (_, constr_inv) = ev_jeval_constr_inv_pf(ctx);
        let (_, apconstr_inv) = ev_japp_apconstr_inv_pf(ctx);

        let outer = vec![svlist_ty(), nat_ty(), nat_ty(), eterm_ty(), eterm_ty()];
        let head = et_app(et_app(et_constr(var(3), var(2)), var(1)), var(0));
        let prem_ty = spine_premise(&var(4), &var(3), &var(2), &head);
        let (prem_binders, _) = peel_n(&prem_ty, 2);

        let g = et_app(et_constr(var(5), var(4)), var(3));
        let constr_term = et_constr(var(5), var(4));
        let pkg1 = apps(pkg_inv.clone(), vec![var(6), g, var(2), var(1), var(0)]);
        let vg = fst(pkg1.clone());
        let vb = fst(snd(pkg1.clone()));
        let ev_g = fst(snd(snd(pkg1.clone())));
        let ev_japp1 = snd(snd(snd(snd(pkg1))));
        let pkg2 = apps(pkg_inv, vec![var(6), constr_term, var(3), vg.clone(), ev_g]);
        let vc = fst(pkg2.clone());
        let va = fst(snd(pkg2.clone()));
        let ev_c = fst(snd(snd(pkg2.clone())));
        let ev_japp2 = snd(snd(snd(snd(pkg2))));

        let vc_eq = apps(constr_inv, vec![var(6), var(5), var(4), vc.clone(), ev_c]);
        let motive_jc = lam(
            sval_ty(),
            ev_prop(japp(var(0), lift(1, 0, &va)), lift(1, 0, &vg)),
        );
        let japp_c2 = transport(
            sval_ty(),
            motive_jc,
            vc,
            sv_constr(var(5), var(4), svnil()),
            vc_eq,
            ev_japp2,
        );
        let vg_eq = apps(
            apconstr_inv.clone(),
            vec![var(5), var(4), svnil(), va.clone(), vg.clone(), japp_c2],
        );
        let fields1 = svcons(va.clone(), svnil());
        let motive_jg = lam(
            sval_ty(),
            ev_prop(japp(var(0), lift(1, 0, &vb)), lift(1, 0, &var(1))),
        );
        let japp_g1 = transport(
            sval_ty(),
            motive_jg,
            vg,
            sv_constr(var(5), var(4), fields1.clone()),
            vg_eq,
            ev_japp1,
        );
        let vh_eq = apps(
            apconstr_inv,
            vec![var(5), var(4), fields1, vb.clone(), var(1), japp_g1],
        );

        let inner = pair_of(
            ge2_pkg_t2(&var(5), &var(4), &var(1), &va, &vb),
            svnil(),
            vh_eq,
        );
        let mid = pair_of(ge2_pkg_t1(&var(5), &var(4), &var(1), &va), vb, inner);
        let ge2 = pair_of(ge2_pkg(&var(5), &var(4), &var(1)), va, mid);

        let proof = lams(&outer, lams(&prem_binders, ge2));
        let goal = pis(&outer, prem_ty);
        (goal, proof)
    }

