    fn nonrealizable_sim_pf(ctx: &Context) -> (Term, Term) {
        let (_, sge) = sim_guarded_exfalso_pf(ctx);
        let (_, sc0) = sim_constr0_exfalso_pf(ctx);

        let triv_pf = || rv_z(nat_z());
        let m = lam(eterm_ty(), nrs_m(&var(5), &var(3), &var(0)));

        let arm0 = lam(ev_prop(jeval(var(4), et_box()), var(2)), triv_pf());
        let arm1 = lam(
            nat_ty(),
            lam(
                ev_prop(jeval(var(5), et_var(var(0))), var(3)),
                apps(sge.clone(), vec![var(6), et_var(var(1)), var(4), var(3)]),
            ),
        );
        let arm2 = lam(
            eterm_ty(),
            lam(
                nrs_m(&var(5), &var(3), &var(0)),
                lam(ev_prop(jeval(var(6), et_lam(var(1))), var(4)), triv_pf()),
            ),
        );
        let arm3 = lam(
            eterm_ty(),
            lam(
                eterm_ty(),
                lam(
                    nrs_m(&var(6), &var(4), &var(1)),
                    lam(
                        nrs_m(&var(7), &var(5), &var(1)),
                        lam(
                            ev_prop(jeval(var(8), et_app(var(3), var(2))), var(6)),
                            apps(sge, vec![var(9), et_app(var(4), var(3)), var(7), var(6)]),
                        ),
                    ),
                ),
            ),
        );
        let motive_prime = lam(
            nat_ty(),
            nrs_m(&var(8), &var(6), &et_constr(var(3), var(0))),
        );
        let zero_m = apps(sc0, vec![var(7), var(2), var(5), var(4)]);
        let succ_m = lam(
            nat_ty(),
            lam(
                nrs_m(&var(8), &var(6), &et_constr(var(3), var(0))),
                lam(
                    ev_prop(jeval(var(9), et_constr(var(4), nat_s(var(1)))), var(7)),
                    triv_pf(),
                ),
            ),
        );
        let rec_nat1 = apps(rec(NAT, 1), vec![motive_prime, zero_m, succ_m, var(1)]);
        let arm4 = lam(
            nat_ty(),
            lam(
                nat_ty(),
                lam(
                    ev_prop(jeval(var(6), et_constr(var(1), var(0))), var(4)),
                    app(rec_nat1, var(0)),
                ),
            ),
        );
        let arm5 = lam(
            nat_ty(),
            lam(ev_prop(jeval(var(5), et_rec(var(0))), var(3)), triv_pf()),
        );

        let rec_term = apps(
            rec(ETERM, 1),
            vec![m, arm0, arm1, arm2, arm3, arm4, arm5, var(3)],
        );
        let body = app(rec_term, var(0));
        let outer = vec![
            svlist_ty(),
            eterm_ty(),
            sval_ty(),
            nr_ty(&var(0)),
            ev_prop(jeval(var(3), var(2)), var(1)),
        ];
        let proof = lams(&outer, body);
        let goal = pis(&outer, sim_p_v2(jeval(var(4), var(3)), var(2)));
        (goal, proof)
    }

