    fn dvapp_constr_overapp_resid_p_pf(ctx: &Context) -> (Term, Term) {
        let (_, spine_inv) = spine_ge2_inv_pf(ctx);
        let (_, base_prem) = dvapp_constr_base_ge2_pf(ctx);
        let (_, cant) = ge2_cant_realize_pf(ctx);
        let (_, nrs) = nonrealizable_sim_pf(ctx);

        let outer = vec![
            svlist_ty(),
            nat_ty(),
            nat_ty(),
            eterm_ty(),
            eterm_ty(),
            list_ty(eterm_ty()),
        ];
        let lst = lcons(eterm_ty(), var(2), lcons(eterm_ty(), var(1), var(0)));
        let nt = dvapp_n_tail_p(&var(5), &et_constr(var(4), var(3)), &lst);
        let (nt_binders, _) = peel_n(&nt, 4);

        let big_e = apps_eterm(
            et_constr(var(8), var(7)),
            lcons(eterm_ty(), var(6), lcons(eterm_ty(), var(5), var(4))),
        );
        let head2 = et_app(et_app(et_constr(var(8), var(7)), var(6)), var(5));
        let base_applied = apps(base_prem, vec![var(9), var(8), var(7), var(6), var(5)]);
        let spine_applied = apps(
            spine_inv,
            vec![
                var(9),
                var(8),
                var(7),
                var(4),
                head2,
                var(2),
                base_applied,
                var(1),
            ],
        );
        let nr = lam(
            nn(),
            lam(
                realizes_val(lift(1, 0, &var(2)), var(0)),
                apps(
                    cant,
                    vec![
                        lift(2, 0, &var(8)),
                        lift(2, 0, &var(7)),
                        lift(2, 0, &var(2)),
                        lift(2, 0, &spine_applied),
                        var(1),
                        var(0),
                    ],
                ),
            ),
        );
        let body = apps(nrs, vec![var(9), big_e, var(2), nr, var(1)]);
        let proof = lams(&outer, lams(&nt_binders, body));
        let goal = pis(&outer, nt);
        (goal, proof)
    }

