    fn rv_box_false_pf(ctx: &Context) -> (Term, Term) {
        let tr = || id_ty(nat_ty(), nat_z(), nat_z());
        let fls = || id_ty(nat_ty(), nat_z(), nat_s(nat_z()));
        let d_inner = apps(
            rec(SVAL, 1),
            vec![
                lam(sval_ty(), Term::Prop),
                fls(),
                lam(svlist_ty(), lam(eterm_ty(), tr())),
                lam(nat_ty(), lam(nat_ty(), lam(svlist_ty(), tr()))),
                lam(nat_ty(), lam(svlist_ty(), tr())),
                var(2),
            ],
        );
        let d_motive = lam(
            sval_ty(),
            lam(nn(), lam(realizes_val(var(1), var(0)), d_inner)),
        );
        let rm = app(rec(RV, 0), d_motive);
        let ty = crate::quote(
            0,
            &infer(ctx, &rm).expect("rv_box_false motive must typecheck"),
        );
        let mut arm_tys: Vec<Term> = Vec::new();
        let mut tail = ty;
        for _ in 0..2 {
            match tail {
                Term::Pi(dom, body) => {
                    arm_tys.push((*dom).clone());
                    tail = (*body).clone();
                }
                _ => panic!("expected 2 arm binders on rec(RV,0)"),
            }
        }
        let mut methods: Vec<Term> = Vec::new();
        for arm in &arm_tys {
            let mut binders: Vec<Term> = Vec::new();
            let mut t = arm.clone();
            while let Term::Pi(dom, body) = t {
                binders.push((*dom).clone());
                t = (*body).clone();
            }
            methods.push(lams(&binders, refl(nat_ty(), nat_z())));
        }
        let mut args = methods;
        args.push(sv_box());
        args.push(var(1));
        args.push(var(0));
        let outer = vec![nn(), realizes_val(sv_box(), var(0))];
        let proof = lams(&outer, apps(rm, args));
        let goal = pis(&outer, fls());
        (goal, proof)
    }

