    #[test]
    fn compile_logic_straightline_is_kernel_checked() {
        let sig = numerals_sig();
        let ctx = Context::with_sig(sig.clone());
        let ground = |ty: Term, lhs: Term, rhs: Term| {
            let goal = id_ty(ty.clone(), lhs, rhs.clone());
            assert!(
                crate::check(&ctx, &refl(ty, rhs), &crate::eval(&sig, &Vec::new(), &goal)).is_ok()
            );
        };
        let nat_list = |xs: &[usize]| {
            xs.iter()
                .rev()
                .fold(lnil(nat_ty()), |acc, &x| lcons(nat_ty(), nat_lit(x), acc))
        };
        ground(nat_ty(), llen(nat_ty(), nat_list(&[0, 1, 2])), nat_lit(3));
        ground(nat_ty(), count_lams(et_lam(et_lam(et_box()))), nat_lit(2));
        ground(nat_ty(), count_lams(et_box()), nat_lit(0));
        ground(
            nat_ty(),
            count_lams(et_lam(et_app(et_box(), et_box()))),
            nat_lit(1),
        );
        ground(slotenv_ty(), rev_iota(nat_lit(3)), nat_list(&[2, 1, 0]));

        let op0 = op_constr(btrue(), nat_lit(1), nat_list(&[0]));
        let op1 = op_constr(btrue(), nat_lit(1), nat_list(&[1]));
        let ops01 = lcons(
            op_ty(),
            op0.clone(),
            lcons(op_ty(), op1.clone(), lnil(op_ty())),
        );
        ground(
            expr_ty(),
            seal_ops(ops01, nat_lit(2)),
            e_let(op0.clone(), e_let(op1.clone(), e_ret(nat_lit(2)))),
        );

        let prog_ty = sigma(list_ty(func_ty()), nat_ty());
        let prog = |f: Term, entry: usize| {
            pair_of(
                prog_ty.clone(),
                lcons(func_ty(), f, lnil(func_ty())),
                nat_lit(entry),
            )
        };
        let s = |i: Term| et_app(et_constr(nat_lit(10), nat_lit(1)), i);

        let e1 = et_lam(et_var(nat_lit(0)));
        ground(
            prog_ty.clone(),
            compile_logic(e1),
            prog(mk_func(nat_lit(1), e_ret(nat_lit(0))), 0),
        );

        let e2 = et_lam(s(et_var(nat_lit(0))));
        ground(
            prog_ty.clone(),
            compile_logic(e2),
            prog(
                mk_func(nat_lit(1), e_let(op0.clone(), e_ret(nat_lit(1)))),
                0,
            ),
        );

        let e3 = et_lam(s(s(et_var(nat_lit(0)))));
        ground(
            prog_ty.clone(),
            compile_logic(e3),
            prog(
                mk_func(
                    nat_lit(1),
                    e_let(op0.clone(), e_let(op1.clone(), e_ret(nat_lit(2)))),
                ),
                0,
            ),
        );

        let e4 = et_lam(et_lam(et_var(nat_lit(1))));
        ground(
            prog_ty.clone(),
            compile_logic(e4),
            prog(mk_func(nat_lit(2), e_ret(nat_lit(0))), 0),
        );
    }

