    #[test]
    fn compile_logic_build_rec_is_kernel_checked() {
        let sig = numerals_sig();
        let ctx = Context::with_sig(sig.clone());
        let prog_ty = sigma(list_ty(func_ty()), nat_ty());
        let nat_list = |xs: &[usize]| {
            xs.iter()
                .rev()
                .fold(lnil(nat_ty()), |acc, &x| lcons(nat_ty(), nat_lit(x), acc))
        };
        let two_funcs = |rec: Term, entry: Term| {
            pair_of(
                prog_ty.clone(),
                lcons(func_ty(), rec, lcons(func_ty(), entry, lnil(func_ty()))),
                nat_lit(1),
            )
        };
        let check = |e: Term, want: Term| {
            let goal = id_ty(prog_ty.clone(), compile_logic(e), want.clone());
            assert!(crate::check(
                &ctx,
                &refl(prog_ty.clone(), want),
                &crate::eval(&sig, &Vec::new(), &goal)
            )
            .is_ok());
        };
        let nat10 = || nat_lit(10);
        let step = || {
            et_lam(et_lam(et_app(
                et_constr(nat10(), nat_lit(1)),
                et_var(nat_lit(0)),
            )))
        };
        let rec_of = |base: Term, major: Term| {
            et_app(
                et_app(et_app(et_app(et_rec(nat10()), et_box()), base), step()),
                major,
            )
        };

        // rec-identity:  λn. Rec NAT _ Z (λp ih. S ih) n
        let e_id = et_lam(rec_of(et_constr(nat10(), nat_lit(0)), et_var(nat_lit(0))));
        let id_rec = mk_func(
            nat_lit(2),
            e_case2(
                btrue(),
                nat_lit(1),
                e_let(
                    op_constr(btrue(), nat_lit(0), lnil(nat_ty())),
                    e_ret(nat_lit(2)),
                ),
                e_let(
                    op_call(nat_lit(0), nat_list(&[0, 2])),
                    e_let(
                        op_constr(btrue(), nat_lit(1), nat_list(&[3])),
                        e_ret(nat_lit(4)),
                    ),
                ),
            ),
        );
        let id_entry = mk_func(
            nat_lit(1),
            e_let(op_call(nat_lit(0), nat_list(&[0, 0])), e_ret(nat_lit(1))),
        );
        check(e_id, two_funcs(id_rec, id_entry));

        // plus:  λa b. Rec NAT _ a (λp ih. S ih) b   (cap=2, Z returns context slot 0)
        let e_plus = et_lam(et_lam(rec_of(et_var(nat_lit(1)), et_var(nat_lit(0)))));
        let plus_rec = mk_func(
            nat_lit(3),
            e_case2(
                btrue(),
                nat_lit(2),
                e_ret(nat_lit(0)),
                e_let(
                    op_call(nat_lit(0), nat_list(&[0, 1, 3])),
                    e_let(
                        op_constr(btrue(), nat_lit(1), nat_list(&[4])),
                        e_ret(nat_lit(5)),
                    ),
                ),
            ),
        );
        let plus_entry = mk_func(
            nat_lit(2),
            e_let(op_call(nat_lit(0), nat_list(&[0, 1, 1])), e_ret(nat_lit(2))),
        );
        check(e_plus, two_funcs(plus_rec, plus_entry));
    }

