    #[test]
    fn sub_l2_closed_form_is_kernel_checked() {
        let sig = numerals_sig();
        let ctx = Context::with_sig(sig.clone());
        let chk = |prop: &Term, proof: &Term| {
            assert!(infer(&ctx, proof).is_ok());
            assert!(crate::check(&ctx, proof, &crate::eval(&sig, &Vec::new(), prop)).is_ok());
        };
        let (mp_prop, mp_proof) = mpred_succ();
        chk(&mp_prop, &mp_proof);
        let (fs_prop, fs_proof) = fold_shift();
        chk(&fs_prop, &fs_proof);
        let (ap_prop, ap_proof) = sub_acc_pure();
        chk(&ap_prop, &ap_proof);

        let tooth = id_ty(nn(), sub_mf(n_of_u64(5), nat_lit(3)), n_of_u64(2));
        assert!(crate::check(
            &ctx,
            &refl(nn(), n_of_u64(2)),
            &crate::eval(&sig, &Vec::new(), &tooth)
        )
        .is_ok());
        let sat = id_ty(nn(), sub_mf(n_of_u64(3), nat_lit(5)), n0());
        assert!(crate::check(
            &ctx,
            &refl(nn(), n0()),
            &crate::eval(&sig, &Vec::new(), &sat)
        )
        .is_ok());
        let bad = id_ty(nn(), sub_mf(n_of_u64(5), nat_lit(3)), n_of_u64(3));
        assert!(crate::check(
            &ctx,
            &refl(nn(), n_of_u64(3)),
            &crate::eval(&sig, &Vec::new(), &bad)
        )
        .is_err());

        let guarded = id_ty(
            nn(),
            app(app(sub_spec_pure(), nat_lit(5)), n_of_u64(3)),
            n0(),
        );
        assert!(crate::check(
            &ctx,
            &refl(nn(), n0()),
            &crate::eval(&sig, &Vec::new(), &guarded)
        )
        .is_ok());
        let raw = id_ty(
            nn(),
            app(app(sub_spec(), nat_lit(5)), n_of_u64(3)),
            n_of_u64(u64::MAX - 1),
        );
        assert!(crate::check(
            &ctx,
            &refl(nn(), n_of_u64(u64::MAX - 1)),
            &crate::eval(&sig, &Vec::new(), &raw)
        )
        .is_ok());
    }

