    #[test]
    fn add_succ_l_is_kernel_checked() {
        let sig = numerals_sig();
        let ctx = Context::with_sig(sig.clone());
        let chk = |prop: &Term, proof: &Term| {
            assert!(infer(&ctx, proof).is_ok());
            assert!(crate::check(&ctx, proof, &crate::eval(&sig, &Vec::new(), prop)).is_ok());
        };

        let (prop, proof) = add_succ_l();
        chk(&prop, &proof);

        let (srp, srpr) = add_succ_r();
        chk(&srp, &srpr);

        let (cmp, cmpr) = pos_add_comm();
        chk(&cmp, &cmpr);
        let icm = app2(cmpr.clone(), pos_of_u64(6), pos_of_u64(9));
        let gcm = id_ty(
            p(),
            padd_(pos_of_u64(6), pos_of_u64(9)),
            padd_(pos_of_u64(9), pos_of_u64(6)),
        );
        assert!(crate::check(&ctx, &icm, &crate::eval(&sig, &Vec::new(), &gcm)).is_ok());

        let (smal, smalr) = sub_mask_add_l();
        chk(&smal, &smalr);
        let isa = app2(smalr.clone(), pos_of_u64(5), pos_of_u64(7));
        let gsa = id_ty(
            mm(),
            sm_(padd_(pos_of_u64(5), pos_of_u64(7)), pos_of_u64(5)),
            ispos(pos_of_u64(7)),
        );
        assert!(crate::check(&ctx, &isa, &crate::eval(&sig, &Vec::new(), &gsa)).is_ok());

        let isr = app2(srpr.clone(), pos_of_u64(6), pos_of_u64(9));
        let gsr = id_ty(
            p(),
            padd_(pos_of_u64(6), app(succ(), pos_of_u64(9))),
            app(succ(), padd_(pos_of_u64(6), pos_of_u64(9))),
        );
        assert!(crate::check(&ctx, &isr, &crate::eval(&sig, &Vec::new(), &gsr)).is_ok());

        let (dp, dpr) = add_diag();
        chk(&dp, &dpr);
        let idg = app(dpr.clone(), pos_of_u64(11));
        let gdg = id_ty(
            p(),
            padd_(pos_of_u64(11), pos_of_u64(11)),
            xo(pos_of_u64(11)),
        );
        assert!(crate::check(&ctx, &idg, &crate::eval(&sig, &Vec::new(), &gdg)).is_ok());

        let ic = app2(proof.clone(), pos_of_u64(5), pos_of_u64(7));
        let gc = id_ty(
            p(),
            padd_(app(succ(), pos_of_u64(5)), pos_of_u64(7)),
            app(succ(), padd_(pos_of_u64(5), pos_of_u64(7))),
        );
        assert!(crate::check(&ctx, &ic, &crate::eval(&sig, &Vec::new(), &gc)).is_ok());

        let bad = id_ty(
            p(),
            padd_(app(succ(), pos_of_u64(5)), pos_of_u64(7)),
            padd_(pos_of_u64(5), pos_of_u64(7)),
        );
        assert!(crate::check(&ctx, &ic, &crate::eval(&sig, &Vec::new(), &bad)).is_err());
    }

